INSERT INTO `berita` (`id`, `judul`, `kategori`, `tanggal`, `penulis`, `status`, `content`, `image`, `url`, `created_at`, `updated_at`) VALUES
(2, 'Perkembangan situasi lokasi kejadian gempa bumi Kab. Sigi', 'favorit', '2024-05-02', 'sabda', 'Ya', '<p class=\"ql-align-justify\">Gempa bumi terjadi di Desa Kamarora A dan Kamarora B Kec. Nokilalaki serta Desa Lembantongoa Kec. Palolo Kab. Sigi pada Minggu (06/08/23) berkekuatan 5.3 SR. Berdasarkan data dari BMKG, tercatat hingga Senin (07/08/23) pukul 22.40 WITA terjadi gempa susulan sebanyak 42 kali.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">BPBD Provinsi Sulawesi Tengah menurunkan Tim untuk melakukan kaji cepat dan mengaktifkan pos pendamping bencana. Berdasarkan data yang diperoleh dari tim, Penduduk di Desa Kamarora A sebanyak 1.794 jiwa yang terdiri dari 406 KK, masyarakat di Desa tersebut mendirikan pengungsian mandiri dengan jumlah jiwa yang berada di pengungsian sebanyak 210 jiwa (38 KK) yang terdiri dari 179 jiwa laki-laki, 31 jiwa perempuan, 20 jiwa balita, 13 bayi, 11 orang lansia, serta 2 jiwa penyandang disabilitas. Sedangkan di Desa Kamarora B jumlah penduduk sebanyak 317 jiwa (101 KK) yang terdiri dari 158 laki-laki, 159 perempuan, 16 lansia, 9 bayi, 27 anak anak serta 1 jiwa penyandang disabilitas.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kebutuhan mendesak di Desa Kamarora A dan Kamarora B yaitu peralatan tidur berupa selimut dan kelambu, makanan siap saji, serta tenda terpal sebagai alas. situasi saat ini, masyarakat dihimbau untuk tetap waspada karena gempa susulan masih terjadi. masyarakat mendirikan tenda masing-masing di luar rumah.</p><p class=\"ql-align-justify\">Hasil pendataan tim di Desa Lembantongoa, Kec. Palolo diperoleh jumlah penduduk sebanyak 792 jiwa yang terdiri dari 375 laki-laki, 417 perempuan, 100 balita, 34 bayi, 69 anak-anak, 11 ibu hamil, 34 ibu menyusui, 52 lansia, 58 orang sakit, dan 12 menyandang disabilitas.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Bangunan terdampak di Dusun I sejumlah 21 unit rumah rusak dan 2 unit rumah ibadah. Dusun II sebanyak 9 unit rumah rusak, Dusun III terdapat 10 unit rumah rusak, Dusun 4 sebanyak 32 unit rumah rusak dan di Dusun 5 sejumlah 7 unit rumah rusak dan 2 fasilitas Pendidikan terdampak yaitu SMP SATAP 26 Sigi dan Sekolah PAUD.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Pengungsian di Desa Lembantongoa terdiri dari pengungsi pos lapangan yang ditempati oleh 216 jiwa pengungsi yang terdiri dari 101 laki-laki, 115 perempuan, 40 anak-anak, 45 balita dan 17 lansia. Selain pengungsi pos lapangan, masyarakat juga membuat pengungsian mandiri di Dusun 5 (lima) sebanyak 576 jiwa yang terdiri dari 274 laki-laki, 302 perempuan, 34 bayi, 55 balita, 69 anak-anak, 11 ibu hamil, 34 ibu menyusui, 58 orang sakit, 34 lansia, serta 12 penyandang disabilitas.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kebutuhan mendesak di Desa Lembantongoa berupa tenda, logistic PB dan obat-obatan. Kondisi terkini di Desa Lembantongoa, masyarakat tetap dihimbau untuk waspada apabila terjadi gempa susulan dan masyarakat mendirikan tenda masing-masing di luar rumah.</p><p><br></p>', '1716479406612-20230808025521.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1716479406612-20230808025521.jpeg', '2024-05-23 15:50:06', '2024-05-23 15:50:06'),
(3, 'Kekeringan melanda 3 kecamatan di Kabupaten Banggai Kepulauan', 'rekomendasi', '2024-05-02', 'sabda', 'Ya', '<p class=\"ql-align-justify\">Fenomena el-nino yang masih berlangsung menyebabkan terjadinya kekeringan. Beberapa wilayah di Sulawesi Tengah mengalami dampak tersebut. Kali ini, kekeringan terjadi di 16 Desa yang tersebar di 3 kecamatan yaitu Kec. Bulagi, Kec. Bulagi Selatan dan Kec. Bulagi Utara Kab. Banggai Kepulauan. Berdasarkan data yang diperoleh sebanyak 1.087 KK terdampak di Desa Kec. Bulagi, 304 KK terdampak di Kec. Bulagi Selatan dan 749 KK terdampak di Kec. Bulagi Utara.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Instansi yang terlibat dalam penanganan kekeringan di kab. Banggai Kepulauan diantaranya BPBD Provinsi Sulawesi Tengah, BPBD Kab. Banggai Kepulauan, PMI Kab. Banggai Kepulauan, Damkar Kab. Banggai Kepulauan, PDAM Kab. Banggai Kepulauan, TNI serta Polsek Kec. Bulagi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Saat ini, masih dilakukan pendistribusian air dengan 3 unit mobil tangki. Air bersih diperoleh dari PDAM Bulagi dan sumber air yang terletak di Desa Bangunemo dengan jarak 23 KM dari Desa Alul. Akses jalan ke Desa Alul yang rusak mengakibatkan proses pengambilan dan pendistribusian air memakan waktu yang lama, serta tedapat kendala pada 2 unit mobil tangki dan tidak dapat melakukan pendistribusian di Desa Alul.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi saat ini, kondisi kekeringan masih berlangsung, masih dibutuhkan air bersih dan mobil tangki air untuk mendukung proses pendistribusian air yang lebih efektif dan merata di seluruh wilayah terdampak.</p><p class=\"ql-align-justify\"><br></p><p><br></p>', '1716479479117-20230611095410.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1716479479117-20230611095410.jpeg', '2024-05-23 15:51:19', '2024-05-23 15:51:19'),
(4, 'Abrasi pantai menyebabkan rusaknya tanggul laut', 'terbaru', '2024-05-24', 'sabda', 'Ya', '<p class=\"ql-align-justify\">Sulteng - Kejadian Abrasi Pantai yang terjadi di Desa&nbsp;Matanga , Kecamatan&nbsp;Banggai Selatan , Kabupaten Banggai Laut, Sulawesi Tengah, Rabu(26/7/2023) Pukul 03:00 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Dalam hal ini, kepala Bidang dan Kedaruratan Badan Penanggulangan Bencana Daerah ( BPBD) Provinsi Sulawesi Tengah, Andy Sembiring mengatakan melalui data terdapat 15 unit rumah warga yang terdampak.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Melalui data, terdapat 15 unit rumah warga yang terdampak Abrasi pantai dan saat ini 5 Kepala Keluarga yang saat ini tengah mengungsi,\" Ucap Kepala bidang kedaruratan dan logistik</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Adapun kronologis dari kejadian ini karena tingginya air laut di sekitar Desa Matanga serta kondisi Tanggul Laut (Talut) yang sudah tidak berfungsi dengan baik menyebabkan gelombang air laut hingga naik kepemukiman dan merusak beberapa rumah warga</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Untuk situasi terakhir sebagian warga yang terdampak mengungsi ke rumah kerabat dan upaya BPBD menghimbau warga untuk tetap selalu waspada terhadap abrasi pantai susulan.</p><p><br></p>', '1716480337501-20232707101710.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1716480337501-20232707101710.jpeg', '2024-05-23 16:05:37', '2024-05-23 16:05:37'),
(5, 'Tim Reaksi Cepat BPBD Sulteng Melakukan Peninjauan Sungai di Desa Damai Makmur', 'terbaru', '2023-02-21', 'feby', 'Ya', '<p class=\"ql-align-justify\">Desa Damai Makmur, Kec. Nuhon Kab. Banggai SULAWESI TENGAH – Tim Reaksi Cepat Penanggulangan Bencana (TRC – PB) Badan Penanggulangan Daerah Provinsi Sulawesi Tengah, melakukan assessment (kaji cepat) di Desa Damai Makmur Kec. Nuhon Kab. Banggai. Pada Sabtu, 11 Februari 2023, tim tiba di Kantor Desa Damai Makmur untuk berkoordinasi terkait peninjauan lokasi bencana.</p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">Berdasarkan keterangan dari Bapak I Wayan Adi Putra selaku Kepala Desa Damai Makmur, bahwa sungai yang terletak di Desa ini, merupakan sungai tadah Hujan, yang artinya sungai ini hanya akan terisi air apabila terjadi hujan di area hulu sungai. Akan tetapi, sungai ini berpotensi untuk menjadi ancaman bagi penduduk Desa, dikarenakan sungai yang jebol menyebabkan terbentuknya aliran sungai baru yang melewati area perkebunan dan persawahan milik warga, serta melintasi ruas jalan penghubung Desa. Posisi Sungai yang terletak dibagian atas perkampungan membuat masyarakat khawatir apabila terjadi hujan di malam hari, ketakutannya apabila aliran air sungai yang membawa material bebatuan akan meluap dan melintasi perkampungan.</p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">Kejadian banjir di Desa ini telah terjadi berulang kali dan menimbulkan dampak bagi area persawahan dan perkebunan warga, olehnya, Kepala Desa dan Jajarannya membutuhkan Tindakan normalisasi sungai guna menekan potensi terjadinya bencana. Besar harapan mereka agar tim BPBD Provinsi Sulawesi Tengah bisa merealisasikan upaya penanganan bencana ini, sebelum terjadi dampak yang lebih besar akibat luapan sungai tersebut.</p><p><br></p>', '1719197057800-damaimakmur.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719197057800-damaimakmur.jpg', '2024-06-24 02:44:17', '2024-06-24 02:44:17'),
(6, 'Akibat Intensitas Hujan Tinggi, Desa Sambo Dilanda Banjir', 'terbaru', '2023-03-09', 'FB', 'Ya', '<p class=\"ql-align-justify\">	Sulawesi Tengah- Intensitas hujan yang tinggi menyebabkan Desa Sambo, Kecamatan Dolo Selatan, Kabupaten Sigi terendam banjir. Akibat curah hujan yang tinggi pada pukul 15.30 WITA menyebabkan sungai sambo meluap pada pukul 17.50 WITA. Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah, melaporkan hujan dengan intensitas tinggi itu menyebabkan sungai sambo.</p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">	\"area yang menggenangi pemukiman, air banjir ini telah merendam 30 hektar area persawahan, 20 hektar perkebunan dan satu unit gilingan padi ikut terendam,\" tulis BPBD Provinsi Sulawesi Tengah dalam keterangan tertulis, Selasa, (7/03/2023).</p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">	dalam hal ini, Kepala Desa Sambo Wahyu Akil, saat dikonfirmasi update oleh Tim Pusat Pengendalian Operasi Penanggulangan Bencana (Pusdalops) mengatakan situasi lapangan Desa Sambo hujan masih berlangsung dengan intensitas tinggi.</p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">	“situasi di lapangan masih berlangsung dengan intensitas tinggi, namun untuk air sudah mulai surut. saat ini masyarakat bergotong-royong membuat tanggul darurat dari bahan kayu di titik jebol sungai sambo yang mengamcam ke Dusun 3 dan Dusun 4,” pungkas Wahyu Akil</p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">	melalui data yang di peroleh terkait jumlah korban yang terdampak tidak ditemukan. Selain itu, untuk situasi terakhir dilaporkan hujan masih berlangsung di wilayah itu dan warga diminta untuk tetap waspada dengan adanya curah hujan intensitas rendah hingga sedang.</p><p><br></p>', '1719197283481-SAMBO.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719197283481-SAMBO.jpg', '2024-06-24 02:48:03', '2024-06-24 02:48:03'),
(7, 'Banjir Merendam Dusun III Desa Palau Kecamatan Balaesang Tanjung', 'terbaru', '2023-03-15', 'FB', 'Ya', '<p class=\"ql-align-justify\">SULAWESI TENGAH- Selasa, 14 Maret 2023 pukul 13.43 Wita, Tim Pusdalops BPBD Provinsi Sulawesi Tengah menerima laporan terkait kejadian banjir pada Selasa, 14 Maret 2023 pukul 11.30 Wita yang terjadi di dusun 3 Desa Palau Kec. Balaesang Tanjung Kab. Donggala. </p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">Intensitas hujan yang tinggi dan kondisi drainase yang kurang berfungsi dengan baik menampung debit air sehingga air meluap dan menggenangi sekitar ± 15 unit rumah, fasilitas umur berupa 1 unit Gedung Gereja dan Gedung SMPN 6 Balaesang Tanjung serta ruas jalan kabupaten terendam banjir. Aparat desa setempat melakukan koordinasi dengan BPBD Kab. Donggala. Situasi terkini air mulai surut dan hujan masih mengguyur dengan intensitas sedang.</p><p><br></p>', '1719197549732-SAMBO.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719197549732-SAMBO.jpg', '2024-06-24 02:52:29', '2024-06-24 02:52:29'),
(8, 'Sungai Kodina Kecamatan Pamona Selatan Meluap Akibat Intensitas Hujan Yang Tinggi', 'terbaru', '2023-03-15', 'fb', 'Ya', '<p class=\"ql-align-justify\">SULAWESI TENGAH- Selasa, 14 Maret 2023 pukul 14.51 Wita, Tim Pusdalops BPBD Provinsi Sulawesi Tengah menerima laporan terkait kejadian Banjir yang terjadi pada pukul 02.00 Wita (14 maret 2023). Banjir terjadi di Dusun 3 Desa Pasir Putih Kec. Pamona Selatan Kab. Poso. </p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">Penyebab terjadinya banjir akibat hujan yang berlangsung selama beberapa hari dengan intensitas tinggi di Kec. Pamona selatan, sehingga Sungai Kodina meluap dan menggenangi sekitar 10 unit rumah warga dan ruas jalan desa. Aparat desa asetempat melakukan koordinasi dengan BPBD Kab. Poso. Situasi akhir terpantau air sudah mulai surut dan masyarakat melakukan pembersihan di rumah masing-masing.</p><p><br></p>', '1719197728822-kodina.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719197728822-kodina.jpg', '2024-06-24 02:55:28', '2024-06-24 02:55:28'),
(9, 'Banjir Desa Dongi-Dongi Kecamaan Lore Utara Kabupaten Poso ', 'terbaru', '2023-03-17', 'fb', 'Ya', '<p class=\"ql-align-justify\">SULAWESI TENGAH- Dini hari pukul 02.00 Wita (16/03/23) telah terjadi kejadian banjir di Desa Dongi-Dongi, Kec. Lore Utara Kab. Poso. Hujan dengan intensitas tinggi yang terjadi selama beberapa hari di wilayah Dongi-Dongi, serta pendangkalan sungai menyebabkan Sungai Dongi-Dongi meluap dan merusak beberapa rumah warga. </p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">Banjir kali ini mengakibatkan jembatan penyebrangan terputus dan 2 unit rumah warga rusak. Sungai ini memerlukan penanganan berupa normalisasi sungai dan pembuatan bronjong. Aparat desa melakukan koordinasi dengan BPBD Kab. Poso. Situasi terkini air sudah mulai surut dan aparat desa tetap melakukan pemantauan situasi desa.</p><p><br></p>', '1719197974662-dongi-dongi.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719197974662-dongi-dongi.jpg', '2024-06-24 02:59:34', '2024-06-24 02:59:34'),
(10, 'Kejadian Banjir Desa Poh Kecamatan Pagimana Kabupaten Banggai', 'terbaru', '2023-03-27', 'fb', 'Ya', '<p class=\"ql-align-justify\">SULAWESI TENGAH – Banjir terjadi di Desa Poh Kec. Pagimana Kab. Banggai pada hari Minggu, 26 Maret 2023 pukul 21.00 Wita. Banjir terjadi akibat curah hujan yang tinggi yang terjadi pada wilayah Kec. Pagimana serta pendangkalan Sungai Jati Yaon, mengakibatkan air sungai meluap hingga ke pemukiman warga dan Jalan Trans dengan ketinggian ± 1 Meter. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Banjir mengakibatkan ± 8 unit rumah warga. Kebutuhan mendesak yang dibutuhkan yaitu normalisasi Sungai Jati Yaon yang mengalami pendangkalan, agar tidak terjadi kejadian banjir apabila hujan dengan intensitas tinggi terjadi Kembali di Desa Poh.</p><p class=\"ql-align-justify\"><br></p><p><br></p>', '1719198360646-POH.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719198360646-POH.jpg', '2024-06-24 03:06:00', '2024-06-24 03:06:00'),
(11, '  Kejadian Banjir Tomini Barat Kecamatan Tomini Kabupaten Parigi Moutong', 'terbaru', '2023-03-27', 'fb', 'Ya', '<p class=\"ql-align-justify\">SULAWESI TENGAH – Kejadian banjir Di Desa Tomini Barat Kec. Tomini Kab. Parigi Moutong terjadi pada Minggu, 23 Maret 2023 pukul 20.00 Wita. Banjir terjadi di Dusun 1 dan Dusun 3. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Banjir terjadi akibat hujan dengan intensitas tinggi terus mengguyur wilayah Tomini Barat yang mengakibatkan meluapnya sungai Di Desa Tomini Barat hingga ke pemukiman warga dengan ketinggian air ± 10 cm. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Peristiwa ini mengakibatkan setidaknya 60 unit rumah warga terdampak serta ±16 KK mengungsi di rumah kerabat. Situasi terkini air sudah mulai surut namun hujan ringan masih terjadi di wilayah Tomini Barat.</p><p><br></p>', '1719199771470-tominibarat.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719199771470-tominibarat.jpg', '2024-06-24 03:29:31', '2024-06-24 03:29:31'),
(12, 'Banjir Desa Tomado Kecamatan Lindu Kabupaten Sigi', 'terbaru', '2023-03-27', 'fb', 'Ya', '<p class=\"ql-align-justify\">SULAWESI TENGAH – Minggu, 26 Maret 2023 pukul 17.00 Wita, curah hujan yang tinggi yang mengguyur wilayah Desa Tomado mengakibatkan banjir yang disebabkan oleh meluapnya Sungai Desa Tomado Kec. Lindu kab. Sigi. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Air sungai meluap ke jalan raya pada pukul 17.00-19.00 Wita dengan ketinggian air sekitar 10cm. Akibat peristiwa ini, dua unit rumah warga terendam banjir. Tidak ada korban jiwa dalam kejadian ini. BPBD setempat melakukan assessment. Situasi terkini, air sudah surut.</p><p><br></p>', '1719199967303-tomado.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719199967303-tomado.jpg', '2024-06-24 03:32:47', '2024-06-24 03:32:47'),
(13, 'Banjir Desa Pakuli Kecamatan Gumbasa Kabupaten Sigi ', 'terbaru', '2023-03-27', 'fb', 'Ya', '<p class=\"ql-align-justify\">SULAWESI TENGAH- Minggu, 26 Maret 2023, Hujan dengan intensitas tinggi yang terjadi di Desa Pakuli menyebabkan meluapnya Sungai Rakuta hingga menggenangi pemukiman warga dan jalan poros Palu-Pakuli dengan ketinggian air ± 10 cm. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Akibat peristiwa tersebut, 2 unit rumah warga terendam. BPBD setempat melakukan assessment terkait kejadian ini. tidak ada korban jiwa dan kerusakan berat yang terjadi akibat peristiwa ini. Situasi terkini, air masih menggenang dan hujan masih berlangsung dengan intensitas rendah.</p><p><br></p>', '1719200547630-pakuli.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719200547630-pakuli.jpg', '2024-06-24 03:42:27', '2024-06-24 03:42:27'),
(14, 'Banjir Terjang & Desa Di Kecamatan Petasia Barat dan Petasia TImur Kabupaten Morowali Utara', 'terbaru', '2023-04-10', 'fb', 'Ya', '<p class=\"ql-align-justify\">SULAWESI TENGAH – Jumat, 07/04/2023 tim Pusdalops BPBD Provinsi Sulawesi Tengah menerima laporan bahwa telah terjadi kejadian banjir pada hari Kamis, 06/04/2023 yang terjadi di Desa Ulula’a, Desa Togo, Desa Sampalowo, Desa Moleono dan Desa Onepute di Kecamatan Petasia Barat serta Desa Tompira dan Desa Bunta di Kecamatan Petasia Timur.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Banjir terjadi akibat curah hujan yang tinggi disertai petir yang menyebabkan meluapnya aliran Sungai Laa dengan ketinggian air mencapai 35cm hingga 100cm yang berdampak pada tujuh desa di dua kecamatan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan data yang kami terima, jumlah terdampak pada Desa Ulula’la sejumlah 193KK, fasilitas umum berupa 2 unit Gedung sekolah, 1 unit fasilitas Kesehatan serta I unit gedung kantor. di Desa Togo terdampak sejumlah 310 KK, Desa Sampalowo sejumlah 81 KK, Desa Moleono sejumlah 96KK, fasilitas umum berupa 2 unit rumah ibadah, 2 unit gedung sekolah, serta kebun seluas 143 Ha. Desa Onepute terdampak sejumlah 246KK, 1 unit rumah ibadah serta 2 unit sekolah. Desa Tompira sejumlah 420KK, 1 unit kantor dan 1 unit sekolah. Desa Bunta terdampak 499KK, 6 unit Rumah Ibadah, serta 3 Unit Sekolah. Pengungsi Desa Sampolowo sebanyak 2KK, Desa Onepute 3KK, Desa Tompira 23KK serta Desa Bunta 135KK. Saat ini kebutuhan mendesak berupa Logistik Makanan, Air Bersih serta Perlengkapan Bayi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Update informasi terakhir tanggal 9 april 2023 pukul 21.15 Wita, - Air sudah surut di wilayah Desa Ulula’a dan Desa Togo, air masih menggenang ±35 cm di Desa Sampalowo, Desa Moleono, dan Desa Onepute, Desa Tompira dan Desa Bunta ketinggian air semakin meningkat. Lokasi pengungsian menggunakan Bangunan Balai Desa dan Kantor Desa setempat.</p><p><br></p>', '1719200732639-morut.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719200732639-morut.jpg', '2024-06-24 03:45:32', '2024-06-24 03:45:32'),
(15, 'Curah Hujan Tinggi Mengakibatkan Sungai Mati di Bondat Meluap', 'terbaru', '2023-05-28', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Kejadian banjir terjadi di Desa Bondat, Kec. Pagimana Kab. Banggai. Banjir terjadi pada Jumat, (26/05/2023). Intensitas hujan yang tinggi sejak pukul 13.23 wita mengakibatkan banjir. Terdapat 5 unit rumah warga terendam dan sekitar ±25 jiwa terdampak akibat kejadian ini. Menurut informasi dari Kepala Desa Bondat, diperlukan tindakan normalisasi terhadap sungai mati yang terdapat di desa ini.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Aparat Desa Bondat berkoordinasi dengan BPBD Kab. Banggai. Tim TRC Kab. Banggai melakukan pembersihan lumpur di rumah terdampak dan melakukan pendistribusian air bersih. Berdasarkan laporan terkini, kondisi banjir berangsur surut dan warga melakukan penampungan air bersih.</p><p><br></p>', '1719200878491-bondat.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719200878491-bondat.jpg', '2024-06-24 03:47:58', '2024-06-24 03:47:58'),
(16, 'Jalan Trans Desa Bajugan Terputus Diterjang Banjir', 'terbaru', '2024-05-28', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Kejadian banjir terjadi di Desa Bajugan, Kec. Galang Kab. Toli-Toli Pada Jum\'at (26/05/2023) pukul 11.30 Wita. Intensitas hujan yang tinggi sejak pagi hari menyebabkan banjir. Jalan trans di Desa Bajugan terputus akibat diterjang banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Aparat Desa Bajugan beserta warga tetap waspada dan memantau situasi di lokasi kejadian serta berkoordinasi dengan BPBD Kab. Toli-Toli. Berdasarkan laporan terkini, kondisi banjir berangsur surut dan telah diturunkan alat berat untuk melakukan penanganan jalan yang terputus.</p><p><br></p>', '1719201208874-bajugan.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719201208874-bajugan.jpg', '2024-06-24 03:53:28', '2024-06-24 03:53:28'),
(17, 'Assessment Kejadian BAnjir Desa Balaang Kecamatan Nuhon Kabupaten Donggala', 'terbaru', '2023-05-29', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Tim Reaksi Cepat Penanggulangan Bencana (TRC-PB) Badan Penanggulangan Bencana Daerah Provinsi Sulawesi Tengah melakukan assessment di Desa Balaang, Kec. Nuhon Kab. Banggai (25/05/2023). Tim berkoordinasi dengan Kepala Desa Balaang di kantor desa setempat.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Tim didampingi oleh aparat desa untuk melakukan tinjauan di area sungai yang menjadi sumber banjir. banjir terjadi akibat intensitas hujan yang tinggi menyebabkan volume air meningkat dan sungai tidak mampu menampung debit air sehingga air meluap merendam pemukiman warga. Banjir merendam sekitar 70 unit rumah warga, lahan perkebunan warga seluas 4 Ha terdampak, juga berdampak pada fasilitas umum berupa akses jalan trans dan pemakaman umum.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan hasil peninjauan di lokasi sungai, rusaknya tanggul menyebabkan tidak adanya penahan air, sehingga dibutuhkan pembuatan bronjong untuk mencegah air mengikis tebing sungai dan meluap ke pemukiman warga. Rusaknya tanggul menyebabkan terbentuknya aliran sungai baru, pendangkalan dan mengecilnya aliran sungai sehingga dibutuhkan penanganan berupa normalisasi sungai sebagai upaya meminimalisir potensi banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Aparat desa setempat berharap dengan adanya peninjauan yang dilakukan oleh tim BPBD Provinsi Sulawesi Tengah, sungai ini dapat segera ditangani agar permasalahan banjir di desa ini dapat teratasi secepatnya.</p><p><br></p>', '1719201441406-assessmentbalaang.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719201441406-assessmentbalaang.jpg', '2024-06-24 03:57:21', '2024-06-24 03:57:21'),
(18, 'Gerak Cepat BPBD Provinsi Sulawesi Tengah Di Desa Balinggi Dan Catur Karya Kecamatan Balinggi Kabupaten Parigi Moutong', 'favorit', '2023-05-30', 'fb', 'Ya', '<p class=\"ql-align-justify\">Kejadian banjir terjadi di Desa Balinggi dan Catur Karya kec. Balinggi Kab. Parigi Moutong (29/05/23). Banjir terjadi akibat intensitas hujan yang tinggi sejak pukul 16.00 Wita hingga malam hari menyebabkan air setinggi 1 Meter menggenangi pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Di Desa Balinggi terdampak di Dusun I sebanyak 18KK, Dusun II sejumlah 15KK serta lahan persawahan seluas 25Ha. Sedangkan di Desa Catur Karya sejumlah 3 unit rumah hanyut dan 6 rumah terendam. Serta 9 KK mengungsi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kebutuhan mendesak saat ini, kebutuhan air bersih serta alat berat untuk pembersihan area pemukiman warga. Merespon kejadian ini, BPBD Provinsi Sulawesi Tengah bergerak cepat untuk menurunkan Tim untuk melakukan assessment ke kec. Balinggi Kab. Parigi Moutong. Saat ini tim telah tiba dan sedang melakukan pendataan di lokasi kejadian.</p><p><br></p>', '1719201759020-gercep.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719201759020-gercep.jpg', '2024-06-24 04:02:39', '2024-06-24 04:02:39'),
(19, 'Tiga Lansia Korban Banjir Balinggi Berhasil di Evakuasi', 'rekomendasi', '2023-06-01', 'fb', 'Ya', '<p class=\"ql-align-justify\">SULTENG - Tim Reaksi Cepat ( TRC) Badan Penanggulangan Bencana Daerah Provinsi (BPBD) bersama TRC BPBD Parigi Moutong berhasil melakukan Proses evakuasi warga terdampak banjir di Desa Balinggi, Kabupaten Parigi Moutong Provinsi Sulawesi Tengah, Kamis (01/06/23)</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Sebelumya, hujan dengan intensitas tinggi, tim yang tengah siaga di posko mendapatkan info Pukul 01.00 dari Kepala dusun untuk dibantu melakukan proses evakuasi 3 orang lansia yang kondisi tidak bisa berjalan</p><p class=\"ql-align-justify\">Kepala Bidang Kedaruratan Dan Logistik, Andy Sembiring mengatakan untuk saat ini TRC-PB BPBD Prov Sulteng bersama TRC-PB BPBD Kabupaten Parigi Moutong berhasil mengevakuasi 3 orang lansia yang berada di Dusun 1 Desa atas nama I Gede Noren (65), Ni Ketut Nanti (75) dan Ni Ketut Nangis (62) Balinggi Kecamatan Balinggi kabupaten Parigi Moutong.</p><p class=\"ql-align-justify\">\"Saat ini tim TRC-PB BPBD Sulteng dan TRC-PB BPBD Kabupaten Parigi moutong. info sekitar pukul 01.00 wita dan tim bergerak langsung sekitar Pukul 01.02 Wita terdapat 3 orang lansia kondisi tidak bisa berjalan dan sudah berhasil dievakuasi\" ucap Andy selaku Kepala Bidang Kedaruratan dan Logistik</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Sementara itu, warga Dusun 1 Desa Balinggi yang sejak kemarin sudah melakukan evakuasi masih tetap berjaga-jaga terjadinya banjir susulan.</p><p><br></p>', '1719201895481-balinggi.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719201895481-balinggi.jpg', '2024-06-24 04:04:56', '2024-06-24 04:04:56'),
(20, 'Kalaksa BPBD Provinsi Sulawesi Tengah Melakukan Kunjungan di Lokasi Terdampak Banjir Bandang Kabupaten Parigi Moutong', 'favorit', '2023-06-03', 'fb', 'Ya', '<p class=\"ql-align-justify\">SULTENG - Kepala Pelaksana (Kalaksa) Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah mengunjungi lokasi terdampak banjir bandang di Desa Balinggi, Kecamatan Balinggi, Kabupaten Parigi Moutong, jumat (3/06/2023)</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Merespon situasi bencana ini, tim melakukan rapat koordinasi yang dilaksanakan di Kantor Desa Balinggi Kec. Balinggi Kab. Parigi Moutong. Sejalan dengan yang paparan Dr. Ir. H. Akris Fattah Yunus (Kalaksa BPBD Provinsi Sulawesi Tengah) dalam wawancaranya</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\" Kami telah melakukan rapat koordinasi di kantor Desa Balinggi dengan seluruh OPD terkait, BPBD Ka. Parigi Moutong, Camat Balinggi, Camat Torue, Dinas PU Kab. Parigi Moutong, termasuk dari Balai Wilayah Sungai Provinsi Sulawesi Tengah. Tentunya kami telah membagi tugas siapa yang mengerjakan Sungai Tapeau, siapa yang mengerjakan Sungai Purwokerto, Sungai Tolai, Sungai Tolai Barat, saat ini kami sedang berkunjung untuk melihat pengungsi di Desa Catur Karya dan memberikan bantuan berupa sandang, pangan dan beberapa perlengkapan rumah tangga. Dan juga kami. Dan juga inshaAllah BPBD Provinsi Sulawesi Tengah akan memberikan bantuan terhadap dua unit rumah yang hanyut serta dua unit rumah rusak berat,\" ucap Akris selaku Kalaksa BPBD Provinsi Sulteng. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Sebelumnya, data terdampak di Desa Catur Karya sebanyak 11KK berjumlah 29 jiwa saat ini mengungsi, 9 unit rumah terendam, area perkebunan kacang seluas 1 hektar, 1 unit Masjid serta 1 unit jembatan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Desa Balinggi terdampak sebanyak 36kk sejumlah 163 jiwa, 34 unit rumah terendam, serta total area persawahan terdampak seluas 50 ha yang tersebar di 3 kelurahan serta jalan desa sepanjang 1KM.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Desa Balinggi Jati terdampak sebanyak 1165 KK, korban jiwa sejumlah 1 jiwa atas nama Ni Ketut Kayun (70), 50 unit rumah terendam, rusak berat 2 unit rumah, total area persawahan terdampak seluas 485 ha tersebar di 22 kelompok tani, sarana pendidikan 3 unit sekolah dasar, 3 unit PAUD, 3 unit Pura, 1 unit Gereja.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Di Kec. Torue, Desa Tolai terdampak sejumlah 120 KK, rumah terendam sebanyak 120 unit serta area persawahan terdampak seluas 54 Ha. Desa Tolai Timur sejumlah 20 KK atau 80 jiwa terdampak, rumah terendam sebanyak 20 unit, area perkebunan warga seluas 10 Ha, area tambak udang terdampak seluas 150 Ha, serta 1 unit jembatan. Desa Tolai Barat terdampak sebanyak 82 jiwa, rumah terendam sebanyak 20 unit, area persawahan seluas 62 ha, serta area tambak udang terdampak seluas 37 Ha. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Alat berat telah diturunkan untuk melakukan penanganan berupa normalisasi pada sungai yang terletak di Dusun Purwokerto Desa Balinggi jati Kec. Balinggi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kalaksa BPBD Provinsi Sulawesi Tengah mengupayakan penanganan terbaik dalam mengatasi sumber bencana di wilayah ini, agar kedepannya tidak terjadi kejadian berulang yang dapat mengancam kehidupan dan penghidupan.</p><p><br></p>', '1719205826993-kalak.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719205826993-kalak.jpg', '2024-06-24 05:10:26', '2024-06-24 05:10:26'),
(22, 'Banjir terjadi di Desa Omu Kecamatan Gumbasa Kabupaten Sigi', 'terbaru', '2023-06-07', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Kejadian banjir terjadi di Desa Omu, Kec. Gumbasa Kab. Sigi pada Selasa (06/06/23) pukul 18.00 Wita.</p><p class=\"ql-align-justify\">Banjir terjadi akibat intensitas hujan yang tinggi sehingga menyebabkan air sungai Desa Omu meluap hingga menggenangi pemukiman warga. Kejadian ini mengakibatkan dua unit rumah warga terendam. aparat Desa berkoordinasi dengan BPBD Kab. Sigi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi terkini di lokasi kejadian, hujan sudah reda dan air telah surut, namun aparat desa setempat tetap mengimbau masyarakatnya agar tetap waspada.</p><p><br></p>', '1719206165543-omu.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719206165543-omu.jpg', '2024-06-24 05:16:05', '2024-06-24 05:16:05'),
(23, 'Banjir Kembali Menerjang Desa Balinggi Kecamatan Balinggi Kabupaten Parigi Moutong', 'terbaru', '2024-06-11', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Kejadian banjir kembali terjadi di Desa Balinggi Kec. Balinggi Kab. Parigi Moutong pada Minggu (11/06/23) pukul 17.25 Wita.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Hujan dengan intensitas sedang hingga lebat terjadi mulai pukul 16.04 sampai 17.45 wita. Sepanjang 1 KM Jalan Trans terdampak akibat kejadian ini. Aparat desa melakukan koordinasi dengan BPBD Kab. Parigi Moutong. Kebutuhan mendesak saat ini masih dalam proses pendataan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi saat ini hujan telah redah serta kondisi genangan air sudah mulai surut. Jalur lalu lintas telah kembali normal dan genangan air tidak sampai memasuki pemukiman warga.</p><p><br></p>', '1719206358232-balinggilagi.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719206358232-balinggilagi.jpg', '2024-06-24 05:19:18', '2024-06-24 05:19:18'),
(24, 'Peninjauan Pasca Banjir Balinggi terjadi lagi', 'terbaru', '2023-06-12', 'fb', 'Ya', '<p class=\"ql-align-justify\">Tim Reaksi Cepat Penanggulangan Bencana Badan Penanggulangan Bencana Daerah Provinsi Sulawesi Tengah melakukan peninjauan terkait dengan penangan bencana banjir yang terjadi di Kec. Balinggi Kab. Parigi Moutong.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Diketahui sebelumnya bahwa telah terjadi banjir bandang yang menerjang pada Senin 29 Mei 2023 di Kec. Parigi Moutong berdasarkan laporan kejadian tersebut Tim Reaksi Cepat Penanggulangan Bencana menurunkan tim untuk melakukan assessment dan melakukan pendampingan pengaktifan posko induk</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Tim melakukan assessment di 8 Desa Di Kecamatan Balinggi dan 6 Desa Di Kecamatan Torue Berdasarkan hasil assessment telah diperoleh terkait data titik luapan titik ancaman serta daerah terdampak Diperlukan penanganan segera terhadap sungai yang menjadi sumber terjadinya banjir</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Pada Minggu (11/06/23) hujan dengan intensitas tinggi mengguyur wilayah kab Parigi Moutong sejak pukul 16.04 Wita sampai 17.45 Wita menyebabkan banjir kembali terjadi di Desa Balinggi Air meluap melalui jembatan yang berada di perbatasan Desa Balinggi dan Desa Tolai Banjir menerjang melewati jalan trans sehingga menghambat arus lalu lintas sementara waktu saat ini kondisi banjir telah surut banjir tidak sampai berdampak pada pemukiman warga</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Merespon hal tersebut tim kembali diturunkan untuk melakukan peninjauan kembali terkait rencana penanganan sungai sebagai upaya meminimalisir dampak yang terjadi Apabila sumber masalah dan penanganan sungai belum dilakukan oleh BPBD setempat dikhawatirkan banjir akan kembali berulang apabila hujan dengan intensitas tinggi kembali terjadi di wilayah ini</p><p><br></p>', '1719206521535-PKBalinggi2.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719206521535-PKBalinggi2.jpg', '2024-06-24 05:22:01', '2024-06-24 05:22:01'),
(25, 'Banjir dan Abrasi Pantai terjadi di Desa Palau Kecamatan Balaesang Tanjung Kabupaten Donggala', 'terbaru', '2023-07-08', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Banjir terjadi di Desa Palau Kec. Balaesang Tanjung Kab. Donggala tepatnya di Dusun III Singkilat pada Selasa, (04/07/23) pukul 00.30 WITA. Intensitas hujan yang tinggi terjadi sejak sore hari (03/07/23) mengakibatkan Sungai Singkilat Meluap menyebabkan banjir setinggi lutut orang dewasa. banjir tersebut juga membawa material lumpur yang berdampak pada pemukiman warga serta beberapa fasilitas umum.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan hasil pendataan, diperoleh data terdampak diantaranya 28 unit rumah yang terdiri dari 32 KK, 5 unit rumah terdampak lumpur, 1 unit rumah rusak berat, serta fasilitas umum berupa 1 unit rumah ibadah (Gereja) serta gedung SMPN SATAP 6 Balaesang Tanjung.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Personil TRC BPBD Provinsi Sulawesi Tengah menurunkan tim untuk melakukan peninjauan langsung ke lokasi sungai untuk melakukan menentukan rencana penanganan. Berdasarkan hasil peninjauan, ditemukan kondisi sungai yang mengalami pendangkalan serta terbentuknya aliran sungai yang baru. Olehnya diperlukan tindakan normalisasi Sungai Singkilat untuk mengatasi permasalahan banjir yang berasal dari pendangkalan sungai ini. Agar kedepannya tidak terjadi kejadian berulang akibat meluapnya sungai apabila terjadi hujan dengan intensitas tinggi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Sementara itu, di Dusun 4 dan 5 Desa Palau Kec. Balaesang Tanjung Kab. Donggala terjadi kejadian abrasi pantai. pada waktu tertentu air pasang menerjang rumah warga yang berada di pesisir pantai dan masuk ke area pemukiman warga dengan ketinggian kurang lebih 30cm sampai 1 meter. Kejadian ini berdampak pada 19 unit rumah warga yang di huni oleh 19 kk, fasilitas umum berupa 1 unit masjid dan 1 unit gedung Sekolah Dasar. Sedangkan di Dusun 5 terdapat 40 unit rumah yang dihuni oleh 42 KK.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Setelah tim melakukan peninjauan di area pesisir pantai, setiap hari pada pukul 05.00-09.00 WITA terjadi air pasang, sehingga diperlukan pembuatan tanggul laut pada area pesisir pantai untuk mencegah air mencapai pemukiman warga.</p>', '1719206730954-banjirxabrasipalau.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719206730954-banjirxabrasipalau.jpg', '2024-06-24 05:25:30', '2024-06-24 05:25:30'),
(26, 'Banjir Terjadi di Desa Malei Kecamatan Balaesang Tanjung Kabupaten Donggala', 'terbaru', '2023-07-08', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Kejadian banjir terjadi di Desa Malei, kec. Balaesang Tanjung Kab. Donggala pada Senin, 3 Juli 2023 pukul 23.00 WITA. Hujan dengan intensitas tinggi di Desa Malei Sejak pukul 10.00 WITA hingga pukul 19.00 WITA mengakibatkan banjir hingga mengikis tebing sungai yang mengancam area pemukiman warga. bahkan banjir ini juga menyebabkan jembatan penghubung Desa Walandano dan Desa Malei ikut ambruk akibat terkikis debit air yang tinggi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan hasil laporan kaji cepat langsung di lapangan, diperoleh data terdampak diantaranya Dusun II Desa Malei, sejumlah 20 Unit Rumah, 20 KK, Rumah ibadah (Masjid) serta Kantor Desa Malei. Dusun III Desa Malei sejumlah 29 unit rumah terdampak dan 29 KK. Dusun V Desa Malei sebanyak 7 unit rumah dan 11 KK. Dusun III Desa Walandano terdampak sejumlah 8 unit rumah, 11 KK serta satu unit masjid dan jembatan, namun tidak terdapat korban jiwa dan pengungsi akibat kejadian ini. Adapun upaya yang dilakukan dalam merespon kejadian ini, TRC PB BPBD Provinsi Sulawesi Tengah melakukan peninjauan langsung ke Sungai Lewonu yang terletak di Desa Malei. Dari hasil pengkajian cepat diperoleh data terkait kebutuhan mendesak yang diperlukan untuk penanganan kejadian ini yaitu tindakan normalisasi sungai Lewonu dan perbaikan jembatan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi akhir setelah pemantauan di lokasi sungai, terbentuknya aliran sungai baru yang melintas menabrak tebing sungai yang berada di area penyangga jembatan mengalami pengikisan sehingga menyebabkan jembatan ambruk. Miringan jembatan penghubung Desa Malei dengan Desa Walandano rusak diterjang banjir sehingga menyebabkan jembatan putus sepanjang 10 meter.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\"><br></p>', '1719207097591-banjirxabrasipalau.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719207097591-banjirxabrasipalau.jpg', '2024-06-24 05:31:37', '2024-06-24 05:31:37'),
(27, 'Jembatan Nyaris Putus akibat Banjir Desa Bambasiang', 'terbaru', '2023-07-08', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Kejadian banjir terjadi di Dusun II Desa Bambasiang, Kec. Palasa Kab. Parigi Moutong pada Sabtu (08/07/23) pukul 03.00 WITA. Banjir terjadi akibat intensitas hujan yang tinggi sejak pukul 19.00 hingga 07.30 WITA menyebabkan meluapnya Sungai Bambasiang hingga ke pemukiman dan jalan desa.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Personil TRC-PB BPBD Provinsi Sulawesi Tengah diturunkan untuk melakukan tinjauan langsung di lokasi kejadian. Berdasarkan hasil peninjauan langsung di lapangan, dperoleh data terdampak diantaranya satu unit rumah warga yang terletak di pinggiran sungai rusak berat, satu KK terdampak sejumlah 4 jiwa kini sedang mengungsi di rumah kerabat yang terletak di Desa Palasa. Selain itu, banjir juga berdampak pada satu fasilitas umum, yakni jembatan penghubung antar dusun di Desa Bambasiang.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kondisi Sungai Bambasiang mengalami pembentukan aliran sungai baru akibat terjadi pendangkalan aliran sungai lama setinggi 2 meter Aliran sungai yang baru membelok menghantam tanggul dan mengikis bagian pinggir sungai serta area miringan jembatan</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Masyarakat melakukan upaya gotong royong untuk melakukan perbaikan jembatan darurat dengan menggunakan bambu, mengingat jembatan tersebut merupakan akses satu-satunya untuk mengubungkan dusun dua dengan dusun tiga, empat dan lima.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Wilayah terancam dalam kondisi ini adalah wilayah pemukiman yang terletak di pinggir sungai dan juga mengancam area pondasi jembatan, dikhawatirkan apabila terjadi hujan menyebabkan tingginya debit air akan menyebabkan pengikisan pada area pondasi jembatan. Kebutuhan penanganan yang diperlukan untuk Sungai Bambasiang berupa pembuatan bronjong serta melakukan tindakan normalisasi sungai serta perbaikan area miringan jembatan.</p><p class=\"ql-align-justify\"><br></p>', '1719207340261-bambasiang.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719207340261-bambasiang.jpg', '2024-06-24 05:35:40', '2024-06-24 05:35:40'),
(28, 'sepanjang Januari hingga Juli 2023, BPBD Sulteng catat 97 Kejadian Bencana', 'favorit', '2023-07-13', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulteng - Berdasarkan data bencana Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah bencana alam di Indonesia sejak 1 Januari hingga 12 Juli 2023 Provinsi Sulawesi Tengah mengalami kejadian bencana alam dengan total 97 kejadian dengan jenis kejadian Banjir yang mendominasi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Ada 58 kejadian bencana banjir, 9 kejadian bencana Abrasi Pancia, 2 kejadian bencana kebakaran Hutan dan lahan, 19 kejadian bencana Puting Beliung dan 9 kejadian bencana Tanah longsor. Hal ini, Kepala Bidang Kedaruratan dan Logistik BPBD Provinsi Sulteng, Andy A. Sembiring mengatakan, daerah paling banyak mengalami kejadian bencana alam antara lain yakni Kabupaten Poso</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Daerah yang paling banyak mengalami kejadian bencana alam antara lain yakni Poso sebanyak 16 kali dan paling mendominasi kejadian Banjir di Poso sebanyak 11 kali kejadian,\" Ucap Kepala Bidang Kedaruratan dan Logistik, Kamis (13/07/2023).</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berbagai bencana alam tersebut menimbulkan sejumlah dampak yakni 235 orang mengungsi, 2 orang meninggal dunia serta 3 orang mengalami luka-luka.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Bencana tersebut menelan korban jiwa dan bangunan serta fasilitas umum pun ikut terdampak. Rumah warga mengalami kerusakan di antaranya, 22 rumah dalam kondisi rusak berat, 59 rumah rusak sedang dan 360 rumah rusak ringan. Sejumlah fasilitas umum juga mengalami kerusakan, terdiri 31 sarana fasilitas pendidikan, 27 fasilitas peribadatan, 5 fasilitas kesehatan, 4 perkantoran dan 10 unit jembatan.</p><p><br></p>', '1719208485469-catatanbencana.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719208485469-catatanbencana.jpg', '2024-06-24 05:54:45', '2024-06-24 05:54:45'),
(29, 'Kejadian Banjir Kelurahan Mendui kecamatan Bungku Tengah Kabupaten Morowali ', 'terbaru', '2023-07-28', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Kejadian banjir terjadi di Kel Mendui Kec Bungku Tengah Kab Morowali pada Kamis (27/07/23) pukul 03 00 WITA. Hujan lebat menyebabkan Sungai Sakita meluap hingga menyebabkan banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Berdasarkan data yang diperoleh dari laporan sementara, akibat kejadian ini sebanyak 10 unit rumah warga terdampak\".Ucap Kepala Bidang Kedaruratan dan Logistik</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Aparat desa setempat berkoordinasi dengan pihak BPBD Kab. Morowali. Masyarakat setempat melakukan pembersihan sungai. Kebutuhan mendesak yang diperlukan berupa normalisasi sungai dan pembuatan tanggul penahan air. Situasi terkini di tempat kejadian banjir telah surut.&nbsp;</p><p><br></p>', '1719209026727-kelmendui.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719209026727-kelmendui.jpg', '2024-06-24 06:03:46', '2024-06-24 06:03:46'),
(30, '108 Kejadian Bencana Di Sulteng didominasi Banjir', 'rekomendasi', '2023-12-04', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Berdasarkan hasil Rekap Data Kejadian Bencana Pusat Pengendalian Operasi (Pusdalops) Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah (Sulteng) pada tahun 2023 Provinsi Sulawesi Tengah mengalami kejadian bencana alam dengan total 108 kejadian dengan jenis kejadian Banjir yang mendominasi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Mayoritas bencana alam tersebut berupa banjir yaitu sebanyak 54 kejadian bencana banjir yang tersebar di Provinsi Sulteng</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Dalam hal ini, manager Pusdalops Yulianingsih Prischilla S.Tr.Ip, mengatakan Berdasarkan wilayahnya, pada 1 Januari hingga 4 Desember 2023 bencana daerah bencana alam paling banyak 10 kejadian terjadi di daerah banggai, Donggala, Morowali Utara dan Poso</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“Dari data yang kita punya, ada 13 kejadian kebakaran hutan dan lahan (karhutla), 20 kejadian puting beliung, kekeringan 2 kejadian, gempa bumi 2 kejadian, abrasi 4 kejadian, banjir bandang 1 kejadian, banjir rob 5 kejadian, gelombang pasang 2 kejadian, Tanah longsor 20 kejadian dan bencana yang paling mendominasi Dari data kita yaitu Banjir ada 54 kejadian, ” ucap Yulianingsih, Senin (04/12/23).</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Yulianingsih atau yang sering disapa Yuli menambahkan berdasarkan wilayahnya, pada 1 Januari hingga 4 Desember 2023 bencana daerah bencana alam paling banyak 10 kejadian terjadi di daerah banggai, Donggala, Morowali Utara dan Poso.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Sebanyak 483 Rumah Rusak Ringan (RR), 91 Rumah Rusak Sedang (RS) dan 29 Rumah Rusak Berat (RB). Selain permukiman terdapat fasilitas umum yang mengalami kerusakan seperti fasilitas pendidikan 35, fasilitas Sarana Ibadah 33, fasilitas Kesehatan 7 unit.</p>', '1719209215835-dominasibencana.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719209215835-dominasibencana.jpg', '2024-06-24 06:06:55', '2024-06-24 06:06:55'),
(31, 'Banjir Menggenangi Dua Desa Di Kabupaten Poso', 'terbaru', '2023-12-28', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Banjir terjadi di Desa Alitupu Kec. Lore Utara Kab. Poso pada Selasa 26 Desember 2023 pukul 01.00 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Intensitas hujan yang tinggi mengakibatkan aliran sungai Desa Alitupu menggenangi pemukiman, bangunan sekolah dasar dan dua gedung mesjid. selain itu menyebabkan jembatan yang menghubungkan Dusun Laricing terputus. Sebanyak 126 KK dan 504 jiwa terdampak akibat kejadian ini. saat ini diperlukan perbaikan jembatan yang terputus.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Selain Desa Alitupu, diwaktu yang sama juga terjadi banjir di Desa Bumi Banyusari Kec. Lore Utara Kab. Poso. intensitas hujan yang tinggi mengakibatkan meningkatnya volume air sungai sehingga menyebabkan tanggul Sungai Pembala jebol dan sampai saat ini air sungai masih menggenangi area perkebunan warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kebutuhan mendesak saat ini ialah bantuan solar untuk pengoprasian alat berat situasi saat ini air telah surut dan pemerintah desa bersama masyarakat melakukan gotong royong bersama masyarakat untuk melakukan upaya penanggulangan darurat dengan membuat tanggul darurat dari karung pasir</p><p><br></p>', '1719209815760-Poso.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719209815760-Poso.jpg', '2024-06-24 06:16:55', '2024-06-24 06:16:55'),
(32, 'Banjir di Desa lalundu Kabupaten Donggala Merendam Ratusan Rumah warga', 'terbaru', '2023-01-08', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Kejadian Banjir yang terjadi di Desa Lalundu Kecamatan Rio Pakava Kabupaten Donggala pada Rabu (04/01/2023) terendam banjir akibat intensitas hujan yang tinggi mengakibatkan meluapnya air Sungai ke pemukiman warga</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kepala Pelaksana (Kalak) Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah, Dr.Ir Akris Fattah Yunus mengatakan bahwa Banjir terjadi pada Kamis sore, sekitar pukul 17.00 Wita yang merendam ratusan rumah warga</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“peristiwa banjir terjadi di tiga dusun yakni di Dusun Dua, Dusun Empat dan Dusun Lima di Desa Lalundu yang disebabkan oleh intensitas hujan yang tinggi mengakibatkan air Sungai Lalundu meluap sehingga merendam permukiman warga dan fasilitas umum,” Kata Kepala Pelaksana BPBD Sulteng Akris Fattah Yunus</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Menanggapi peristiwa banjir, tim mendapatkan informasi dari aparat desa setempat, berkoordinasi segera dilakukan dengan Tim Reaksi Cepat (TRC) BPBD Kabupaten Donggala untuk meninjau lokasi banjir dan melakukan asesmen</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“selain 200 unit rumah yang terendam banjir, juga merendam satu unit puskesmas, dua unit sekolah, satu jembatan rubuh dan dua unit masjid. Adapun yang menjadi kebutuhan mendesak yaitu alat berat dan bantuan logistik,” ucapnya</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Sementara itu, kata dia, untuk saat ini warga tetap bertahan di rumah masing-masing dan saat ini air perlahan surut.</p><p><br></p>', '1719210032515-Lalundu.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719210032515-Lalundu.jpg', '2024-06-24 06:20:32', '2024-06-24 06:20:32'),
(33, 'BAnjir dan Tanah Longsor Melanda Dusun 4 Desa Siboang Kecamatan Sojol Kabupaten Donggala', 'terbaru', '2024-01-22', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Banjir terjadi Di Dusun 4 Desa Siboang pada Senin, 15 Januari 2024 pada pukul 14.00 WITA. Intensitas hujan yang tinggi mengakibatkan meluapnya aliran sungai Dusun 4 Desa Siboang dan terjadinya tanah longsor di area pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan hasil pendataan tim, sebanyak 30 KK terdampak, terdiri dari 35 jiwa laki-laki, 21 jiwa perempuan, 10 jiwa lansia, anak-anak/balita sebanyak 10 jiwa serta 2 jiwa bayi. 11 unit rumah hanyut terseret banjir serta 1 unit jembatan putus. Sebanyak 11 KK mengungsi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kebutuhan mendesak di lapangan berupa bantuan logistik PB (family kit dan kidsware), makanan siap saji serta pakaian layak pakai.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi saat ini, air sudah surut. warga membuat 2 tenda darurat untuk menjadi tempat pengungsian, akses jalan hanya bisa dilalui dengan jalan kaki. Sebagian masyarakat yang rumahnya terdampak mengungsi di gedung sekolah SDN Sipator. Tim belum bisa memasuki pemukiman terdampak dikarenakan situasi sungai siboang banjir.</p><p><br></p>', '1719210279332-Siboang.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719210279332-Siboang.jpg', '2024-06-24 06:24:39', '2024-06-24 06:24:39'),
(34, 'Kepala Pelaksana BPBD Sulteng Mengimbau Masyarakat Waspada Potensi Banjir di Musim Penghujan', 'favorit', '2024-01-24', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah- Menghadapi musim hujan di Provinsi Sulawesi Tengah, Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah (Sulteng) memberikan imbauan agar tetap tingkatkan kewaspadaan dimusim penghujan kepada seluruh masyarakat baik kota maupun kabupaten.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan data kejadian bencana dari Pusat Pengendali Operasi Pusdalops BPBD Provinsi Sulteng tercatat banjir terdapat ditiga Kabupaten yaitu kabupaten Donggala Morowali Utara dan Tojo Una-una</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kepala Pelaksana BPBD Provinsi Sulawesi Tengah, Dr.Ir Akris Fattah Yunus, Rabu (24/01/24), mengatakan melalui perkiraan BMKG, musim hujan di Provinsi Sulteng secara umum terjadi pada bulan Januari hingga maret 2024 yaitu tingkat curah hujan yang tinggi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Memasuki bulan Januari hingga Maret berdasarkan perkiraan BMKG curah hujan yang cukup tinggi Untuk itu kerawanan bencana di Provinsi Sulteng saat musim hujan adalah terjadinya banjir angin puting beliung dan tanah longsor Ketiga potensi kerawanan ini yang sering ditangani dimusim penghujan ujarnya</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Untuk itu salah satu upaya mengantisipasi, BPBD Provinsi Sulteng mengimbaukan kepada masyarakat Provinsi Sulawesi Tengah, yaitu meningkatkan kewaspadaan terhadap ancaman banjir, puting beliung, cuaca ekstrim, tanah longsor dilingkungan atau diwilayah Kota maupun Kabupaten</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“diimbau kepada seluruh masyarakat bagi pengguna jalan agar lebih waspada dan berhati-hati ketika berkendara dalam situasi hujan deras, dan disarankan untuk menepi atau berteduh jika jarak pandang tidak memungkinkan dalam berkendara, masyaraakat juga menghindari area pantai, sungai untuk tetap siaga jika terjadi hal yang tidak diinginkan,”tuturnya.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Lanjutnya, dalam hal ini masyarakat diminta untuk memperhatikan barang-barang berharga serta barang penting seperti dokumen. Namun, Kalak BPBD Sulteng Akris, meminta masyarakat untuk tidak panik, tapi tetap waspada, mengingat curah hujan beberapa hari ini cukup tinggi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“Jika ada tanda tanda akan berpotensi bencana, masyarakat bisa melaporkan ke RT/RW setempat, lurah dan nantinya lurah yang akan meneruskan ke dinas terkait dan BPBD,\" pungkasnya.</p><p><br></p>', '1719210472519-kalaksa.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719210472519-kalaksa.png', '2024-06-24 06:27:52', '2024-06-24 06:27:52'),
(35, 'Hujan Yang Mengguyur Desa Kumbasa Semalaman Mengakibatkan Warga Terisolir', 'terbaru', '2024-01-24', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Kejadian banjir terjadi di Desa Kumbasa, Kecamatan Sindue Kabupaten Donggala pada Rabu (09/01/23) pada pukul 09.00 WITA</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Hujan yang mengguyur dengan intensitas tinggi sejak pukul 23.00 WITA hingga pukul 10.00 WITA menyebabkan meningkatnya debit air sungai sehingga jembatan tidak bisa diakses. untuk sementara masyarakat di Desa Kumbasa terisolasi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan sekitar 100 KK masyarakat Desa Kumbasa terisolasi serta 1 unit jembatan rusak. LAngkah yang dilakukan saat ini ialah melakukan assessment dan berkoordinasi dengan aparat desa setempat. Terkait data kebutuhan mendesak saat ini masih belum diketahui.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi di lokasi kejadian saat ini, hujan berangsur mereda, Jembatan penghubung Desa Kumbasa masih belum bisa diakses akibat banjir serta aparat Desa Kumbasa menghimbau kepada masyarakat untuk tetap waspada.</p><p><br></p>', '1719210589653-kumbasa.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719210589653-kumbasa.png', '2024-06-24 06:29:50', '2024-06-24 06:29:50'),
(36, 'Hujan Sejak Dini Hari Menyebabkan Banjir di Desa Malino Jaya Kecamatan Soyo Jaya Kabupaten Morowali Utara', 'terbaru', '2024-01-24', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah- Kejadian Banjir yang terjadi di Desa Malino Jaya Kecamatan Soyo Jaya Kabupaten Morowali Utara pada Senin, (22/01/24) Hujan deras melanda wilayah Kabupaten Morowali Utara sejak Senin dini hari sejak pukul 02.25 WITA</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan data yang diperoleh dari Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah, terdapat tiga rumah warga, tiga unit lapak jualan rusak ringan dan jalan trans Malino, Bugi Touna serta tebing pengaman (bronjong) rusak berat akibat banjir yang melanda di Desa Malino Jaya.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kepala Pelaksana BPBD Provinsi Sulteng Dr.Ir Akris Fattah Yunus mengatakan, terjadi hujan dengan intensitas tinggi di Desa Malino Jaya karena tersumbatnya saluran air mengakibatkan air sungai meluap dan menggenangi pemukiman warga serta mengakibatkan dampak kerusakan,</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“Alhamdulillah tidak ada korban jiwa, semuanya berhasil menyelamatkan diri saat banjir, namun untuk kebutuhan mendesak mereka meminta untuk normalisasi sungai .” ungkapnya</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Merujuk pada informasi dari BPBD Kabupaten Morowali Utara, situasi akhir saat ini air sudah surut dan masyarakat yang terdampak banjir telah membersihkan rumah mereka masing-masing. Namun masyarakat dihimbau untuk tetap waspada dan selalu melaporkan apabila ada tanda-tanda akan terjadi bencana, sedini mungkin.</p><p><br></p>', '1719210956792-soyojaya.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719210956792-soyojaya.png', '2024-06-24 06:35:57', '2024-06-24 06:35:57'),
(37, 'Banjir Terjang Sungai Wera Renggut 3 Korban Jiwa', 'terbaru', '2024-02-27', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah- Akibat cuaca buruk Banjir melanda Desa Balumpewa, Kecamatan Dolo Barat, Kabupaten Sigi, pada Senin (26/02/24) Pukul 18:17 WITA. Berdasarkan data yang diterima oleh Pusat Pengendalian Operasi (Pusdalops) Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah. Awalnya akibat intensitas hujan tinggi mengguyur wilayah Sungai Wera mengakibatkan debit air Sungai meningkat.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kepala Pelaksana (Kalak) BPBD Sulteng, Dr.Ir Akris Fattah Yunus, mengatakan Akibat luapan Sungai itu, menyebabkan 3 orang korban yang sedang berada di sekitar air terjun terbawa arus Sungai, 1 korban jiwa meninggal Dunia dan 2 orang belum ditemukan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“intensitas hujan yang tinggi menyebabkan banjir di sungai Wera, mengakibatkan debit air Sungai meningkat sehingga menyebabkan 3 korban, 2 orang belum ditemukan dan 1 orang meninggal dunia,” ucapnya.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Akris menyampaikan upaya penanganan yang dilakukan dengan mengerahkan Tim Reaksi Cepat (TRC) BPBD Sulteng untuk membantu melakukan pengupayaan pencarian 2 korban yang saat ini belum ditemukan serta melakukan evakuasi korban yang membutuhkan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“adapun langkah yang dilaksanakan yaitu telah melakukan assessment, berkoordinasi dengan BPBD kabupaten sigi, berkoordinasi dengan Basarnas Kota Palu, dan tim BPBD Sulteng telah melakukan upaya penanganan pencarian korban yang saat ini belum ditemukan,”</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Untuk situasi akhir saat ini pencarian korban sedang dihentikan dan akan dilanjutkan pada Selasa 27 Februari 2024 pada pagi hari.</p><p><br></p>', '1719211078128-wera.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719211078128-wera.png', '2024-06-24 06:37:58', '2024-06-24 06:37:58'),
(38, '4 Kecamatan Terdampak Banjir, BPBD Sulteng Salurkan Dukungan Penanganan Bencana', 'terbaru', '2024-03-05', 'fb', 'Ya', '<p class=\"ql-align-justify\">Palu - Menanggapi kejadian bencana banjir di Kabupaten Buol, Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah melakukan penyaluran dukungan, baik dari dukungan logistik hingga dukungan upaya penanganan pada hari Senin (4/03/2024).</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Sehubungan dengan hal tersebut, BPBD Provinsi Sulawesi Tengah menurunkan sejumlah personil diantaranya 4 Orang Personil TRC-PB dan 3 Orang Personil PUSDALOPS untuk melakukan dukungan upaya penanganan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Tidak hanya itu, BPBD Prov. Sulteng juga menyalurkan dukungan logistik seperti :</p><p class=\"ql-align-justify\">Paket Hunian sementara sebanyak 37 Paket, paket perlengkapan keluarga sebanyak 26 paket, kidsware 25 paket, masker sebanyak 1512 pcs serta selimut sebanyak 106 lembar. Dukungan tersebut akan disalurkan ke 4 kecamatan yang terdampak Banjir dan Tanah Longsor di Kabupaten Buol.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Sesuai Data Sementara, terdapat 4 Kecamatan terdampak yaitu : Kecamatan Karamat terdiri dari Desa Busak 1, Desa Busak 2, Desa Monano. Kecamatan Lakea Desa lakea 2, Desa Tuinan dan Desa Ngune. Desa Biau meliputi Kelurahan leok 1, Kelurahan Leok 2, Kelurahan Komaligon, Kel. Kali serta Kelurahan Kulango dan Kecamatan Momonu Desa Pinamula.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Pusdalops BPBD Provinsi Sulawesi Tengah akan melakukan pendampingan melalui pos pendamping penanganan darurat bencana banjir Kabupaten Buol.</p><p><br></p>', '1719211336413-salurkan.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719211336413-salurkan.png', '2024-06-24 06:42:16', '2024-06-24 06:42:16'),
(39, 'BPBD Sulteng Salurkan Bantuan Bagi Warga Terdampak Banjir dan Tanah Longsor di Buol', 'terbaru', '2024-03-06', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah (Sulteng) menyalurkan bantuan logistik untuk warga yang terdampak bencana Banjir dan Tanah Longsor di Kabupaten Buol pada minggu 3 Maret 2024 Pukul 04.30 WITA</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kepala Bidang Kedaruratan dan Logistik BPBD Provinsi Sulteng, Andy Sembiring, mengatakan penyaluran logistik di posko induk yang bertempat di kantor BPBD Buol telah diterima langsung oleh pihak BPBD Kabupaten Buol</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Tim kami dari BPBD Sulteng sudah distribusikan logistik ke BPBD Buol untuk warga yang terdampak banjir dan tanah longsor juga sudah mendirikan Pos Pendampingan untuk membantu mendampingi BPBD Buol dalam penanganan bencana,” Ucap Andy Sembiring, Rabu (06/03/24).</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">BPBD Sulteng saat menyalurkan bantuan di posko induk yang bertempat di kantor BPBD Buol</p><p class=\"ql-align-justify\">Lanjutnya, BPBD Provinsi Sulteng telah menyalurkan dukungan logistik berupa Paket Hunian Sementara sebanyak 37 Paket seperti Sleeping bag, tikar matras, kelambu dan terpal, Paket perlengkapan keluarga sebanyak 26 paket, paket kidsware 24 Paket, paket masker sebanyak 1512 pcs serta selimut sebanyak 106 lembar.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“selanjutnya penyaluran logistik akan didistribusikan oleh BPBD Kabupaten Buol kepada Masyarakat yang terdampak bencana. Dukungan tersebut akan disalurkan ke 4 kecamatan yang terdampak Banjir dan Tanah Longsor di Kabupaten Buol,”ungkapnya.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Selain itu, dalam penyerahan bantuan ini diharapkan dapat meringankan beban warga yang terdampak banjir dan tanah longsor.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Sebelumnya curah hujan yang tinggi mengakibatkan banjir di 4 kecamatan dan tanah longsor di Desa Busak I dan Leok II. Sesuai Data yang diterima oleh Pusat Pengendali Operasi (Pusdalops) BPBD Sulteng, terdapat 4 Kecamatan terdampak yaitu, Kecamatan Karamat terdiri dari Desa Busak 1, Desa Busak 2, Desa Monano. Kecamatan Lakea Desa lakea 2, Desa Tuinan dan Desa Ngune. Desa Biau meliputi Kelurahan leok 1, Kelurahan Leok 2, Kelurahan Komaligon, Kel. Kali serta Kelurahan Kulango dan Kecamatan Momonu Desa Pinamula.</p><p><br></p>', '1719211773113-salurkan2.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719211773113-salurkan2.png', '2024-06-24 06:49:33', '2024-06-24 06:49:33'),
(40, '3 Dusun Terdampak Banjir Dengan Ketinggian Air Mencapai Lutut Orang Dewasa', 'terbaru', '2024-06-22', 'Admin Dalops', 'Ya', '<p>Intensitas hujan sedang hingga tinggi mengguyur Desa Tindaki Kecamata Parigi Selatan Kabupaten Parigi Moutong pada Sabtu (22/06/24) pukul 22.00 WITA mengakibatkan banjir dengan ketinggian mencapai lutut orang dewasa.</p><p><br></p><p>Kejadian ini berdampak pada pemukiman warga di Dusun 1, 2 dan 6 sebanyak 100 unit rumah dan 2 Unit mesjid terendam. Diketahui pengungsi sebanyak 10 KK. Kebutuhan mendesak berupa Logistik PB.</p><p><br></p><p>Situasi akhir dilokasi kejadian hujan telah reda dan air berangsur surut.</p>', '1719211919943-WhatsAppImage2024-06-23at01.03.08.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719211919943-WhatsAppImage2024-06-23at01.03.08.jpeg', '2024-06-24 06:51:59', '2024-06-24 06:51:59'),
(41, 'Meluapnya Sungai Lente Mengakibatkan Banjir Setinggi Leher Orang Dewasa', 'terbaru', '2024-06-23', 'Admin Pusdalops', 'Ya', '<p>Banjir terjadi di Desa Dampal Kecamatan Sirenja Kabupaten Donggala pada Minggu (23/06/24) pukul 05.00 WITA. Intensitas hujan sedang hingga lebat mengakibatkan Sungai Lente meluap dan menggenangi Dusun 1, 2 dan 3 dengan ketinggian air mencapai leher orang dewasa.&nbsp;</p><p><br></p><p>Terdampak akibat kejadian ini diantaranya 200 unit rumah, 2 sarana pendidikan, 1 unit perkantoran serta 52 Ha lahan persawahan. Diketahui sebanyak 115 KK mengungsi.</p><p><br></p><p>Kebutuhan mendesak berupa logistik PB. Situasi akhir saat ini hujan telah reda dan warga sedang mengevakuasi diri ke tempat yang lebih aman</p>', '1719212286099-WhatsAppImage2024-06-23at07.55.38.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719212286099-WhatsAppImage2024-06-23at07.55.38.jpeg', '2024-06-24 06:58:06', '2024-06-24 06:58:06'),
(42, 'Banjir Bandang Terjang 2 Desa di Kecamatan Toribulu', 'terbaru', '2024-06-23', 'Admin Pusdalops', 'Ya', '<p>Banjir Bandang terjang 2 Desa Di Kecamatan Toribulu</p><p><br></p><p>Intensitas hujan sedang hingga lebat yang mengguyur Kecamatan Toribulu Kabupaten Parigi Moutong mengakibatkan banjir bandang di Desa Sibalago dan Desa Sienjo pada Minggu (23/06/24) pukul 04.38 WITA. Banjir tersebut disebabkan bertemunya air laut pasang dan banjir yang meluap dari Sungai Toribulu.</p><p><br></p><p>Terdampak di Desa Sienjo sebanyak 30KK. Di Desa Sibalago sebanyak 90 KK, serta 1 unit jembatan penghubung Sibalago dan Sienjo terputus. Pengungsi dalam proses pendataan. 1 jiwa meninggal dunia (Andi Nur Hayati) serta 1 orang belum ditemukan (Aco).</p><p><br></p><p>Kebutuhan mendesak berupa Alat Berst, Normalisasi Sungai, Perbaikan jembatan, Air bersih, serta Logistik PB. Situasi akhir hujan belum reda, masyarakat melakukan pembersihan material banjir bandang, warga Sibalago masih terisolir akibat putusnya jembatan, air perlahan surut.</p>', '1719212358103-WhatsAppImage2024-06-23at09.25.03.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719212358103-WhatsAppImage2024-06-23at09.25.03.jpeg', '2024-06-24 06:59:18', '2024-06-24 06:59:18'),
(43, 'Luapan Sungai Lembe dan Panasakan Sebabkan Tergenangnya Puluhan Rumah', 'terbaru', '2024-06-23', 'Admin Pusdalops', 'Ya', '<p>Luapan sungai Lembe dan Panasakan sebabkan tergenangnya puluhan rumah</p><p><br></p><p>Banjir terjadi di Kelurahan Baru dan Panasakan Kecamatan Baolan Kabupaten Toli-Toli pada Minggu (23/06/24) pukul 16.22 WITA.&nbsp;</p><p><br></p><p>Hujan dengan intensitas sedang mengakibatkan beberapa jalan dan rumah yang berada di sekitar Sungai tergenang air. Luapan sungai Lembe dan Panasakan serta sedimentasi pada saluran drainase dalam kota turut menjadi pemicu banjir.&nbsp;</p><p><br></p><p>Kejadian ini mengakibatkan 50 Unit rumah terdampak. Dibutuhkan pemeliharaan drainase. Kondisi saat ini air sudah turun namun hujan intensitas rendah masih berlangsung</p>', '1719212437087-WhatsAppImage2024-06-23at21.00.36.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719212437087-WhatsAppImage2024-06-23at21.00.36.jpeg', '2024-06-24 07:00:37', '2024-06-24 07:00:37'),
(44, 'Desa Rejeki Kecamatan Palolo Kabupaten Sigi Terendam Banjir', 'terbaru', '2024-06-23', 'Admin Pusdalops', 'Ya', '<p>Desa Rejeki Kecamatan Palolo Kabupaten Sigi terendam banjir.</p><p><br></p><p>&nbsp;Hujan dengan intensitas rendah hingga sedang mengakibatkan beberapa rumah di Desa Rejeki terendam banjir.&nbsp;</p><p><br></p><p>Kejadian ini mengakibatkan 47 KK, 175 jiwa, 16 Lansia, 2 ibu hamil serta 13 balita terdampak. Selain itu, 2 unit rumah dilaporkan rusak sedang.&nbsp;</p><p><br></p><p>Tidak ada korban jiwa akibat kejadian ini. Kondisi saat ini air telah surut</p>', '1719212490821-WhatsAppImage2024-06-23at23.40.27.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719212490821-WhatsAppImage2024-06-23at23.40.27.jpeg', '2024-06-24 07:01:30', '2024-06-24 07:01:30'),
(45, 'Luapan Sungai Rendam Pemukiman Warga di Desa Tombongan Ulos dan Kelurahan Kalaka', 'terbaru', '2024-06-23', 'Admin Pusdalops', 'Ya', '<p>Sungai di Kelurahan Kalaka Meluap merendam Desa Tombongan Ulos dan Kelurahan Kalaka</p><p><br></p><p>Banjir terjadi di Kelurahan Kalaka dan Desa Tombongan Ulos Kecamatan Bunta Kabupaten Banggai pada Minggu (23/06/24) pukul 17.30 WITA. Intensitas hujan sedang hingga lebat yang terjadi mengakibatkan meluapnya Sungai di Kelurahan Kalaka hingga menggenangi pemukiman warga.</p><p><br></p><p>Terdampak di Kelurahan Kalaka diantaranya 50KK, 10 unit rumah rusak berat serta 1 unit rumah hanyut terbawa arus banjir. Sementara itu, di Desa Tombongan Ulos meliputi Dusun I sebanyak 11 unit rumah terendam, Dusun II terdapat 2 unit rumah terendam.</p><p><br></p><p>Kebutuhan mendesak berupa normalisasi sungai. Situasi saat ini hujan telah redah dan air telah surut.</p>', '1719212565683-WhatsAppImage2024-06-24at00.31.42.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719212565683-WhatsAppImage2024-06-24at00.31.42.jpeg', '2024-06-24 07:02:45', '2024-06-24 07:02:45'),
(47, 'Dua Rumah Warga Terseret Banjir Di Buol', 'terbaru', '2024-03-07', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Kejadian Banjir terjadi di Kecamatan Paleleh, Kabupaten Buol, Sulawesi Tengah pada kamis, 7 Maret 2024. Sekitar puluhan rumah terendam banjir khususnya di Desa Mulangato.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan laporan yang di terima Pusat Pengendali Operasi (Pusdalops) Badan Penanggulangan Bencana Daerah (BPBD) setempat, banjir terjadi akibat intensitas hujan yang tinggi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Hal ini dibenarkan oleh Kepala Pelaksana (Kalak) BPBD Provinsi Sulteng, Akris Fattah Yunus melalui laporan yang diterimanya, terdapat 2 rumah di sekitar sungai terbawa arus dan setidaknya 40 unit rumah ikut terendam banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“Hujan lebat dari malam hari hingga pagi tadi, membuat meluapnya air sungai yang mengakibatkan 2 rumah disekitar sungai terbawah arus, dan setidaknya 40 rumah lainnya terendam banjir”ucapnya.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Tidak ada korban jiwa dalam peristiwa itu. Saat ini BPBD setempat Bersama Tim Reaksi Cepat (TRC) Buol dan TRC Bersama Pusdalops BPBD Provinsi Sulteng tengah melakukan pendataan dan berkoordinasi dengan aparat desa.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Untuk situasi kondisi banjir sudah berangsur surut, namun hujan terus mengguyur daerah itu dengan intensitas tinggi,\" jelasnya.</p><p><br></p>', '1719213023456-2rmhterseret.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719213023456-2rmhterseret.png', '2024-06-24 07:10:23', '2024-06-24 07:10:23'),
(48, 'Huntara korban BAnjir Touna Hampir Rampung ', 'terbaru', '2024-03-08', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah- Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah (Sulteng) membangun Hunian Sementara (Huntara) bagi warga yang terdampak banjir di Desa Tayawa, Kabupaten Tojo Una-una. Huntara korban banjir ini akan dibangun sebanyak 6 unit. Sementara capaian progres pembangunan huntara sudah menyentuh 75 persen.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kepala Bidang Kedaruratan dan Logistik, Andi Sembiring menyampaikan, pembangunan huntara bagi warga terdampak bencana banjir akan terus dipercepat, sehingga sebelum bulan puasa, masyarakat bisa menempati hunian yang disediakan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Kami memacu tim pembangunan huntara di Desa Tayawa ini agar bisa ditempati masyarakat sebelum Ramadhan 1445Hijriah,\" ucapnya, Jumat (08/03/2024).</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan data BPBD Sulteng, tercatat yang menempati hunian sementara korban bencana ada sekitar 6 KK yang kondisi rumahnya tak layak huni.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Total ada 6 unit yang dibangun, tapi baru 4 unit yang selesai dan 2 unit sementara penyelesaian. Ditargetkan sebelum puasa ini korban sudah bisa menemapati,\" harapnya.</p><p><br></p>', '1719213144379-huntara.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719213144379-huntara.png', '2024-06-24 07:12:24', '2024-06-24 07:12:24'),
(49, '44 KK Terdampak Banjir di Desa Ogomolos Kabupaten Parigi Moutong ', 'terbaru', '2024-07-23', 'fb', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Banjir merendam sebanyak tiga dusun di Desa Ogomolos, Kecamatan Mepanga, Kabupaten Parigi Moutong, Sulawesi Tengah pada Rabu, (27/03/2024). Banjir ini disebabkan intensitas curah hujan tinggi yang mengakibatkan meluapnya sungai Mubang hingga ke pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Total ada 44 KK dengan 130 jiwa dari tiga dusun yang terdampak banjir di desa Ogomolos. Dusun terdampak diantramya II, III dan IV,\" kata Kepala Pelaksana BPBD Sulteng, Akris Fattah.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Atas kejadian ini, tidak ada warga setempat yang mengungsi bahkan tidak ditemukan adanya korban jiwa. Namun ada lahan perkebunan warga sekitar 20 Hektare yang ikut terendam.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Untuk kebutuhan mendesak saat ini yaitu normalisasi sungai hingga sejumlah kebutuhan pokok warga diantaranya sembako, selimut, peralatan dapur dan perlengkapan makan lainnya,\" ujarnya.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kini situasi banjir yang merendam desa ogomolos telah berangsur surut. Saat ini hujan yang sebelumunnya mengguyur daerah parigi moutong dan sekitarnya telah redah.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Dari hasil koordinasi dengan BPBD setempat, warga telah membersihkan rumahnya karna banjir telah surut,\"tutupnya.</p><p><br></p>', '1719214382933-ogomolos44kk.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719214382933-ogomolos44kk.png', '2024-06-24 07:33:02', '2024-06-24 07:33:02'),
(50, 'Banjir Merendam 3 Kecamatan di Kabupaten Buol', 'terbaru', '2024-04-07', 'admin Pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah- Banjir meredam Kabupaten Buol, Kecamatan Paleleh, Kecamatan Paleleh Barat dan Kecamatan Lakea, Minggu, (07/04/2024) Pukul 18.30 Wita</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Menurut laporan yang diterima Pusat Pengendali Operasi (Pusdalops) Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah (Sulteng) Intensitas curah hujan yang tinggi mengakibatkan meluapnya sungai hingga menggenangi pemukiman warga</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Akibatnya sejumlah fasilitas umum terendam banjir, begitu pula dengan rumah masyarakat . Bahkan menurut laporan koordinasi Bersama BPBD Kabupaten Buol, sejumlah kendaraan tidak bisa terhindar dari tingginya luapan air</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Hal ini dibenarkan oleh Kepala Bidang Kedaruratan dan Logistik BPBD Sulteng, Andy A. Sembiring, melalui laporan yang diterimanya, ada III Kecamatan yang terdampak banjir di Kabupaten Buol</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“Belum diketahui pasti berapa besar dampak banjir, namun dari laporan yang kami terima, Desa Talaki 350 KK dengan 1600 jiwa, ?Desa Kwala Besar masih dalam pendataan, ?Desa Dutuno masih dalam pendataan, sementara kecamatan Paleleh barat ada empat desa masih dalam pendataan dan kecamatan Lakea, Desa Lakea II masih dalam pendataan” Kata Kepala Bidang Kedaruratan dan Logistik, Andy Sembiring</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Andy menambahkan, saat ini ia telah menyiapkan personil Tim Reaksi Cepat (TRC) BPBD Provinsi Sulteng untuk dapat sewaktu waktu dapat turun ke lokasi terdampak bencana yang terjadi di Kabupaten Buol</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“untuk kebutuhan mendesak saat ini yaitu sejumlah kebutuhan warga seperti Logistik penanganan bencana, perlengkapan bayi, Pakaian dan selimut,”ujarnya</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Atas kejadian ini, tidak ditemukan adanya korban jiwa, warga yang mengungsi bahkan masi dalam pendataan. Saat ini situasi hujan yang sebelumnya mengguyur daerah Buol masih berlangsung dengan intensitas sedang</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“Dari hasil koordinasi dengan BPBD setempat, banjir di desa Talaki mulai berangsur surut, Masyarakat juga melakukan evakuasi mandiri ke rumah kerabat dan beberapa lokasi yang lebih aman,”tutupnya.</p><p><br></p>', '1719277186208-buol.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719277186208-buol.png', '2024-06-25 00:59:46', '2024-06-25 00:59:46'),
(51, 'Curah Hujan Tinggi Banjir Rendam 14 Rumah Warga di Sigi', 'terbaru', '2024-04-11', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah- Banjir kembali meredam Desa Sambo, Kecamatan Dolo Selatan, Kabupaten Sigi, Kamis (11/04/2024) Pukul 19.30 Wita.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan laporan yang diterima Pusat Pengendali Operasi (Pusdalops) Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah (Sulteng) Intensitas curah hujan yang tinggi di pegunungan menyebabkan meluapnya air di daerah aliran sungai Sambo meluap</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Akibatnya meluap ke pemukiman warga hingga merendam persawahan dan perkebunan dengan ketinggian berkisar 50 cm sehingga merendam 14 rumah warga turut terdampak banjir tersebut.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Hal ini dibenarkan oleh Kepala Pelaksana BPBD Provinsi Sulteng, Akris Fattah Yunus, melalui laporan yang diterimanya jika ada 14 Kepala Keluarga (KK) dan 55 Jiwa yang terdampak.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Intensitas curah hujan yang tinggi di pegunungan menyebabkan air meluap ke sungai Sambo hingga ke pemukiman warga dengan ketinggian 50 cm ujarnya</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Atas kejadian ini, disebutkan tidak ditemukan adanya korban jiwa, bahkan tidak adasatupun warga yang mengungsi. Sementara hujan sudah berhenti dan banjir masih menggenangi rumah warga</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"untuk kebutuhan mendesak saat ini yaitu alat berat, dari hasil koordinasi BPBD Kabupaten Sigi bersama pemerintah desa sambo,\" sebutnya.</p><p><br></p>', '1719277376783-samboo.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719277376783-samboo.png', '2024-06-25 01:02:56', '2024-06-25 01:02:56'),
(52, 'Dua Desa Di Kecamatan Dolo Selatan Terdampak Banjir ', 'terbaru', '2024-04-17', 'admin Pusdalops', 'Ya', '<p class=\"ql-align-justify\">Palu-Tepat pada pukul 22.00 Wita (17/04/2024), 2 (Dua) Desa di Kec. Dolo Selatan, tepatnya di Desa Balongga dan Desa Sambo terendam banjir sehingga membuat warga geger karena kejadian tersebut.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Menanggapi hal tersebut, Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah menurutkan sejumlah personil untuk penangan kejadian banjir di 2 desa tersebut.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Dikabarkan, 1 orang lansia harus dievakuasi karena rumahnya yang terjebak banjir, langsung Tim TRC-PB BPBD Prov. Sulteng dengan sigap mengevakuasi korban dan membawa korban ke tempat yang lebih aman.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Menurut Koordinator Lapangan Tim TRC-PB BPBD Prov Sulteng, M. Roys menjelaskan bahwa, hingga hari ini (Kamis, 18/04/2024) jumlah warga yang terdampk di Desa Sambo 307 Jiwa (103 KK), 91 unit Rumah Terdampak dan kurang lebih 50 ha lahan perkebunan terdampak banjir. Sedangkan di Desa Balongga, 384 Jiwa (112 KK) warga terdampak oleh banjir. 1 orang luka-luka dan 73 Unit Rumah warga terdamak oleh banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“Sesuai data yang tim kami peroleh, di Desa Sambo ada 307 Jiwa (103 KK) warga yang terdampak, 91 unit rumah warga, dan kurang lebih 50 ha lahan perkebunan warga terdampak. Sedangkan di Desa Balongga, 384 Jiwa (112 KK) terdampak oleh banjir, 1 orang luka-luka, dan 73 unit rumah warga terdampak banjir.” Jelar Koordinator Lapangan M.Roys saat di wawancara via telfon.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Beliau juga menambahkan, Kepala Pelanksana BPBD Prov. Sulteng Dr. Ir. H. Akris Fattah Yunus, MM sempat meninjau langsung, dan melihat langsung ke lokasi kejadian. Dan juga beliau sempat berkoordnasi langsung dengan Wakil Bupati Sigi membahas penanggulangan bencana di Kec. Dolo Selatan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">“Bapak Dr. Ir. H. Akris Fattah Yunus, MM selaku Kepala Pelaksana BPBD Prov Sulteng juga sempat meninjau dan melihat langsung ke lokasi kejadian, beliau juga berkoordinasi dengan beberapa pejabat di lingkup Kab. Sigi seperti Wakil Bupati Sigi membahas penanggulangan bencana di Kec. Dolo Selatan” tutupnya.-</p><p class=\"ql-align-justify\"><br></p><p><br></p>', '1719277733450-dolsel.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719277733450-dolsel.png', '2024-06-25 01:08:53', '2024-06-25 01:08:53'),
(53, 'Banjir Terjang Dua Desa Di Kabupaten Sigi', 'terbaru', '2024-04-17', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah- Banjir meredam 2 Desa di Kecamatan Dolo Selatan, Kabupaten Sigi, Sulawesi Tengah pada Rabu (17/04/2024), sekitar Pukul 07.00 Wita.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Data yang diterima Pusat Pengendali Operasi (Pusdalops) Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah (Sulteng) Intensitas curah hujan yang tinggi menyebabkan meluapnya di daerah aliran di daerah sungai Balongga di wilayah tersebut.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kepala Pelaksana BPBD Provinsi Sulteng, Akris Fattah Yunus, sebanyak 2 desa yang terdampak diantaranya Desa Sambo dan Desa Balonga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"akibat meluapnya sungai Balongga, banjir ini tidak hanya merendam pemukiman warga namun satu orang hanyut terbawah arus banjir. tapi syukur Alhamdullilah ditemukan dalam keadaan selamat ,\" Sebutnya</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">atas kejadjian ini, belum diketahui berapa jumlah yang terdampak dan mengungsi karena masih dalam tahap pendataan</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Dalam hal ini, Kepala Bidang Kedaruratan dan Logistik, Andy Sembiring mengatakan, bahwa tim BPBD Sulteng segera menuju untuk kelokasi banjir di kabupaten Sigi</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Personil kami saat ini segera persiapan untuk akses kelokasi,\" singkatnya.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Situasi akhir banjir mulai menggenangi pemukiman warga, tadi sudah koordinasi bersama kepala desa dan pemerintah desa juga yang hanyut sudah di temukan dan saat ini akses jalan Palu-Bangga terputus\" tutupnya</p><p><br></p>', '1719277868613-sigi2.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719277868613-sigi2.png', '2024-06-25 01:11:08', '2024-06-25 01:11:08'),
(54, 'Banjir Rendam 5 Desa di Morowali Utara', 'terbaru', '2024-04-16', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah- Banjir meredam 5 Desa di Kecamatan Petasia Barat, Kabupaten Morowali Utara, Sulawesi Tengah pda Minggu (16/04/2024), sekitar Pukul 07.00 Wita.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Data yang diterima Pusat Pengendali Operasi (Pusdalops) Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah (Sulteng) Intensitas curah hujan yang tinggi menyebabkan meluapnya air di daerah aliran sungai Daan di wilayah tersebut.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kepala Pelaksana BPBD Provinsi Sulteng, Akris Fattah Yunus, sebanyak 5 desa yang terdampak diantaranya desa Sampalowo, Onepute, Moleono, Togo Mulya dan Ululaa. Bahkan banjir ini tidak hanya merendam pemukiman namun juga perkebunan yang jadi sumber mata pencarian warga ikut terdampak.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Total ada 289 KK dari 5 desa terdampak dan sekitar ratusan hektare perkebunan dan persawahan hingga sebagian fasilitas umum seperti masjid dan sekolah juga terendam banjir itu,\" sebutnya.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Tidak ditemukan adanya korban jiwa, atas kejadjian ini, namun sekitar 4 Kepala keluarga di salah satu desa terdampak memilih mengungsi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Hasil koordinasi kami dari aparat desa setempat dan TRC BPBD morut, untuk kebutuhan mendesak warga saat ini yaitu logistik Sembako, Obat-obatan, dan air bersih,\" harapnya</p><p class=\"ql-align-justify\"><br></p><p><br></p>', '1719278204384-mrutt.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719278204384-mrutt.png', '2024-06-25 01:16:44', '2024-06-25 01:16:44'),
(55, 'Jalur Penghubung Desa Kolori Terputus', 'terbaru', '2024-04-26', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah- Banjir meredam Desa Lengkeka, Kecamatan Lore Barat, Kabupaten Poso,Selasa (16/04/2024) Pukul 20.30 Wita</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan laporan yang diterima Pusat Pengendali Operasi (Pusdalops) Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah (Sulteng) Intensitas curah hujan yang tinggi di menyebabkan meluapnya air di daerah aliran sungai Daan</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Akibatnya, merendam 3 rumah warga turut terdampak banjir tersebut hingga jalan menuju Desa Kolori terputus kurang lebih 15 Ruas Jalan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Hal ini dibenarkan oleh Kepala Pelaksana BPBD Provinsi Sulteng, Akris Fattah Yunus, melalui laporan yang diterimanya ada 3 Kepala Keluarga (KK) yang terdampak.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"Intensitas curah hujan yang tinggi pada malam hari mengakibatkan sungai Daan meluap hingga ke pemukiman warga serta jalur penghubung menuju Desa Kolori terputus,\" ujarnya.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Atas kejadian ini, disebutkan tidak ditemukan adanya korban jiwa, bahkan tidak ada satupun warga yang mengungsi. Situasi saat ini menunjukkan bahwa banjir mulai surut</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">\"untuk kebutuhan mendesak saat ini yaitu perbaikan jalan, dari hasil koordinasi aparat Desa Lengkeka bersama Babinsa,\" sebutnya.</p><p class=\"ql-align-justify\"><br></p><p><br></p>', '1719278410616-lengkeka.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719278410616-lengkeka.png', '2024-06-25 01:20:10', '2024-06-25 01:20:10'),
(56, 'Desa Korobono Terendam Banjir', 'terbaru', '2023-05-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Korobono Kecamatan Pamona Tenggara Kabupaten Poso pada Selasa (07/05/24) pukul 17.30 WITA. Hujan dengan intensitas sedang hingga lebat mengakibatkan banjir dengan ketinggian 40 cm yang menggenangi pemukiman, persawahan serta jalan trans.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 52 KK, fasilitas umum, 1 unit kantor desa, 1 unit kantor kecamatan, 1 unit rumah ibadah, 4 unit gedung sekolah serta sekitar 38 Ha lahan persawahan terdampak. Dibutuhkan normalisasi sungai. Kondisi saat ini air masih menggenangi pemukiman.</p><p class=\"ql-align-justify\">&nbsp;</p><p><br></p>', '1719278760753-korobono.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719278760753-korobono.png', '2024-06-25 01:26:00', '2024-06-25 01:26:00'),
(57, 'Banjir terjadi di Desa Mohoni Kecamatan Petasia Timur Kabupaten Morowali', 'terbaru', '2024-05-06', 'admin pusdalops ', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Mohoni Kecamatan Petasia Timur Kabupaten Morowali Utara pada Senin (06/05/24) pukul 20.00 WITA. Hujan dengan intensitas sedang hingga lebat yang di sertai kilat pada Senin-Selasa pukul 20.00 hingga 04.00 WITA menyebabkan meluapnya Sungai Tambalako sehingga merendam Dusun 1 dengan ketinggian air sekitar 40cm.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 25 KK. Dibutuhkan sembako dan logistik PB lainnya. Kondisi saat ini air berangsur surut.</p><p><br></p>', '1719279001443-mohoni.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719279001443-mohoni.png', '2024-06-25 01:30:01', '2024-06-25 01:30:01'),
(59, 'Banjir Rendam Ruas Jalan Desa Maholo', 'terbaru', '2024-05-05', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Maholo Kecamatan Lore Timur Kabupaten Poso pada Minggu (05/05/24) pukul 23.30 WITA. Musim penghujan dan intesitas hujan yang tinggi pada hari Minggu, menyebabkan air Sungai meluap ke pemukiman warga dan mengakibatkan 6 rumah terendam banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 6 unit rumah warga, kebun sayur dan tanaman kakao seluas ±20 Ha, sawah ± 6 Ha dan ruas jalan seluas 1 KM. kebutuhan mnedesak belum diketahui. Saat ini situasi di lokasi kejadian air sudah surut.</p>', '1719279141330-maholo.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719279141330-maholo.png', '2024-06-25 01:32:21', '2024-06-25 01:32:21'),
(60, 'Banjir Terjadi di Desa Wosu Kecamatan Bungku Barat Kabupaten Morowali', 'terbaru', '2024-05-05', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Wosu Kecamatan Bungku Barat Kabupaten Morowali pada Minggu (05/05/24) pukul 23.00 WITA. Intensias hujan yang tinggi menyebabkan meluapnya Sungai yang berada di Desa Wosu hingga ke pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">kejadian ini mengakibatkan 45 KK dan 1 unit masjid terdampak. Tidak ada korban jiwa dan pengungsi akibat kejadian ini. Kebutuhan mendesak saat ini berupa logistic PB. Kondisi saat ini hujan telah berhenti dan air berangsur surut.</p>', '1719279288413-wosu.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719279288413-wosu.png', '2024-06-25 01:34:48', '2024-06-25 01:34:48'),
(61, 'Desa Sampeantaba Kecamatan Wita Ponda Kabupaten Morowali Terendam Banjir', 'terbaru', '2024-05-06', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Sampeantaba Kecamatan Wita Ponda Kabupaten Morowali pada Senin (06/05/24) pukul 06.00 WITA. Hujan dengan intensitas tinggi mengakibatkan peningkatan debit air Sungai sehingga mengakibatkan air meluap menggenangi pekarangan rumah warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 45 KK/180 jiwa terdampak, 45 unit rumah dan 1 gedung Sekolah Dasar terdampak. 1 Kk mengungsi kerumah keluarga. Dibutuhkan logistic PB. Saat ini hujan sudah berhenti dan air berangsur surut.</p>', '1719279409792-sampeantaba.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719279409792-sampeantaba.png', '2024-06-25 01:36:49', '2024-06-25 01:36:49'),
(62, 'Desa Kamarora A Kecamatan Nokilalaki Kabupaten Sigi terendam banjir', 'terbaru', '2024-05-04', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Kamarora A Kecamatan Nokilalaki Kabupaten Sigi pada Sabtu (04/05/24) pukul 01.00 WITA. Hujan dengan intensitas tinggi mengakibatkan meluapnya air Sungai Sopu di Desa Kamarora A hingga terbentuknya aliran sungai baru. Sawah seluas 30 Ha terdampak akibat kejadian ini. Tidak ada pengungsi dan korban jiwa.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Dibutuhkan normalisasi sungai dan pembuatan bronjong. Situasi saat ini hujan telah reda dan banjir telah surut, masyarakat pun melakukan kerja bakti membersihkan sisa banjir.</p>', '1719279661225-kamaroraA.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719279661225-kamaroraA.png', '2024-06-25 01:41:01', '2024-06-25 01:41:01'),
(63, '2 Kelurahan di Kecamatan Palu Barat Terendam Banjir', 'terbaru', '2024-05-04', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Kelurahan Baru dan Kelurahan Ujuna Kecamatan Palu Barat Kota Palu pada Sabtu (04/05/24) pukul 09.00 WITA. Intensitas hujan yang tinggi mengakibatkan tergenangnya air di pemukiman warga di Kelurahan Baru dan Kelurahan Ujuna. Terdampak di Kelurahan Baru sebanyak 130 KK dan 88 unit rumah di RT 02 dan RT 01 RW 01. 50 KK, 250 jiwa serta 50 KK terdampak di RT 03 RW 01. Kelurahan Ujuna terdampak di RT 02 RW 02 sebanyak 20 unit rumah dan 27 KK, RT 03 RW 02 sebanyak 26 Rumah dan 26 KK, RT 01 RW 01 sebanyak 6 unit rumah dan 6 KK terdampak.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi saat ini hujan telah redah namun air masih menggenangi rumah warga</p><p><br></p>', '1719280019537-ujuna.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719280019537-ujuna.png', '2024-06-25 01:46:59', '2024-06-25 01:46:59'),
(64, 'Jembatan Putus Akibat Banjir di Desa Watukilo', 'terbaru', '2024-05-04', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Intensitas hujan yang tinggi pada malam hari mengakibatkan meluapnya Sungai di Desa Watukilo pada Sabtu (04/05/24) pukul 02.00 WITA hingga mengakibatkan terendamnya rumah warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 22 unit rumah terendam, serta fasilitas umum berupa jembatan putus akibat banjir. Dibutuhkan Tindakan normalisasi Sungai. Situasi akhir di lokasi kejadian, hujan sudah reda dan air berangsur surut, namun Masyarakat dihimbau untuk tetap waspada.</p>', '1719280215462-watukilo.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719280215462-watukilo.png', '2024-06-25 01:50:15', '2024-06-25 01:50:15'),
(65, 'Keterbatasan Penerangan Sempat Memicu Kepanikan Warga', 'terbaru', '2024-05-03', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Jumat (03/05/24) pukul 22.00 WITA terjadi hujan dengan intensitas tinggi yang mengakibatkan meluapnya Sungai Desa kabua-Bua hingga berdampak ke pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 98 jiwa terdampak. Fasilitas umum berupa jalan yang menghubungkan Desa kabua-Bua dan Desa Balaan, dan ruas jalan Dusun 3 Lantio juga terdampak.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Selain itu, juga mengakibatkan 4 KK mengungsi Dibutuhkan penanganan berupa pembuatan tanggul Kendala yang ditemukan dilapangan adalah Hujan yang masih mengguyur dan keterbatasan pencahayaan menyebabkan tidak dapat mengambil dokumentasi kejadian secara maksimal</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi saat ini hujan dengan intensitas tinggi masih berlangsung dan air masih menggenang.</p>', '1719280349748-kabuabua.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719280349748-kabuabua.png', '2024-06-25 01:52:29', '2024-06-25 01:52:29'),
(66, 'Dongi-Dongi Diterjang Banjir', 'terbaru', '2024-05-03', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Hujan dengan intensitas tinggi pada Jumat (03/05/24) pukul 22.20 WITA mengakibatkan meningkatnya debit air Sungai Sopu hingga menyebabkan beberapa rumah warga yang terletak di bantaran Sungai terendam banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 6 unit rumah warga terdampak dan 8 KK mengungsi di rumah kerabat. Dibutuhkan Tindakan normalisasi Sungai dan pembuatan tanggul. Situasi akhir di lokasi kejadian, hujan dengan intensitas sedang masih berlangsung namun air berangsur surut.</p>', '1719280504227-dongdong.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719280504227-dongdong.png', '2024-06-25 01:55:04', '2024-06-25 01:55:04'),
(67, 'Desa Balaan Kecamatan Nuhon Terendam Banjir', 'terbaru', '2024-05-03', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Desa Balaan Kecamatan Nuhon Kabupaten Banggai direndam banjir pada Jumat (03/05/24) pukul 21.00 WITA. Hujan dengan intensitas tinggi mengakibatkan meluapnya Sungai Balaan hingga merendam pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Banjir berdampak pada 2 unit rumah warga. Dibutuhkan normalisasi Sungai balaan untuk mengurangi resiko banjir susulan akan terjadi apabila hujan mengakibatkan peningkatan debit air Sungai. Situasi akhir hujan masih berlangsung dan air masih menggenang</p>', '1719280616145-balaan.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719280616145-balaan.png', '2024-06-25 01:56:56', '2024-06-25 01:56:56'),
(68, 'Pendangkalan Sungai Uedele Sebabkan Rumah Warga Terendam', 'terbaru', '2024-05-03', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Uedele Kecamatan Tojo Kabupaten Tojo Una-Una pada Jumat (03/05/24) pukul 04.00 WITA. Hujan dengan intensitas tinggi dan pendangkalan Sungai Uedele mengakibatkan air meluap hingga menggenangi pekarangan rumah warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 50 unit rumah warga terdampak. Tidak terdapat pengungsi dan korban jiwa dalam kejadian ini. Situasi akhir hujan telah berhenti dan air berangsur surut.</p><p class=\"ql-align-justify\"><br></p>', '1719280720239-uedele.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719280720239-uedele.png', '2024-06-25 01:58:40', '2024-06-25 01:58:40'),
(69, 'Sungai Untu Ncayo Meluap Ke Pemukiman Warga', 'terbaru', '2024-05-03', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Kelurahan Sayo Kecamatan Poso Kabupaten Poso pada Jumat (03/05/24) pukul 07.00 WITA. Hujan dengan intensitas tinggi dan meningkatnya debit air Sungai Untu Ncayo mengakibatkan air meluap hingga menggenangi pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 16 KK, 14 unit rumah terendam dan 1 unit Gedung Sekolah TK juga terdampak. Kejadian ini mengakibatkan 16 KK mengungsi. Upaya penanganan kejadian ini yaitu normalisasi Sungai dan pemeliharaan drainase.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi terakhir hujan masih berlangsung dengan intensitas tinggi, air masih menggenang setinggi pinggang orang dewasa. Masyarakat terdampak mengungsi ke rumah warga yang tidak terdampak.</p><p class=\"ql-align-justify\"><br></p>', '1719280866489-sayo.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719280866489-sayo.png', '2024-06-25 02:01:06', '2024-06-25 02:01:06'),
(70, 'Jalan Penghubung Desa Alitupu-Watumaeta Tertutup Material', 'terbaru', '2024-04-29', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Tanah longsor terjadi di Desa Alitupu Kecamatan Lore Utara kabupaten Poso pada Senin (29/04/24) pukul 20.00 WITA. Intensitas hujan yang tinggi mengakibatkan longsor dan menutup akses jalan penghubung antara Desa Alitupu dan Desa Watumaeta.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Jalan penghubung Desa Alitupu dan Desa Watumaeta sepanjang 100meter terdampak. Dibutuhkan alat berat untuk pembersihan. Situasi saat ini hujan telah reda dan warga melakukan gotong royong menggunakan alat sederhana untuk melakukan pembersihan.</p>', '1719281211583-alitupu.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719281211583-alitupu.png', '2024-06-25 02:06:51', '2024-06-25 02:06:51'),
(71, 'Enam Desa Di Dua Kecamatan Kabupaten Parimo Diterjang Banjir', 'terbaru', '2024-04-29', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Tompo, Desa Paria, Desa Sibatang Kecamatan Taopa dan Desa Gio Barat, Desa Pandelalap Desa Tuladenggi Kecamatan Moutong pada Senin (29/04/24) pukul 00.05 WITA. Hujan dengan intensitas tinggi menjadi penyebab banjir kali ini.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Terdampak di Kecamatan Taopa diantaranya Desa Paria sebanyak 125 KK, Desa Sibatang 21 KK. Kecamatan Moutong Desa Gio Barat sebanyak 181 KK, dan 2 unit rumah warga rusak ringan. Desa Pandelalap 38 KK dan Desa Tuladenggi sebanyak 22 KK. Kejadian ini mengakibatkan 5 KK mengungsi.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kebutuhan mendesak berupa logistic sembako dan normalisasi Sungai. Situasi saat ini air berangsur surut dan warga telah membersihkan rumah masing-masing.</p><p><br></p>', '1719281354939-taopa.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719281354939-taopa.png', '2024-06-25 02:09:14', '2024-06-25 02:09:14'),
(72, 'Kelurahan Kayamanya Direndam Banjir', 'terbaru', '2024-04-28', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Kelurahan Kayamanya Kecamatan Poso Kota Kabupaten Poso pada Minggu (28/04/24) pukul 19.57 WITA. Intensitas hujan yang tinggi sejak pukul 16.30 WITA sampai dengan 19.40 WITA mengakibatkan air Sungai meluap ke pemukiman warga yang bermukin disekitar bantaran Sungai.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 9 unit rumah warga. Tidak ada korban jiwa dan pengungsi akibat kejadian ini. Kebutuhan mendesak yang diperlukan berupa pompa air atau alkon.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi saat ini hujan mulai reda dan air genangan banjir perlahan surut. Namun Masyarakat tetap dihimbau waspada apabila terjadi banjir susulan.</p><p><br></p>', '1719281468279-kayamanya.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719281468279-kayamanya.png', '2024-06-25 02:11:08', '2024-06-25 02:11:08'),
(73, 'Desa Jaya Makmur Terendam Banjir', 'terbaru', '2024-04-25', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa jaya Makmur Kecamatan Nuhon Kabupaten Banggai pada kamis (25/04/24) pukul 14.00 WITA. Intensitas hujan yang tinggi sejak pukul 10.00 WITA mengakibatkan banjir pada pukul 14.00 hingga sore hari.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Berdasarkan informasi yang diperoleh dari lapangan, tidak ditemukan adanya korban jiwa dan pengungsi akibat kejadian ini. Dibutuhkan Tindakan normalisasi Sungai sebagai Langkah penanganan. Situasi saat ini hujan mulai reda.</p>', '1719281588910-jamak.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719281588910-jamak.png', '2024-06-25 02:13:08', '2024-06-25 02:13:08'),
(74, 'Musim Penghujan, Desa Amporiwo Terendam Banjir', 'terbaru', '2024-04-22', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Amporiwo Kecamatan Pamona Tenggara Kabupaten Poso pada Senin (22/04/24) pukul 21.00 WITA. Intensitas hujan yang tinggi sejak sore hari pukul 16.00 WITA mengakibatkan meluapnya Sungai yang terletak di Desa Amporiwo hingga ke pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 8 unit rumah warga serta 2 pondasi jembatan tergerus air dan terancam amblas. Dibutuhkan normalisasi Sungai sebagai Upaya penanganan dan pencegahan terjadinya kejadian berulang apabila terjadi hujan.</p>', '1719285463687-ampriwo2.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719285463687-ampriwo2.png', '2024-06-25 03:17:43', '2024-06-25 03:17:43'),
(75, 'Banjir Terjadi di Desa Mamu Kecamatan Pipikoro', 'terbaru', '2024-04-21', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Mamu sekitar pukul 17.30 WITA pada hari Minggu (21/04/24). Intensitas hujan yang tinggi mengakibatkan meluapnya Sungai yang terletak di Desa Mamu hingga ke pemukiman dan Perkebunan warga. Lahan persawahan warga seluas kurang lebih 2 Ha terdampak. Fasilitas umum berupa jembatan penghubung antara Desa Mamu dan Desa Kalamanta hanyut terbawa banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Tidak ada korban jiwa maupun pengungsi akibat kejadian ini. Dibutuhkan perbaikan jembatan penghubung yang rusak. Situasi akhir di lokasi kejadian hujan reda dan air telah surut.</p>', '1719285617787-mamu.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719285617787-mamu.png', '2024-06-25 03:20:17', '2024-06-25 03:20:17'),
(76, 'Desa Doda Kecamatan Lore Tengah Kabupaten Poso Diterjang Banjir', 'terbaru', '2024-04-21', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Doda Kecamatan Lore Tengah Kabupaten Poso pada Rabu, 21 April 2024 pukul 18.30 WITA Intensitas hujan yang tinggi menyebabkan meluapnya Sungai Desa Doda hingga ke pemukiman warga. Sebanyak 2 KK mengungsi ke rumah tetangga. Saat ini dibutuhkan Tindakan normalisasi Sungai sebagai Upaya penanganan dan mencegah kejadian berulang Kembali terjadi apabila terjadi hujan.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi terkini hujan terpantau mulai reda dan air berangsur-angsur surut. Akan tetapi Masyarakat tetap dihimbau untuk waspada kemungkinan terjadinya banjir susulan.</p>', '1719286681877-doda.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719286681877-doda.png', '2024-06-25 03:38:01', '2024-06-25 03:38:01'),
(78, '50 unit terendam di Dusun I Desa Bainaa', 'terbaru', '2024-05-19', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Bainaa Barat Kecamatan Tinombo Kabupaten Parigi Moutong pada Minggu (19/05/24) pukul 05.00 WITA. Hujan dengan intensitas tinggi mengakibatkan terendamnya pemukiman warga Dusun 1 Desa Bainaa.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 50 unit rumah terendam, 50 KK terdampak dan 1 unit jembatan rusak. Dibutuhkan normalisasi sungai. Situasi saat ini banjir berangsur surut dan warga mulai membersihkan rumah masing-masing.</p>', '1719287237460-bainaa.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719287237460-bainaa.png', '2024-06-25 03:47:17', '2024-06-25 03:47:17'),
(79, 'Sungai Salo Tuli Meluap Ke Pemukiman Warga', 'terbaru', '2024-05-16', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Banjir terjadi di Desa Tolisu Kecamatan Toili Kabupaten Banggai Pada Kamis (16/05/24) pukul 22.20 WITA. Hujan dengan intensitas tinggi mengakibatkan meluapnya air Sungai Salo Tuli yang berdampak ke pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Terdampak sebanyak kurang lebih sejumlah 18 unit rumah warga. Dibutuhkan normalisasi sungai, saat ini kondisi air belum surut.</p>', '1719287497645-Saltul.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719287497645-Saltul.png', '2024-06-25 03:51:37', '2024-06-25 03:51:37'),
(82, 'Banjir menerjang Desa Mbuwu Dengan Ketinggian Hingga Setinggi Leher Orang Dewasa', 'terbaru', '2024-06-24', 'Admin Pusdalops', 'Ya', '<p>Banjir terjadi di Dusun I Desa Mbuwu Kecamatan Banawa Selatan Kabupaten Donggala pada Senin (24/06/24) pukul 13.30 WITA. Intensitas hujan yang tinggi dan berlangsung dari pagi hingga saat ini mengakibatkan meluapnya air di Sungai yang ada di Desa Mbuwu Kecamatan Banawa Selatan Kabupaten Donggala.</p><p>Kejadian ini berdampak pada 200 KK.</p><p><br></p><p>Situasi akhir saat ini, menurut informasi dari Sekdes Mbuwu, tinggi air mencapai leher orang dewasa, warga panik dan mengungsi ke tempat yang lebih tinggi.</p>', '1719287571125-mbuwu.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719287571125-mbuwu.jpeg', '2024-06-25 03:52:51', '2024-06-25 03:52:51'),
(83, 'Sungai Samalera Meluap Merendam 2 Desa', 'terbaru', '2024-05-16', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah - Banjir terjadi di Desa Maranda dan Desa Trimulya Kecamatan Poso Pesisir Utara Kabupaten Poso pada Kamis (16/05/24) pukul 19.00 WITA. Hujan dengan intensitas tinggi sejak sore hari mengakibatkan Sungai Samalera meluap hingga ke pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Terdampak di Desa Maranda sebanyak 30 unit rumah, 3 sarana pendidikan, 1 sarana kesahara dan 1 sarana ibadah.Tidak ada pengungsi dan korban jiwa dalam peristiwa ini. Kebutuhan mendesak berupa sembako dan normalisasi sungai. Saat ini ketinggian air terus bertambah.</p>', '1719287645529-maranda.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719287645529-maranda.png', '2024-06-25 03:54:05', '2024-06-25 03:54:05'),
(84, 'Hujan mengakibatkan banjir dan tanah longsor di Desa Tanampulu', 'terbaru', '2024-06-24', 'Admin Pusdalops', 'Ya', '<p>Intensitas hujan yang terjadi sejak pagi hari di Desa Tanampulu Kecamatan Banawa Selatan Kabupaten Donggala pada Senin (24/06/24) pukul 09.00 WITA mengakibatkan meluapnya Sungai Di Desa Tanampulu. Selain itu terjadi pula tana longsor di Jalan satu-satunya sehingga akses jalan tertutup material longsor.&nbsp;</p><p><br></p><p>Kejadian ini berdampak pada sekitar 30 unit rumah warga serta jalan penghubung desa. Dibutuhkan normalisasi sungai dan Alat berat untuk membersihkan material longsor. Situasi akhir hujan mulai reda dan air belum surut</p>', '1719287689950-tanampulu.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719287689950-tanampulu.jpeg', '2024-06-25 03:54:49', '2024-06-25 03:54:49'),
(85, 'Banjir Membuke dipicu Meningkatnya Debir Air Sungai', 'terbaru', '2024-05-16', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Membuke Kecamatan Poso Pesisir Utara Kabupaten Poso pada Kamis (16/05/24) pukul 21.00 WITA. Hukan dengan intensitas tinggi sejak sore hari mengakibatkan debit air yang mengalir pada drainase meningkat dan meluap hingga menggenangi pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Saat ini data terdampak masih dalam proses pendataan. Kebutuhan mendesak saat ini yaitu perbaikan drainase. Kondisi terkini, air masih menggenang.</p>', '1719287787718-membuke.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719287787718-membuke.png', '2024-06-25 03:56:27', '2024-06-25 03:56:27'),
(86, 'Jembatan Penghubung Desa Singura dan Toribulu Terputus Diterjang Banjir', 'terbaru', '2024-06-24', 'Admin Pusdalops', 'Ya', '<p>Intensitas hujan yang tinggi mengakibatkan meningkatnya debit air pada Sungai Desa Singura Kecamatan Toribulu Kabupaten Parigi Moutong pada Minggu (23/06/24) pukul 04.38 WITA sehingga mengakibatkan putusnya Jembatan Penghubung Desa Sigura dan Desa Toribulu.</p><p><br></p><p>Saat ini aparat desa dan warga bergotong royong membuat jembatan darurat dari batang pohon kelapa. Saat ini jembatan darurat sudah bisa dilalui oleh kendaraan roda 2 dan 4.</p>', '1719287801398-singura.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719287801398-singura.jpeg', '2024-06-25 03:56:41', '2024-06-25 03:56:41'),
(88, 'Jalan Penghubung Desa Watatu dan Mbuwu Terputus Akibat Tanah Longsor', 'terbaru', '2024-06-24', 'Admin Pusdalops', 'Ya', '<p>Intensitas hujan yang tinggi sejak pagi hingga saat ini mengakibatkan meluapnya sungai yang berada di Desa Watatu Kecamatan Banawa Selatan Kabupaten Donggala pada Senin (24/06/24) pukul 13.30 WITA.&nbsp;</p><p><br></p><p>Kejadian ini mengakibatkan putusnya jalan penghubung Desa Watatu dan Desa Mbuwu akibat Longsor.&nbsp;</p><p><br></p><p>Situasi akhir hujan telah reda, namun di Dusun IV air meluap setinggi pinggang orang dewasa. Saat ini aparat desa sedang mengusahakan alat berat untuk proses membuka jalan yang tertimbun longsor</p>', '1719287905095-watatu.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719287905095-watatu.jpeg', '2024-06-25 03:58:25', '2024-06-25 03:58:25'),
(89, 'Empat Desa Di Kecamatan Ongka Malino Terendam Banjir', 'terbaru', '2024-05-28', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Ongka, Desa Malino, Kayu Jati dan Desa Santigi Kecamatan Ongka Malino Kabupaten Parigi Moutong pada Selasa (28/05/24) pukul 16.00 WITA. Hujan dengan intensitas tinggi mengakibatkan meluapnya Sungai Malino Hingga ke Pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Terdampak di Desa Ongka sebanyak 118 KK yang terdiri dari 9 bayi 27 balita 79 anak dan 31 lansia di Dusun I 2 bayi 6 balita 10 anak dan 6 lansia di Dusun II 1 balita 16 anak dan 1 lansia di Dusun III 1 bayi 6 anak dan 3 lansia di Dusun V Terdampak di Desa Santigi sebanyak 9 KK Sementara itu data terdampak di Desa Malino dan Kayu Jati masih dalam pendataan</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kebutuhan mendesak yaitu normalisasi sungai dan logistik PB. Saat ini hujan telah reda, namun air masih menggenang.</p>', '1719287948000-ongka.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719287948000-ongka.png', '2024-06-25 03:59:08', '2024-06-25 03:59:08'),
(90, 'Tanah Longsor Mengakibatkan Dua Unit Rumah Rusak Berat', 'terbaru', '2024-06-11', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Kejadian Tanah Longsor terjadi di Kelurahan Kilongan, Kecamatan Luwuk Utara Kabupaten Banggai pada Selasa (11/06/24) pukul 01.00 WITA. Intensitas hujan yang tinggi yang terjadi beberapa hari belakangan mengakibatkan tanah longsor yang mengakibatkan 2 unit rumah rusak berat.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini tidak menimbulkan korban jiwa. Namun warga yang rumahnya terdampak membutuhkan tenda pengungsian untuk bermukim sementara setelah rusaknya kediaman mereka. Situasi akhir di Lokasi kejadian, hujan telah berhenti namun Masyarakat sekitar masih tetap waspada apabila terjadinya longsor susulan.</p>', '1719288132883-kilongan.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719288132883-kilongan.png', '2024-06-25 04:02:12', '2024-06-25 04:02:12'),
(91, 'Banjir terjadi di 3 Desa Kecamatan Tomini Kabupaten Parigi Moutong ', 'terbaru', '2024-06-24', 'Admin Pusdalops', 'Ya', '<p>Intensitas hujan yang tinggi mengakibatkan meluapnya air Sungai yang berada di Desa Tomini Barat, Desa Tomini Utara dan Desa Tomini pada Senin (24/06/24) pukul 10.00 WITA</p><p><br></p><p>Dari data sementara di Desa Tomini Utara 2 KK Terdampak dan 1 Unit rumah rusak berat serrta untuk kebutuhan mendesak masih dalam pendataan. Situasi saat ini hujan telah reda, air belum surut</p>', '1719288320853-ttt.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719288320853-ttt.jpeg', '2024-06-25 04:05:20', '2024-06-25 04:05:20'),
(92, 'Jalan Poros Nyaris Putus ', 'terbaru', '2024-06-10', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Kejadian Banjir Desa Padang Kec. Balantak Kab. Banggai, senin ( 10/06/24 ) pukul 07:00 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Intensitas curah hujan yang tinggi sejak malam hari mengakibatkan peningkatan debit air di sungai Desa Padang sehingga berdampak ke pemukiman warga dan jalan poros penghubung desa. Dari data terdampak yang didapati 5 unit rumah warga dengan 15 KK terendam banjir serta jalan poros ikut terkikis akibat banjir yang terjadi.</p>', '1719288379279-padang.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719288379279-padang.png', '2024-06-25 04:06:19', '2024-06-25 04:06:19'),
(93, 'Banjir terjadi di Desa Toliba Kecamatan Tojo Barat Kabupaten Tojo Una-Una ', 'terbaru', '2024-06-24', 'Admin Pusdalops', 'Ya', '<p>Intensitas hujan yang tinggi, mengakibatkan meluapnya air di sungai yang ada di Desa Toliba Kecamatan Tojo Barat Kabupaten Tojo Una-Una pada Senin (24/06/24) pukul 16.30 WITA. Sebanyak 12 unit rumah terendam dan 12 KK terdampak kejadian ini.</p><p><br></p><p>TRC BPBD Touna meminta bantuan dari Pusdalops BPBD Sulteng untuk melakukan pendataan dan kaji cepat lapangan. Saat ini hujan dengan intensitas sedang masih mengguyur dan air masih menggenangi rumah warga.</p>', '1719288526040-toliba.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719288526040-toliba.jpeg', '2024-06-25 04:07:49', '2024-06-25 04:08:46'),
(94, 'Sungai Mentawa dan Torono Meluap Menggenangi Pemukiman Warga', 'terbaru', '2024-06-10', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Banjir terjadi di Desa Sausu Torono Kecamatan Sausu kabupaten Parigi Moutong pada Senin (10/06/24) pukul 07.00 WITA. Hujan dengan intensitas tinggi mengakibatkan Sungai Mentawa dan Sungai Torono meluap hingga menggenangi pemukiman warga. Selain pemukiman warga, banjir juga mengakibatkan pembelajaran di SDN Kecil Sausu Torono diliburkan sementara akibat Gedung sekolah tergenang.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 12 KK terdampak, 12 unit rumah warga terendam serta 1 gedung sekolah terdampak. Tindakan yang dibutuhkan sebagai Upaya penanganan yaitu normalisasi Sungai dan pemasangan bronjong. Situasi akhir di Lokasi kejadian hujan masih berlangsung dengan intensitas rendah, air menggenang dengan ketinggian sekitar 50 cm.</p>', '1719288620890-sautor.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719288620890-sautor.jpeg', '2024-06-25 04:10:20', '2024-06-25 04:10:20'),
(95, 'Banjir Rendam Pemukiman Warga Kelurahan Pagimana Kabupaten Banggai', 'terbaru', '2024-06-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Kejadian Banjir Kelurahan Pagimana Kec. Pagimana Kab. Banggai, jumat ( 07/06/24 ) pukul 12.00 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Dikarenakan Intensitas Curah Hujan yang tinggi sejak pukul 11.00 Wita – 12.30 Wita menyebabkan meluapnya sungai dan drainase yang berada di Kelurahan Pagimana hingga berdampak ke pemukiman warga. Dari data yang didapati 6 unit rumah warga, 1 kantor kelurahan Pagimana serta cakupan wilayah terdampak berkisar ±1 Ha.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Adapun Langkah penanganan yang harus dilakukan ialah normalisasi sungai guna untuk mencegah terjadinya banjir Kembali.</p><p class=\"ql-align-justify\"><br></p>', '1719288881451-pgmn.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719288881451-pgmn.jpeg', '2024-06-25 04:14:41', '2024-06-25 04:14:41'),
(96, 'Banjir Rendam Pemukiman warga di Dua Desa Kabupaten Sigi', 'terbaru', '2024-06-06', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Kejadian Banjir Desa Bangga dan Desa Walatana Kec. Dolo Selatan Kab.Sigi pada kamis ( 06/06/24 ) pukul 18:06 WITA. Intensitas Curah Hujan yang tinggi menyebabkan meluapnya Sungai yang berada di sekitaran Desa Bangga dan Desa Walatana hingga berdampak ke pemukiman warga. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Dari kejadian ini 7 rumah dengan 21 jiwa serta akses jalan poros terdampak di Desa Bangga dan 11 KK dengan 23 jiwa di Desa Walatana. Adapun kebuthan mendesak yang harus terpenuhi ialah penanganan normalisasi Sungai, peralatan kebersihan untuk membersihkan sisa-sisa banjir serta logistic penanggulangan bencana. </p>', '1719289546513-walatana.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719289546513-walatana.png', '2024-06-25 04:25:46', '2024-06-25 04:25:46'),
(97, '7 KK Terendam Banjir Di Toli-Toli', 'terbaru', '2024-06-04', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Kejadian Banjir di Desa Batuilo Kec. Ogodeide Kab. Tolitoli pada selasa ( 04/06/24 ) pukul 16:30 WITA. Intensitas Curah Hujan yang tinggi menyebabkan meluapnya Sungai yang berada di Desa Batuilo hingga ke pemukiman warga. Adapun dampak dari kejadian ini yaitu 5 KK di Dusun 1 dan 2 KK di Dusun 2 serta Langkah penanganan yang harus dilakukan ialah dengan melakuan normalisasi Sungai.</p><p class=\"ql-align-justify\"><br></p>', '1719289743307-ogdei.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719289743307-ogdei.jpeg', '2024-06-25 04:29:03', '2024-06-25 04:29:03'),
(98, 'Banjir Terjang Dua Kelurahan Di Banggai Laut', 'terbaru', '2024-06-03', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir kembali terjadi di Desa Lampa, Kelurahan Lompio dan Kelurahan Dodung, Kecamatan Banggai, Kabupaten Banggai Laut pada senin ( 03/06/24 ) pukul 12:00 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Banjir yang terjadi akibat dari curah hujan dari pukul 12.00 hingga sore hari, sehingga merendam beberapa Kelurahan di Kecamatan Banggai sebagian rumah yang rendah dari jalur jalan terendam banjir. Adapun 30 KK terdampak serta 5 KK terpaksa harus mengungsi ke pihak keluarga.</p>', '1719291108211-balut.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719291108211-balut.jpeg', '2024-06-25 04:51:48', '2024-06-25 04:51:48'),
(99, 'Desa Eeya Terendam Banjir', 'terbaru', '2024-06-04', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Kejadian banjir terjadi di Desa Eeya Kecamatan Palasa Barat Kabupaten Parigi Moutong, selasa ( 04/06/24 ) pukul 05:05 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Dikarenakan hujan dengan intensitas yang tinggi mengakibatkan peningkatan debit air di Sungai Desa Eeya sehingga meluap ke pemukiman warga dan membawa beberapa material batu serta batang pohon.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Akibat dari kejadian ini 14 KK terdampak serta membutuhkan bantuan berupa logistic penanggulangan bencana. Adapun Langkah penanganan yang harus dilakukan yaitu membersihkan sisa-sisa material menggunakan alat berat.</p><p class=\"ql-align-justify\"><br></p>', '1719291354895-eeya.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719291354895-eeya.jpeg', '2024-06-25 04:55:54', '2024-06-25 04:55:54'),
(100, 'Sungai Kajulangko Meluap', 'terbaru', '2024-06-03', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Banjir terjadi di Desa Pusungi pada Senin (03/06/24) pukul 19.45 WITA disebabkan oleh intensitas hujan yang tinggi mengakibatkan peningkatan debit air Sungai Kajulangko hingga meluap ke pemukiman warga. Terdampak akibat kejadian ini yakni jalan poros Desa Pusungi terendam banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Tidak ada pengungsi dan korban jiwa akibat kejadian ini. Situasi akhir air masih menggenang dan hujan masih mengguyur dengan intensitas tinggi. Masyarakat dihimbau untuk waspada apabila terjadi hujan dengan intensitas tinggi dengan waktu yang lama.</p><p class=\"ql-align-justify\"><br></p>', '1719291579054-pusungi.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719291579054-pusungi.png', '2024-06-25 04:59:39', '2024-06-25 04:59:39'),
(101, 'Sungai Meko Mengakibatkan Pemukiman terendam', 'terbaru', '2024-06-04', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Intensitas Hujan yang tinggi mengakibatkan peningkatan debit air Sungai Meko yang meluap hingga ke pemukiman warga pada Selasa (04/06/24) pukul 04.00 WITA. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 172 KK, 172 unit rumah, 4 unit sarana ibadah, 6 unit Gedung perkantoran serta 2 unit Gedung sekolah. Dibutuhkan paket sembako serta Tindakan normalisasi Sungai. Situasi akhir air masih menggenang namun hujan telah reda</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\"><br></p>', '1719292230253-meko.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719292230253-meko.jpeg', '2024-06-25 05:10:30', '2024-06-25 05:10:30'),
(102, 'Banjir dan tanah Longsor Melanda 3 Kecamatan Di Banggai Laut', 'terbaru', '2024-06-13', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Intensitas Hujan yang tinggi mengakibatkan peningkatan debit air Sungai Meko yang meluap hingga ke pemukiman warga pada Selasa (04/06/24) pukul 04.00 WITA. </p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 172 KK, 172 unit rumah, 4 unit sarana ibadah, 6 unit Gedung perkantoran serta 2 unit Gedung sekolah. Dibutuhkan paket sembako serta Tindakan normalisasi Sungai. Situasi akhir air masih menggenang namun hujan telah reda</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian Banjir dan Tanah Longsor Kec. Banggai, Kec. Banggai Selatan, Kec. Banggai Tengah Kab. Banggai Laut, Kamis ( 13/06/24) pukul 05.00 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Intensitas Curah Hujan yang tinggi sejak malam hari mengakibatkan peningkatan debit air dengan ketinggian air 50-80 cm sehingga berdampak ke pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Adapun dari data terdampak sementara yang terhimpun saat ini yaitu Desa Lompio, Desa Lambako, Desa Kokini, Desa Lampa, Desa Bentean, dan Desa Monsongan. Serta situasi saat ini dilokasi kejadian hujan masih mengguyur dengan intensitas sedang dan air masih menggenangi pemukiman warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Hingga berita ini diterbitkan BPBD setempat sedang melakukan pendataan di Lokasi terdampak banjir dan tanah longsor.</p><p class=\"ql-align-justify\"><br></p>', '1719292446042-balut2.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719292446042-balut2.jpeg', '2024-06-25 05:14:06', '2024-06-25 05:14:06'),
(103, 'Dua Desa Di Banawa Selatan Diterjang Banjir', 'terbaru', '2024-04-13', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Kejadian Banjir Desa Lumbutarombo dan Desa Salumpaku Kec. Banawa Selatan Kab. Donggala, Kamis (13/06/24 ) pukul 15.30 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Intensitas Curah Hujan yang tinggi sejak Sore hari pada Kecamatan Banawa Selatan mengakibatkan peningkatan debit air sehingga yang menggenangi pemukiman warga, sementara itu dari data terdampak diketahui ±15 KK dan 1 lapangan terendam banjir di Desa Lumbutarombo, serta 5 unit rumah di dusun 1 dan 2 unit rumah di dusun 2 Desa Salumpaku juga ikut terendam banjir.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Adapun kebutuhan yang harus terpenuhi dari kejadian ini yaitu melakukan normalisasi sungai, pemasangan beronjong pada tebing sungai serta logistik penanggulangan bencana.</p><p class=\"ql-align-justify\"><br></p>', '1719292989824-lumbutarombo.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719292989824-lumbutarombo.jpeg', '2024-06-25 05:23:09', '2024-06-25 05:23:09'),
(104, 'Jalan Trans Sulawesi Terendam Banjir Di Desa Tuntung', 'terbaru', '2024-06-13', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Intensitas hujan yang tinggi mengakibatkan limpahan material dari gunung terbawa ke bahu jalan sehingga merusak jaringan sumber air bersih warga dusun I wilayah Bahu Desa Tuntung, Kecamatan Bunta Kabupaten Banggai pada Sabtu (15/06/24) pukul 15.00 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 9 KK, 9 unit rumah, tergenangnya jalan trans serta rusaknya jaringan sumber air bersih warga. Tidak ada pengungsi dan korban jiwa akibat kejadian ini. Dibutuhkan segera perbaikan jaringan pipa air bersih warga.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi akhir hujan telah reda, namun tumpukan material dari pegunungan masih berserakan di bahu jalan.</p><p class=\"ql-align-justify\"><br></p>', '1719293412353-tuntung.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719293412353-tuntung.png', '2024-06-25 05:30:12', '2024-06-25 05:30:12'),
(106, 'Kejadian Banjir Desa Saloya Kecamatan Sindue Kabupaten Donggala', 'terbaru', '2024-06-13', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Sulawesi Tengah – Intensitas Hujan yang tinggi sejak sore hari mengakibatkan peningkatan debit air Sungai yang ada di Desa Saloya Sehingga meluap ke pemukiman warga Desa Saloya Kecamatan Sindue Kabupaten Donggala pada Kamis (13/06/24) pukul 17.30 WITA.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 60 unit rumah dan 1 Gedung TK Saloya, serta sekitar 10 KK mengungsi kerumah kerabat atau tetangga. Dibutuhkan Tindakan normalisasi Sungai dan kebutuhan sembako. Situasi saat ini hujan telah reda dan air masih menggenang di area pemukiman</p><p class=\"ql-align-justify\"><br></p>', '1719293968467-saloya.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719293968467-saloya.jpeg', '2024-06-25 05:39:28', '2024-06-25 05:39:28'),
(107, '51 Unit Rumah Terendam Banjir di Desa Lalong ', 'terbaru', '2024-06-25', 'Admin Pusdalops', 'Ya', '<p>hujan dengan intensitas sedang hingga lebat disertai petir dan angin kencang telah melanda Desa Lalong Kec. Tinangkung Utara. Menyebabkan Drainase tidak dapat menempung debit air sehingga menggenangi pemukiman warga dengan ketinggian ± 30 cm</p><p><br></p><p>Dari data assessment sementara didapati ±51 unit rumah warga terdampak, luas area terdapak genanngan air&nbsp;±2.27 Ha. serta kebutuhan mendesak yang harus dilakukan ialah pembuatan platdeker berjumal 2 unit serta drainase sepanjang 400 meter.</p>', '1719326372391-lalong.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719326372391-lalong.jpeg', '2024-06-25 14:39:32', '2024-06-25 14:39:32'),
(108, 'Respon Cepat Bencana, BPBD SULTENG Turunkan Alat Berat Di Desa Dampal.', 'favorit', '2024-06-26', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Sulawesi Tengah – Kejadian banjir yang terjadi di Desa Dampal Kecamatan Sirenja Kabupaten Donggala pada Minggu (23/06/24) pukul 05.00 WITA silam yang dipicu oleh meluapnya Sungai Hingga merendam pemukiman warga dan berdampak pada 224 KK yang tersebar di Dusun 1,2 dan 3.</p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">	Merespon kejadian ini, Pemerintah Provinsi Sulawesi Tengah yang di Koordinir Langsung Oleh Bapak Wakil Gubernur Ma\'mun Amir bersama BPBD Povinsi Sulawesi Tengah turun langsung ke Lokasi kejadian untuk menindaklanjuti permintaan pengerjaan Sungai.</p><p class=\"ql-align-justify\">	</p><p class=\"ql-align-justify\">	Dalam hal ini, BPBD Provinsi Sulawesi Tengah menurunkan sebuah alat berat untuk melakukan penanganan. Dengan ini diharapkan agar pada prosesnya dapat berjalan dengan lancar serta dapat mengurangi dampak bagi Masyarakat sekitar.</p><p><br></p>', '1719382363863-alber.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719382363863-alber.jpeg', '2024-06-26 06:12:43', '2024-06-26 06:12:43'),
(109, 'Jalan Poros Palu-Bangga Terendam Lumpur', 'terbaru', '2024-07-01', 'admin pusdalops', 'Ya', '<p>Banjir terjadi di Desa Bobo dan Desa Pesaku Kecamatan Dolo Barat Kabupaten Sigi pada Senin (01/07/24) pukul 18.30 WITA. Intensitas hujan yang tinggi mengakibatkan Sungai di Desa Bobo dan Pesaku meluap ke pemikiman warga hingga jalan poros Palu-Bangga.</p><p><br></p><p>Kejadian ini mengakibatkan jalan poros terdampak lumpur, 4 rumah dan 4 KK terdampak akibat kejadian ini. Saat ini hujan mulai reda.</p>', '1719893243240-WhatsAppImage2024-07-01at21.29.45.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719893243240-WhatsAppImage2024-07-01at21.29.45.jpeg', '2024-07-02 04:07:23', '2024-07-02 04:07:23'),
(110, 'Akses Jalan Terputus, Warga Dusun V Simbulangan Terisolir', 'terbaru', '2024-07-03', 'Admin Pusdalops', 'Ya', '<p>Banjir terjadi di Dusun V Simbulangan Desa Toribulu Kecamatan Toribulu Kabupaten Parigi Moutong pada Rabu (03/07/24) pukul 11.00 WITA. Hujan yang berlangsung sejak pagi hari mengakibatkan meningkatnya debit air Sungai hingga meluap ke pemukiman warga. Selain itu, akses jalan menuju Dusun V Simbulangan pun tidak dapat dilalui mengakibatkan warga terisolir.</p><p><br></p><p>Kejadian ini mengakibatkan 12 unit rumah dan 13 KK terdampak. 13 KK tersebut diketahui saat ini mengungsi ke rumah kerabat.</p><p><br></p><p>Saat ini dibutuhkan pembuatan jembatan penyebrangan. Situasi akhir hujan telah reda namun banjir masih menggenang</p>', '1720004992416-IMG-20240703-WA0075.jpg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720004992416-IMG-20240703-WA0075.jpg', '2024-07-03 11:09:52', '2024-07-03 11:09:52'),
(112, 'Banjir Terjang 4 Kecamatan di Kabupaten Banggai laut', 'terbaru', '2024-07-04', 'admin Pusdalops', 'Ya', '<p><strong>B</strong>anjir terjadi di Kecamatan Banggai Selatan, Banggai Tengah, Banggai dan Banggai Utara Kabupaten Banggai Laut pada Kamis (04/07/24) pukul 07.00 WITA. Hujan dengan Intensitas Tinggi mengakibatkan debit air sungai meningkat dan meluap hinhha ke pemukiman warga .&nbsp;</p><p><br></p><p>Kejadian ini mengakibatkan 53 KK terdampak di Desa Bentean, 68 KK terdampak di Desa Bayumpayan, 74 KK di Desa Tanobonununga, 97 KK di Desa Kokini, 30 KK di Desa Pasir Putih. sementara itu terdampak di Desa Tolokibit, Adean, Mominit, Lambako, Bone Baru dan Paisumosoni masih dalam pendataan.</p><p><br></p><p>Kebutuhan mendesak berupa Logistik PB, penanganan berupa normalisasi sungai serta pembuatan drainase. situasi akhir saat ini, hujan masih berlangsung dengan intensitas tinggi. ketinggian air yang menggenangi pemukiman warga sekitar 30 hingga 50 CM. Warga terdampak mengungsi ke rumah kerabat.</p>', '1720073946951-balut2.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720073946951-balut2.jpeg', '2024-07-04 06:19:06', '2024-07-04 06:19:06'),
(113, '2 Kendaraan Roda Empat Terdampak Tanah Longsor', 'terbaru', '2024-07-07', 'Admin Pusdalops', 'Ya', '<p>Sulawesi Tengah- Tanah Longsor terjadi di Dusun 3 Pangas Desa Lambori Kecamatan Palasa Kabupaten Parigi Moutong pada Minggu (07/07/24) pukul 06.00 WITA. Hujan dengan intensitas tinggi sejak malam hari mengakibatkan tanah longsor di Dusun 3 Pangas Desa Lambori.</p><p><br></p><p>Kejadian ini mengakibatkan 2 unit mobil terdampak, serta ruas jalan trans Sulawesi tertimbun material longsor.&nbsp;</p><p><br></p><p>Dibutuhkan alat berat untuk pembersihan material longsor. Situasi saat ini hujan masih berlangsung dan akses jalan masih tertutup sehingga tidak dapat dilalui kendaraan.</p>', '1720324282101-a6f02f36-fdce-439e-9dd0-dd10dd10a040.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720324282101-a6f02f36-fdce-439e-9dd0-dd10dd10a040.jpeg', '2024-07-07 03:51:22', '2024-07-07 03:51:22'),
(114, '4 Kelurahan di Kecamatan Palu Selatan dan Palu Timur terendam Banjir', 'terbaru', '2024-07-07', 'Admin Pusdalops', 'Ya', '<p>Sulawesi Tengah, Banjir terjadi di Kelurahan Tatura Utara, Tatura Selatan Kecamatan Palu Selatan dan Kelurahan Besusu Timur, Besusu Selatan Kecamatan Palu Timu pada Minggu (07/07/24) pukul 22.00 WITA.&nbsp;</p><p><br></p><p>Hujan dengan intensitas tinggi yang berlangsung sejak sore hari menyebabkan meningkatnya debit air di beberapa titik Sungai Palu hingga meluap dan merendam pemukiman warga di bantaran sungai.</p><p><br></p><p>Terdampak di Kelurahan Besusu Timur sebanyak 8 unit rumah terendam serta 20 unit rumah terendam di Kelurahan Tatura Utara.&nbsp;</p><p><br></p><p>Kebutuhan yaitu Alkon dan alat pembersih. Situasi akhir hujan telah reda namun banjir masih menggenangi beberapa rumah warga.</p>', '1720388821831-7a549e2f-fe36-4d6e-b925-00545cb84102.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720388821831-7a549e2f-fe36-4d6e-b925-00545cb84102.jpeg', '2024-07-07 21:47:01', '2024-07-08 06:13:34'),
(115, 'Luapan Air Sungai dan Air Laut Pasang Merendam Pemukiman Warga', 'terbaru', '2024-07-08', 'Admin Pusdalops', 'Ya', '<p>Banjir terjadi di Desa Sampeantaba Kecamatan Witaponda Kabupaten Morowali pada Senin (08/07/24) pukul 09.00 WITA. Intensitas hujan yang tinggi menyebabkan volume air Sungai Lantula meluap disertai pasang air laut hingga ke pemukiman warga setinggi 50 cm.&nbsp;</p><p><br></p><p>Sebanyak 27 unit rumah warga terendam dan 35 KK 210 terdampak, terdapat 6 jiwa lansia, 2 bayi dan 3 balita. Sebanyak 2 KK yang terdiri dari 10 jiwa diketahui saat ini mengungsi di kantor desa.</p><p><br></p><p>Dibutuhkan Tindakan normalisasi Sungai. Situasi akhir saat ini hujan telah reda dan banjir masih menggenangi pemukiman warga.</p>', '1720425385945-c1f514bb-cb79-407e-a3e2-8083773ae921.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720425385945-c1f514bb-cb79-407e-a3e2-8083773ae921.jpeg', '2024-07-08 07:56:25', '2024-07-08 07:56:25'),
(116, '160 Unit Rumah Terendam Di Desa Rusa Kencana', 'terbaru', '2024-07-08', 'Admin Pusdalops', 'Ya', '<p>Sulawesi Tengah - Banjir terjadi di Desa Rusa Kencana Kecamatan Toili Kabupaten Banggai pada Senin (08/07/24) pukul 10.00 WITA. Intensitas hujan yang tinggi serta air laut yg pasang mengakibatkan banjir yang menggenangi pemukiman warga dengan ketinggian sekitar 100 cm.</p><p><br></p><p>Kejadian ini menyebabkan 160 unit rumah terendam serta 170 KK yang terdiri dari 400 jiwa terdampak. Tidak ada pengungsi dan korban jiwa akibat kejadian ini.</p><p><br></p><p>Terkait kebutuhan mendesak masih dalam proses pendataan. Situasi saat ini hujan telah reda namun air masih menggenangi pemukiman penduduk.</p>', '1720430888787-828f38bf-9486-49a2-a63b-2ff40741476e.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720430888787-828f38bf-9486-49a2-a63b-2ff40741476e.jpeg', '2024-07-08 09:28:08', '2024-07-08 09:28:08'),
(117, '296 Jiwa Terisolir di Dusun Tumpu Jaya 1 Desa Sinorang Kecamatan Batui Selatan Kabupaten Banggai', 'terbaru', '2024-07-10', 'admin pusdalops', 'Ya', '<p>Sulawesi Tengah - Banjir terjadi di Dusun Tumpu Jaya 1 Desa Sinorang Kecamatan Batui Selatan Kabupaten Banggai pada Rabu (10/07/24) pukul 05.00 WITA. Hujan dengan intensitas tinggi mengakibatkan Sungai Sinorang meluap hingga menggenangi pemukiman warga.</p><p><br></p><p>Terdampak sebanyak 98 KK yang terdiri dari 296 jiwa terisolir serta 1 unit rumah warga terendam. 1 KK mengungsi ke rumah kerabat. Tidak ada korban jiwa akibat kejadian ini. Dibutuhkan segera Tindakan normalisasi Sungai.</p><p><br></p><p>Situasi akhir saat ini hujan masih berlangsung dengan intensitas tinggi, air masih menggenang dengan ketinggian sekitar 40cm.</p>', '1720575495521-tumpujaya1.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720575495521-tumpujaya1.png', '2024-07-10 01:38:15', '2024-07-10 01:38:15'),
(118, '500 meter Jalan Desa Tidak Dapat Dilalui Kendaraan di Desa Ondo-Ondolu 1 Kecamatan Batui Kabupaten Banggai', 'terbaru', '2024-07-10', 'admin pusdalops', 'Ya', '<p>Banjir terjadi di Desa Ondo-Ondolu 1 Kecamatan Batui Kabupaten Banggai pada Rabu (10/07/24) pukul 05.00 WITA. Hujan dengan intensitas tinggi mengakibatkan Sungai yang berada di Desa Ondo-Ondolu 1 meluap hingga menggenangi jalan desa dan Perkebunan.</p><p><br></p><p>Kejadian ini mengakibatkan sekitar 500 meter jalan desa tidak dapat dilalui oleh kendaraan roda empat maupun kendaraan roda dua, serta seluas 5 Ha lahan Perkebunan. Dibutuhkan Tindakan normalisasi Sungai.</p><p><br></p><p>Situasi saat ini, hujan masih berlangsung dengan intensitas tinggi, air masih menggenang setinggi 50 cm. Masyarakat melakukan gotong royong untuk membuat jembatan penyebrangan di Dusun 1.</p>', '1720575546071-WhatsAppImage2024-07-10at09.02.59.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720575546071-WhatsAppImage2024-07-10at09.02.59.jpeg', '2024-07-10 01:39:06', '2024-07-10 01:39:06'),
(119, 'Sungai di Desa Sukamaju Meluap, 30 KK serta Fasilitas Umum terdampak', 'terbaru', '2024-07-10', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Sukamaju Kecamatan Batui Selatan Kabupaten Banggai pada Rabu (10/07/24) pukul 08.00 WITA. Hujan dengan intensitas tinggi mengakibatkan Sungai di Desa Sukamaju meluap hingga menggenangi pemukiman warga. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 33 KK serta 4 fasilitas umum terdampak. Fasilitas umum terdampak diantaranya Gedung sekolah TK/Paud, Puskesmas Pembantu, Kantor Desa serta Gedung Sekolah Dasar. Dibutuhkan Tindakan normalisasi Sungai.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi saat ini, hujan masih berlangsung dengan intensitas tinggi dan air masih menggenang dengan ketinggian sekitar 50 cm</p>', 'sukamaju.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/sukamaju.jpeg', '2024-07-10 03:02:03', '2024-07-10 03:02:03'),
(120, 'Tanggul Jebol di Desa Argakencana menyebabkan banjir di Tiga Desa Kecamatan Moilong', 'terbaru', '2024-07-10', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Karanganyar dan Desa Toili Kecamatan Moilong Kabupaten Banggai pada Rabu (10/07/24) pukul 09.00 WITA. Hujan dengan intensitas tinggi mengakibatkan jebolnya bendung/tanggul yang berada di Desa Argakencana Kecamatan Moilong hingga menyebabkan air Sungai meluap ke Dusun Kayuku Desa Toili, Desa Karanganyar dan Desa Saluan Kecamatan Moilong Kabupaten Banggai.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Terdampak di Desa Toili dan Saluan sedang dalam pendataan. Sementara itu di Desa Karanganyar sebanyak 50 unit rumah terendam banjir. Kebutuhan mendesak berupa normalisasi Sungai. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi akhir saat ini, hujan masih berlangsung, air masih menggenangi pemukiman warga serta jembatan yang ada di Dusun Kayuku Desa Toili masih belum bisa di akses kendaraan.</p><p><br></p>', '1720582012658-WhatsAppImage2024-07-10at10.43.01.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720582012658-WhatsAppImage2024-07-10at10.43.01.jpeg', '2024-07-10 03:26:52', '2024-07-10 03:26:52'),
(121, '20 Hektar Persawahan Serta Belasan Bangunan Terdampak Banjir ', 'terbaru', '2024-07-10', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Kayowa Kecamatan Batui Kabupaten Banggai pada Rabu (10/07/2024) pukul 04.00 WITA. Hujan dengan intensitas tinggi mengakibatkan Sungai di Desa Kayowa meluap hingga menggenangi pemukiman warga dan lahan pertanian</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 10 KK, 1 fasilitas umum, 11 bangunan serta 20 hektar sawah terdampak banjir. Kebutuhan mendesak berupa normalisasi Sungai. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Situasi saat ini hujan masih berlangsung dengan intensitas tinggi dan air masih menggenangi pemukiman warga.</p><p><br></p>', '1720583684440-WhatsAppImage2024-07-10at11.40.27.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1720583684440-WhatsAppImage2024-07-10at11.40.27.jpeg', '2024-07-10 03:54:44', '2024-07-10 03:54:44'),
(122, 'Akses Jalan Trans Terendam, Lalulintas Terhambat', 'terbaru', '2024-07-22', 'Admin pusdalops', 'Ya', '<p>Banjir terjadi di Desa Tolai Kecamatan Torue Kabupaten Parigi Moutong pada Senin (22/07/24) pukul 17.30 WITA. Hujan dengan intensitas tinggi mengakibatkan meluapnya Sungai Wetua hingga ke drainase di jalan Trans Sulawesi.&nbsp;</p><p><br></p><p>Kejadian ini berdampak pada jalan Trans Sulawesi, Dusun 8 Desa Tolai, irigasi Dusun 6 Buanasari serta lahan persawahan.&nbsp;</p><p><br></p><p>Kebutuhan mendesak berupa pemeliharaan drainase dan normalisasi sungai. Situasi akhir air masih menggenang, hujan masih berlangsung dan akses lalu lintas terhambat</p>', '1721696735795-Tolai.JPG', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1721696735795-Tolai.JPG', '2024-07-23 01:05:35', '2024-07-23 01:05:35'),
(123, 'Luapan Dua Sungai Mengakibatkan Pemukiman Warga Terendam Banjir', 'terbaru', '2024-07-08', 'Admin Pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Tanasumpu Kecamatan mamosalato Kabupaten Morowali Utara pada Rabu (07/08/24) pukul 05.00 WITA. Intensitas hujan yang tinggi mengakibatkan meningkatnya debit air di Sungai Tanasumpu dan Sungai Cendrawasih sehingga meluap menggenangi pemukiman warga. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 300 KK/1.500 jiwa. Tidak terdapat pengungsi dan korban jiwa akibat kejadian ini. Dibutuhkan normalisasi Sungai dan pemeliharaan tanggul. Situasi saat ini hujan masih berlangung dengan intensitas ringan hingga sedang.</p>', '1722997358764-tnsp.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1722997358764-tnsp.jpeg', '2024-08-07 02:22:38', '2024-08-07 02:22:38'),
(124, 'Menanggapi Potensi Gempa Megathrust, BPBD Sulteng melakukan Rakor Mitigasi Bencana', 'rekomendasi', '2024-08-20', 'Admin Dalops', 'Ya', '<p>Menanggapi Potensi Gempa Megathrust, BPBD Sulteng melakukan Rakor Mitigasi Bencana</p><p><br></p><p>Palu - saat ini indonesia sedang dilanda isu ancaman bencana Gempa Bumi yang berskala besar yaitu, Gempa Megathrust.&nbsp;</p><p><br></p><p>Menanggapi hal tersebut, Badan Penanggulangan Bencana Daerah (BPBD) Provinsi Sulawesi Tengah melakukan Rapat Koordinasi terkait Mitigasi Bencana terhadap Potensi Gempa Megathrust.</p><p><br></p><p>Dalam kegiatan tersebut, dihadiri langsung oleh Kepala Pelaksana BPBD Prov. Sulteng beserta seluruh Kepala Bidang BPBD Prov. Sulteng, perwakilan dari BMKG Stasiun Geofisika Palu dan Organisasi Perangkat Daerah Lintas Sektor.</p><p><br></p><p>BMKG Stasiun Geofisikan Palu, yang dihadiri langsung oleh Bapak Sujabar, S.T , selaku Kepala BMKG Stasiun Geofisika Palu menjelaskan bahwa, Berdasarkan informasi tersebut, Gempabumi merupakan salah satu kejadian yang tidak dapat diprediksi waktu dan tempat kejadiannya, dan Sulawesi Tengah merupakan wilayah yang sering diguncang oleh gempa bumi. olehnya setiap lembaga yang berwenang melakukan tugasnya untuk melakukan pemantauan, memberikan informasi bukan untuk memprediksi terjadinya suatu bencana, melainkan untuk meminimalisir dampak yang terjadi akibat bencana.&nbsp;</p><p><br></p><p>Dalam hal ini juga, Kepala Pelaksana BPBD Prov. Sulteng juga menghimbau kepada seluruh masyarakat diharapkan untuk tidak panik dalam menghadapi situasi ini, bekali diri dengan pengetahuan mitigasi bencana dan berdoa memohon perlindungan Yang Maha Kuasa.</p>', '1724151050521-405e67cc-cb62-47da-9d4f-5ddb81a2ecd0.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1724151050521-405e67cc-cb62-47da-9d4f-5ddb81a2ecd0.jpeg', '2024-08-20 09:51:41', '2024-08-20 10:50:50'),
(125, '2 Jembatan Penghubung Terputus Di Kecamatan Banawa Selatan', 'terbaru', '2024-08-22', 'Admin Pusdalops', 'Ya', '<p>Banjir terjadi di Desa Lalombi, Kecamatan Banawa Selatan Kabupaten Donggala Pada Kamis (22/08/24) pukul 20.30 WITA. Hujan dengan intensitas tinggi mengakibatkan meluapnya Sungsi di Desa Lalombi sehingga merendam pemukiman warga dan jembatan penghubung antara Dusun 2 dan Dusun 4 putus, kemudian jembatan antar Desa Lalombi dan Desa Salusumpu.</p><p><br></p><p>Kejadian ini berdampak pada 8 unit rumah dan 2 unit jembatan. Kebutuhan mendesak berupa normalisasi sungai dan perbaikan jembatan. Situasi akhir air telah surut dan tidak ada pengungsi serta korban jiwa akibat kejadian ini</p>', '1724378514558-WhatsApp Image 2024-08-22 at 22.39.55.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1724378514558-WhatsApp Image 2024-08-22 at 22.39.55.jpeg', '2024-08-23 02:01:54', '2024-08-23 02:01:54'),
(126, 'Tanggul Sungai jebol Menyebabkan Air Menggenangi Pemukiman Warga ', 'terbaru', '2024-08-22', 'Admin Pusdalops', 'Ya', '<p>Tanggul Sungai jebol Menyebabkan Air Menggenangi Pemukiman Warga&nbsp;</p><p><br></p><p>Banjir terjadi di Desa Balinggi Jati Kecamatan Balinggi Kabupaten Parigi Moutong pada Kamis (22/08/34) pukul 21.50 WITA hujsn dengan intensitas tinggi menyebabkan tanggul rusak sehingga meluap dan merendam pemukiman warga.&nbsp;</p><p><br></p><p>Terdampak akibat kejadian ini sebanyak kurang lebih 80 KK. Dibutuhkan perbaikan tanggul yang rusak. Situasi saat ini air belum surut namun hujan mulai reda.</p>', '1724378633426-blg.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1724378633426-blg.png', '2024-08-23 02:03:53', '2024-08-23 02:03:53'),
(127, 'Banjir dan Tanah Longsor Menerjang Akses Jalan Kebun Kopi', 'terbaru', '2024-08-22', 'Admin Pusdalops', 'Ya', '<p>Banjir dan tanah longsor terjadi di Desa Toboli Kecamatan Toboli Barat Kabupaten Parigi Moutong pada Kamis (22/08/24) pukul 23.00 WITA. Hujan dengan intensitas tinggi yang membawa material tanah, batuan, kerikil dan pohon tumbang, serta beberapa bagian ruas jalan longsor mengakibatkan terhambatnya akses jalan Trans Sulawesi (Kebun Kopi). </p><p><br></p><p>kejadian ini mengakibatkan akses lalu lintas terhambat, dibutuhkan segera pembersihan material longsor yang menutupi badan jalan, agar lalu lintas kembali lancar. Situasi saat ini hujan telah reda.</p><p><br></p>', '1724379115856-kpk.png', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1724379115856-kpk.png', '2024-08-23 02:11:55', '2024-08-23 02:11:55'),
(128, 'Tinjauan lokasi Tambang Galian C pasca bencana alam Banjir di Kelurahan Watusampu', 'rekomendasi', '2024-09-10', 'Admin Pusdalops', 'Ya', '<p>Tinjauan Oleh Instansi Terkait Pasca Bencana Banjir dan Tanah Longsor di Watusampu</p><p><br></p><p>Palu - Selasa (10/09/24) Tim Gabungan OPD Sulawesi Tengah yang terdiri dari BPBD Provinsi Sulteng, BPBD Kota Palu, BPSDM, Dinas Sosial, Dinas Lingkungan Hidup, Dinas Kesehatan, DInas PErhubungan, Balai Jalan, Pengusaha Tambang Galian C juga bersama warga setempat.</p><p><br></p><p>&nbsp;Tim gabungan melakukan Rapat koordinasi di kantor camat ulujadi serta dilanjutkan dengan peninjauan langsung di lokasi tambang tentang mitigasi bencana serta dampaknya bagi kesehatan masyarakat.</p><p><br></p><p>Menurut Sumarno selaku kepala dinas Perhubungan akses jalan trans di daerah pertambangan mengalami perlambatan arus lalu lintas, kerusakan jalan serta meningkatnya kecelakaan.&nbsp;</p><p><br></p><p>Dalam kesempatan ini juga dibahas terkait pemeliharaan debu yang beterbangan di jalan raya, pembuatan drainase, dan pembersihan plat deker yang tersumbat.</p>', '1726195986101-ba259072-6ed4-458e-aaeb-e36e73324750.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1726195986101-ba259072-6ed4-458e-aaeb-e36e73324750.jpeg', '2024-09-13 02:53:06', '2024-09-13 02:53:06'),
(129, 'Intensitas Hujan Yang Tinggi Mengakibatkan Meluapnya Sungai Hingga Menggenangi Beberapa Rumah', 'terbaru', '2024-10-10', 'Admin Pusdalops', 'Ya', '<p>Banjir terjadi di Kelurahan Bahontula Kecamatan Petasia Kabupaten Morowali Utara pada Kamis (10/10/24) pukul 23.16 WITA</p><p><br></p><p>Hujan yang terjadi sejak pukul 21.40 dengan intensitas tinggi mengakibatkan meluapnya sungsi hingga menggenangi beberapa rumah warga. Terdampak akibat kejadian ini yakni 9 KK dan 45 Jiwa serta 1 KK mengungsi.</p><p><br></p><p>Kebutuhan mendesak berupa normalisasi sungai dan pemasangan bronjong. Situasi akhir air berangsur surut.</p>', '1728613595668-WhatsApp Image 2024-10-11 at 01.16.40.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1728613595668-WhatsApp Image 2024-10-11 at 01.16.40.jpeg', '2024-10-11 02:26:35', '2024-10-11 02:26:35'),
(130, 'Kalaksa BPBD Provinsi Sulawesi Tengah Mewakili Gubernur Sulawesi Tengah Memberikan Sambutan Sekaligus Membuka Kegiatan Literasi Iklim dan Kualitas Udara', 'terbaru', '2024-10-12', 'Admin Pusdalops', 'Ya', '<p>Sulawesi Tengah - Workshop dan Literasi Iklim dan Kualitas Udara yang diselenggarakan oleh Stasiun Pemantauan Atmosfer Global Lore Lindu Bariri. Kegiatan ini mengusung tema \"Peran Generasi Muda dalam Aksi Nyata Perubahan Iklim Sulawesi Tengah 2024\" yang berlangsung di Aula Pogombo pada Sabtu (12/10/24) pukul 08.00-16.00 WITA.&nbsp;</p><p><br></p><p>Kegiatan ini dihadiri oleh unsur Forum Koordinasi Pimpinan Daerah, Para Staff Ahli Gubernur, Kepala Badan Meteorologi, Klimatologi dan Geofisika Stasiun Pemantau Atmosfer Global Lore Lindu Bariri, Narasumber, para Mitra Kerja dan Stakeholder terkait dan peserta workshop yang merupakan pelajar dari beberapa Sekolah Menengah Atas yang ada di Kota Palu.</p><p><br></p><p>Pada kesempatan kali ini, Kalaksa BPBD Provinsi Sulawesi Tengah mewakili Gubernur Sulawesi Tengah untuk memberikan sambutan sekaligus membuka kegiatan.</p><p><br></p><p>Dalam sambutannya, Dr. Ir. H. Akris Fattah Yunus menuturkan, \"Apresiasi yang setinggi-tingginya kepada Badan Meteorologi, Klimatologi dan Geofisika Stasiun Pemantau Atmosfer Global Lore Lindu Bariri yang telah berinisiatif menyelenggarakan kegiatan ini\".</p><p><br></p><p>Literasi iklim dan kualitas udara untuk generasi muda tidak hanya berfokus pada peningkatan pengetahuan mengenai iklim dan kualitas udara tetapi juga bertujuan untuk membekali generasi muda dengan informasi yang relevan agar mereka dapat menjadi agen perubahan dalam menjaga lingkungan.</p><p><br></p><p>\"Kita semua menyadari bahwa perubahan iklim dan penurunan kualitas udara merupakan tantangan serius yang harus dihadapi, olehnya, generasi muda memiliki peran yang sangat penting dalam menghadapi tantangan ke depan, sehingga melalui literasi ini, kita dapat memahami dampak perubahan iklim serta langkah-langkah yang dapat diambil untuk meminimalisir dampak\", tambahnya.</p><p><br></p><p>Mengedukasi masyarakat tentang pentingnya menjaga kualitas udara dan lingkungan juga dapat memicu kesadaran yang lebih besar dan mendorong perubahan positif. Hal ini merupakan tanggung jawab kita semua untuk meminimalisir dampak perubahan iklim serta mewujudkan aksi nyata demi masa depan bumi yang lebih sehat untuk generasi yang akan datang.</p>', '1728713665736-IMG_0376.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1728713665736-IMG_0376.jpeg', '2024-10-12 06:14:25', '2024-10-12 06:19:37'),
(131, 'Bidang Kedaruratan dan Logistik BPBD Provinsi Sulawesi Tengah Menyelenggarakan Bimbingan Teknis Terhadap Personil TRC', 'favorit', '2024-02-11', 'Admin Pusdalops', 'Ya', '<p>Sulawesi Tengah - Seorang personil TRC harus dibekali oleh keahlian yang menunjang kinerja di lapangan, berdasarkan pertimbangan tersebut, Kepala Bidang Kedaruratan Dan Logistik BPBD Provinsi Sulawesi Tengah, Andy Sembiring, S.STP, M.Si menyelenggarakan bimbingan teknis dalam rangka peningkatan kapasitas personil Tim Reaksi Cepat Penanggulangan Bencana. Kegiatan yang di gelar di Aula Taipa Beach Resort sejak 18 - 21 November 2024 menghadirkan beberapa narasumber yang berasal dari Pusat Pendidikan dan Pelatihan (Pusdiklat) BNPB dan Pusdalops BNPB.</p><p><br></p><p>Materi yang disajikan adalah materi pokok yang sifatnya penting yang harus dikuasai oleh setiap personil TRC. Selain menerima materi, pada kesempatan kali ini juga diikuti dengan implementasi materi tersebut dalam bentuk simulasi secara langsung. Selain materi pembelajaran, melalui pelatihan ini, para personil juga dilatih untuk mempererat kerjasama, bekerja dalam tim, saling menghargai, saling merangkul dalam mencapai tujuan bersama.</p><p><br></p><p>Setelah pelatihan ini, diharapkan kemampuan tim dalam menemukan solusi dalam masalah, solidaritas dan kemampuan teknis semakin meningkat, sehingga terwujudnya insan yang unggul dan bertanggung jawab dalam menjalankan tugas melayani masyarakat.</p>', '1732501784495-bimtek.jpeg', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1732501784495-bimtek.jpeg', '2024-11-25 02:26:53', '2024-11-25 02:29:47'),
(132, '-	Banjir menerjang Desa Ganda-Ganda Menyebabkan Kerusakan dan Korban jiwa', 'terbaru', '2025-01-03', 'Admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir bandang terjadi pada Jumat (03/01/25) pada pukul 17.45 WITA. Hujan dengan intensitas tinggi sejak pukul 11.30 WITA mengakibatkan banjir bandang yang menimbulkan kerusakan site (camp) milik PT. Surya Armindo Perkasa. </p><p class=\"ql-align-justify\">	Kejadian ini mengakibatkan 1 orang korban jiwa dan 3 orang mengalami luka ringan.</p><p class=\"ql-align-justify\">Situasi akhir hujan masih mengguyur dan banjir masih menggenang.</p><p class=\"ql-align-justify\"><br></p><p><br></p>', '1747891553335-WhatsApp Image 2025-05-22 at 10.20.11.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747891553335-WhatsApp Image 2025-05-22 at 10.20.11.jpeg', '2025-05-22 05:25:53', '2025-05-22 05:25:53'),
(133, '-	Banjir Merendam Desa Pinamula', 'terbaru', '2025-01-15', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Rabu (15/01/25) pukul 07.30 WITA. Intensitas hujan yang tinggi mengakibatkan meluapnya Sungai Pinamula di Kecamatan Momonu dengan ketinggian sekitar lutut orang dewasa dan debit air terus meningkat.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 47 KK, 42 unit rumah dan 1 unit Gedung sekolah.</p><p class=\"ql-align-justify\">	Kebutuhan mendesak berupa Logistic PB dan pembuatan tanggul sepanjang 200 Meter. Situasi akhir luapan air masih belum surut, ketinggian air terkini sekitar 10-15 cm. saat ini Masyarakat membersihkan genangan air dalam rumah dengan alat seadanya.</p>', '1747891664214-WhatsApp Image 2025-05-22 at 13.21.37.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747891664214-WhatsApp Image 2025-05-22 at 13.21.37.jpeg', '2025-05-22 05:27:44', '2025-05-22 05:27:44'),
(134, '-	Curah Hujan Yang Tinggi Memicu Banjir di Desa Batusuya', 'terbaru', '2025-01-15', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi di Desa Batusuya, Kecamatan Sindue Tambusambora Kabupaten Donggala pada Rabu (15/01/25) pukul 14.00 WITA. Intensitas hujan yang tinggi mengakibatkan meluapnya air Sungai yang ada di Desa Batusuya hingga berdampak ke lingkungan Masyarakat dan merusak fasilitas desa.</p><p class=\"ql-align-justify\">	Kejadian ini berdampak pada 16 KK, 16 unit rumah warga dan Kantor Desa Batusuya. Situasi akhir banjir telah surut, hujan mulai reda.</p><p class=\"ql-align-justify\"><br></p>', '1747891720314-WhatsApp Image 2025-05-22 at 13.21.37 (1).jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747891720314-WhatsApp Image 2025-05-22 at 13.21.37 (1).jpeg', '2025-05-22 05:28:40', '2025-05-22 05:28:40'),
(135, '-	Lingkungan Tanjung Kelurahan Buol Kecamatan Biau Terendam Banjir ', 'terbaru', '2025-01-17', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Jumat (17/01/25) pukul 07.30 WITA. Intensitas hujan yang tinggi sejak kemarin mengakibatkan banjir dan naiknya air laut dengan ketinggian kurang lebih se lutut orang dewasa.</p><p class=\"ql-align-justify\">	Kejadian ini mengakibatkan 40 KK dan 40 unit rumah terdampak. Kebutuhan mendesak beruoa Logistik PB, mesin pompa air (alkon) serta pembuatan drainase sepanjang 50 meter. Situasi akhir saat ini luapan air belum surut. Ketinggian air sekitar 10-15 cm. Masyarakat melakukan gotong royong untuk membuat drainase darurat sepanjang 50 meter.</p><p class=\"ql-align-justify\"><br></p>', '1747891781945-WhatsApp Image 2025-05-22 at 13.21.37 (2).jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747891781945-WhatsApp Image 2025-05-22 at 13.21.37 (2).jpeg', '2025-05-22 05:29:41', '2025-05-22 05:29:41'),
(136, '-	Banjir Merendam 2 Desa Di Kecamatan Sigi Biromaru ', 'terbaru', '2025-01-19', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Minggu (19/01/25) pukul 19.10 WITA. Intensitas hujan sedang hingga tinggi megakbatkan meluapnya air melalui drainase yang ada di Desa Sidera dan Jono Oge hingga ke pemukiman warga.</p><p class=\"ql-align-justify\">	Terdampak di Desa Sidera sebanyak 5 unit rumah, dan 4 unit rumah di Desa Jono Oge. </p><p class=\"ql-align-justify\">Kebutuhan mendesak masih dalam pendataan. Situasi akhir banjir telah surut dan hujan mulai reda. </p><p class=\"ql-align-justify\"><br></p>', '1747891839199-WhatsApp Image 2025-05-22 at 13.21.38.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747891839199-WhatsApp Image 2025-05-22 at 13.21.38.jpeg', '2025-05-22 05:30:39', '2025-05-22 05:30:39'),
(137, '-	Desa Tuva Kecamatan Gumbasa Kabupaten Sigi Terendam Banjir ', 'terbaru', '2025-01-20', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Senin (20/01/25) pukul 16.00 WITA. Intensitas hujan yang tinggi mengakibatkan meluapnya air Sungai ke pemukiman warga. Intensitas terdampak akibat kejadian ini diantaranya 1 unit Bangunan Sekolah dan 1 Unit Puskesmas Pembantu.</p><p class=\"ql-align-justify\">	Kebutuhan mendesak berupa alat berat guna melakukan normalisasi Sungai. Situasi akhir saat ini jalan poros seudah dapat dilalui oleh kendaraan.&nbsp;</p><p class=\"ql-align-justify\"><br></p>', '1747891951701-WhatsApp Image 2025-05-22 at 13.21.38 (1).jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747891951701-WhatsApp Image 2025-05-22 at 13.21.38 (1).jpeg', '2025-05-22 05:32:31', '2025-05-22 05:32:31'),
(138, '', '', '2025-01-23', 'admin pusdalops', '', '<p class=\"ql-align-justify\">Tanah longsor terjadi pada Kamis (23/01/25) pukul 10.30 WITA. Hujan yang terjadi pada rabu sore hingga malam hari memicu terjadinya longsor pada jalan poros penghubung Poso-Tentena dan juga berdampak pada beberapa unit rumah warga.</p><p class=\"ql-align-justify\">Kejadian inimengakibatkan 5 unit rumah terdampak dan jalan poros Poso-Tentena tidak dapat di lalui. Kebutuhan mendesak saat ini perbaikan akses jalan. Situasi akhir jalan poros belum dapat dilalui kendaraan. Alternatif jalan lainnya melalui jalan desa.</p><p class=\"ql-align-justify\"><br></p>', '1747892513788-WhatsApp Image 2025-05-22 at 13.35.59.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747892513788-WhatsApp Image 2025-05-22 at 13.35.59.jpeg', '2025-05-22 05:37:29', '2025-05-22 05:41:53'),
(139, '-	Banjir Desa Tandayondo Kecamatan Soyo Jaya Kabupaten Morowali Utara', 'terbaru', '2025-01-24', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Jumat (24/01/25) pukul 03.00 WITA tepatnya di RT 03 – RT 04 Desa Tandayondo. Hujan dengan intensitas tinggi sejak sore hingga malam hari mengakibatkan Sungai Sumara meluap menggenangi pemukiman rumah warga.</p><p class=\"ql-align-justify\">	Terdampak akibat kejadian ini diantara 23 KK/215 jiwa, lansia sebanyak 15 jiwa dan 23 rumah terdampak. Kebutuhan mendesak berupa penambahan tanggul. Situasi akhir kondisi luapan air berangsur surut.</p><p class=\"ql-align-justify\"><br></p>', '1747892455911-WhatsApp Image 2025-05-22 at 13.21.39 (2).jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747892455911-WhatsApp Image 2025-05-22 at 13.21.39 (2).jpeg', '2025-05-22 05:40:55', '2025-05-22 05:40:55'),
(140, '-	Gempa Bumi Mengguncang Desa Salua Kecamatan Kulawi Kabupaten Sigi ', 'terbaru', '2025-01-26', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Gempa bumi terjadi pada Minggu (26/01/25) pukul 12.36 WITA. Pada hari Minggu, Wilayah Kulawi diguncang gempa bumi tektonik dengan kekuatan magnitudo 4,5 berlokasi di Darat dengan kedalaman 5 KM.</p><p class=\"ql-align-justify\">Tercatat terjadi dua kali gempa susulan. </p><p class=\"ql-align-justify\">	Dampak gempa bumi getaran terasa nyata dalam rumah namun belum ada informasi terkait data spesifik terkait dampak kejadian. Situasi akhir Masyarakat dihimbau untuk tetap tenang dan tidak terpengaruh oleh isu yang tidak bisa dipertanggungjawabkan kebenarannya.</p><p><br></p>', '1747892631616-WhatsApp Image 2025-05-22 at 13.21.40.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747892631616-WhatsApp Image 2025-05-22 at 13.21.40.jpeg', '2025-05-22 05:43:51', '2025-05-22 05:43:51'),
(141, '-	Banjir merendam 3 desa di kecamatan Galang Kabupaten Toli-Toli', 'terbaru', '2025-01-26', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi Desa Ginunggung, Kalangkangan dan Lalos Kecamatan Galang Kabupaten Toli-Toli pada Minggu (26/01/25) pukul 17.00 WITA. Terjadi hujan dengan intensitas tinggi mengakibatkan banjir di beberapa titik yang tersebar di tiga desa tersebut. </p><p class=\"ql-align-justify\">	Saat ini data terkait kebutuhan mendesak masih dalam proses pendataan. Situasi akhir hujan masih mengguyur tiga desa tersebut, namun banjir berangsur surut.</p><p><br></p>', '1747892754921-WhatsApp Image 2025-05-22 at 13.21.40 (1).jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747892754921-WhatsApp Image 2025-05-22 at 13.21.40 (1).jpeg', '2025-05-22 05:45:54', '2025-05-22 05:45:54'),
(142, '-	Banjir merendam 2 Kelurahan di Kecamatan Baolan Toli-Toli', 'terbaru', '2025-01-26', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi di Kelurahan Baru dan Kelurahan Panasakan Baolan Toli-Toli pada Minggu, 26 Januari 2025 pukul 18.30 WITA. Terjadi hujan sejak pukul 16.30 WITA. </p><p class=\"ql-align-justify\">	Mengakibatkan banjir di beberapa titik di kedua kelurahan tersebut.</p><p class=\"ql-align-justify\">Kebutuhan mendesak masih dalam pendataan. Situasi akhir banjir berangsur surut.</p><p><br></p>', '1747892820291-WhatsApp Image 2025-05-22 at 13.21.40 (2).jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747892820291-WhatsApp Image 2025-05-22 at 13.21.40 (2).jpeg', '2025-05-22 05:47:00', '2025-05-22 05:47:00'),
(143, '-	Banjir Desa Pasir Putih Kecamatan Pamona Selatan Kabupaten Poso ', 'terbaru', '2025-01-28', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Selasa (28/01/25) pukul 02.00 WITA. Intensitas hujan yang tinggi memicu meluapnya Sungai Kodina, luapan air memasuki pemukiman pada pukul 02.00 WITA.</p><p class=\"ql-align-justify\">	Kejadian ini berdampak pada 220 KK di Dusun 3, kompleks perumahan warga, rumah ibadah, Perkebunan warga dan jalan trans Sulawesi. Kebutuhan mendesak berupa normalisasi Sungai Kodina dan pembuatan talud di 3 titik. Situasi akhir banjir masih menggenangi pemukman dan aktivitas Masyarakat masih terhambat.</p><p><br></p>', '1747892897047-WhatsApp Image 2025-05-22 at 13.21.41.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747892897047-WhatsApp Image 2025-05-22 at 13.21.41.jpeg', '2025-05-22 05:48:17', '2025-05-22 05:48:17'),
(144, '-	Gempa Bumi terjadi di Desa Salumpengut Kecamatan Moutong Kabupaten Parigi Moutung ', 'terbaru', '2025-01-28', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Gempa Bumi terjadi pada Selasa (28/01/25) pukul 21.53 WITA gempa bumi tektonik terjadi dengan kekuatan magnitude 6.1 dengna kedalaman 76 km. Dampak gempa bumi getaran terasa nyata dalam rumah namun belum ada informasi terkait data spesifik terkait dampak kejadian. Situasi akhir Masyarakat dihimbau untuk tetap tenang dan tidak terpengaruh oleh isu yang tidak bisa dipertanggungjawabkan kebenarannya.</p><p><br></p>', '1747892966152-WhatsApp Image 2025-05-22 at 13.21.41 (1).jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747892966152-WhatsApp Image 2025-05-22 at 13.21.41 (1).jpeg', '2025-05-22 05:49:26', '2025-05-22 05:49:26'),
(145, '-	Banjir terjadi di Desa Balau Kecamatan Tiloan Kabupaten Buol ', 'terbaru', '2025-01-30', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Kamis (30/01/25) pukul 01.27 WITA. Intensitas hujan sedang hingga lebat mengakibatkan banjir meluap ke pemukiman warga dengan ketinggian sekitar 1 meter. </p><p class=\"ql-align-justify\">	Terdampak akibat kejadian ini sebanyak 212 KK dengan kebutuhan mendesak berupa Logistik PB. Situasi akhir air belum surut, ketinggian mencapai 1 Meter, mendirikan tenda darurat desa.</p><p><br></p>', '1747893052176-WhatsApp Image 2025-05-22 at 13.21.42.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747893052176-WhatsApp Image 2025-05-22 at 13.21.42.jpeg', '2025-05-22 05:50:52', '2025-05-22 05:50:52'),
(146, '-	Banjir Desa Ogomatanang Kecamatan Lampasio Kabupaten Toli-Toli', 'terbaru', '2025-02-01', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Hujan sejak siang hingga sore mengakibatkan banjir di Desa Ogomatanang yang disebabkan saluran drainase yang sudah dangkal.</p><p class=\"ql-align-justify\">	Terdampak akibat kejadian ini sebanyak 10 unit rumah warga, sekitar 105 Ha Perkebunan warga. Hujan sudah reda dan banjir mulai surut.</p><p class=\"ql-align-justify\"><br></p><p><br></p>', '1747893201988-WhatsApp Image 2025-05-22 at 13.52.31.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747893201988-WhatsApp Image 2025-05-22 at 13.52.31.jpeg', '2025-05-22 05:53:21', '2025-05-22 05:53:21'),
(147, '-	Banjir dan Tanah Longsor menggenangi 2 Desa Di Kecamatan Basidondo ', '', '2025-02-01', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir dan Tanah Longsor terjadi pada Sabtu (01/02/25) pukul 17.30 WITA, hujan dengan intensitas tinggi sejak sore hari mengakibatkan banjir dan tanah longsor di beberapa titik wilayah Kecamatan Basidondo.</p><p class=\"ql-align-justify\">Terdampak pada kejadian ini diantara nya, di Desa Kayulompa sebanyak 2 unit rumah rusak ringan, 1 unit jembatan putus, 1 unit tiang Listrik ambruk.</p><p class=\"ql-align-justify\"><br></p>', '1747980591187-WhatsApp Image 2025-02-02 at 08.49.05.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747980591187-WhatsApp Image 2025-02-02 at 08.49.05.jpeg', '2025-05-23 06:06:29', '2025-05-23 06:09:51'),
(148, '-	Tanah Longsor Melanda Kelurahan Leok 1 ', 'terbaru', '2025-02-01', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Tanah longsor terjadi di Desa Lingkungan Damar Kelurahan Leok 1 Kecamatan Biau Kabupaten Buol pada Sabtu (01/02/25) pukul 18.10 WITA. Intensitas hujan yang tinggi sejak siang hingga menjelang malam hari mengakibatkan tanah longsor yang menimbun badan jalan sepanjang 50 meter, sehingga akses jalan belum dapat dilalui sementara. </p><p class=\"ql-align-justify\">Dibutuhkan kendaraan alat berat untuk melakukan pembersihan material yahg menutupi badan jalan. Situasi ahkir Masyarakat bergotong royong untuk memindahkan material longsor dengan alat seadanya.</p><p class=\"ql-align-justify\"><br></p><p><br></p>', '1747980637687-WhatsApp Image 2025-02-01 at 22.57.07.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747980637687-WhatsApp Image 2025-02-01 at 22.57.07.jpeg', '2025-05-23 06:10:37', '2025-05-23 06:10:37'),
(149, '-	Banjir Merendam Desa Silondou Kecamatan Basidondo Kabupaten Toli-Toli ', '', '2025-02-01', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Sabtu (01/02/25) pukul 18.00 WITA. Intensitas hujan yang tinggi mengakibatkan meluapnya air ke pemukiman penduduk, usaha pertanian, sekolah SMP, SD Paud Kantor Desa dan Rumah Ibadah.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 350 KK, kebutuhan mendesak berupa sembako. Situasi akhir air mulai surut.</p>', '1747980770046-WhatsApp Image 2025-02-02 at 08.49.05 (1).jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747980770046-WhatsApp Image 2025-02-02 at 08.49.05 (1).jpeg', '2025-05-23 06:12:04', '2025-05-23 06:12:50'),
(150, '-	Banjir Rob menerjang Desa Sausu Peore ', 'terbaru', '2025-02-01', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir rob terjadi pada Sabtu (01/02/25) pukul 16.00 WITA. Air laut pasang mengakibatkan jebolnya tangggul hingga meluapnya air ke pemukiman warga. </p><p class=\"ql-align-justify\">	Kejadian ini berdampak pada 100 KK dan 100 unit rumah warga. Kebutuhan endesak berupa perbaikan tanggul. 	Situasi akhir air telah surut namun Masyarakat mash waspada apabila air Kembali naik pada sore hari.</p><p class=\"ql-align-justify\"><br></p><p><br></p>', '1747980834624-WhatsApp Image 2025-02-02 at 10.33.38.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747980834624-WhatsApp Image 2025-02-02 at 10.33.38.jpeg', '2025-05-23 06:13:54', '2025-05-23 06:13:54'),
(151, '-	Tanah Longsor Menimbun Jalan Trans Desa Lunguto', 'terbaru', '2025-02-01', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Tanah longsor terjadi di Desa Lunguto Kecamatan Paleleh Barat Kabupaten Buol pada Sabtu (01/02/25) pukul 16.10 WITA. Intensitas hujan sedang hingga tinggi mengakibatkan tanah longsor menimbun jalan trans dan beberapa rumah warga sehingga akses jalan belum dapat dilalui. </p><p class=\"ql-align-justify\">	Kejadian ini menyebankan sekitar 75 meter jalan trans terdampak, 3 unit rumah rusak berat, 3 KK 9 Jiwa, 1 unit rumah ibadah ikut terdampak serta 9 unit rumah terancam. </p><p class=\"ql-align-justify\">	Kebutuhan mendesak berupa logistic PB dan kendaraan alat berat. Situasi akhir pemerintah setempat bekerjasama dengan BPJN melakukan penanganan material longsor dengan alat berat, arus lalu lintas saat ini menggunakan jalur alternatif yang hanya bisa dilalui kendaraan kecil hingga sedang.</p><p><br></p>', '1747980893601-WhatsApp Image 2025-02-02 at 12.52.22.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747980893601-WhatsApp Image 2025-02-02 at 12.52.22.jpeg', '2025-05-23 06:14:53', '2025-05-23 06:14:53'),
(152, 'Angin Kencang Melanda Desa Bongganan ', 'terbaru', '2025-02-06', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Angin kencang terjadi di Desa Bongganan Kecamatan Tinangkung Kabupaten Banggai Kepulauan pada Kamis (06/02/25) pukul 01.20 WITA. Cuaca buruk disertai angin kencang berdampak ke pemukiman warga.</p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 1 unit rumah warga roboh dan rusak berat. 1 Kk terdampak terdiri dari 2 jiwa diantaranya bapak Lispan dan Ibu Difa. Kebutuhan mendesak berupa logistic PB. Situasi akhir rumah tersebut masih roboh dan jatuh ke air.</p>', '1747980988514-WhatsApp Image 2025-02-06 at 10.17.59.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747980988514-WhatsApp Image 2025-02-06 at 10.17.59.jpeg', '2025-05-23 06:16:28', '2025-05-23 06:16:28'),
(153, '-	Angin Kencang Mengakibatkan Pohon Tumbang di Kabonena', 'terbaru', '2025-02-06', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Hujan deras disertai angin kencang terjadi pada pukul 22.45 WITA di Kelurahahn Kabonena Kecamatan Ulujadi Kota Palu (kamis, 07/02/25). Mengakibatkan robohnya sebuah pohon di Jl. Lasoso yang membuat akses jalan sempat terhambat.</p><p class=\"ql-align-justify\">Situasi akhir Masyarakat bersinergi dengan DLH Kota Palu melakukan pembersihan material pohon tumbang yang melintang dijalan, sehingga akses jalan dapat Kembali lancar.&nbsp;</p><p class=\"ql-align-justify\"><br></p>', '1747981055583-WhatsApp Image 2025-02-08 at 00.37.01.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747981055583-WhatsApp Image 2025-02-08 at 00.37.01.jpeg', '2025-05-23 06:17:35', '2025-05-23 06:17:35'),
(154, '-	Angin Kencang Terjadi di Desa Tinakin Laut Kecamatan Banggai Kabupaten Banggai Laut', 'terbaru', '2025-02-08', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Hujan deras disertai angin kencang terjadi pada pukul 23.45 Wita (Sabtu, 08/02/25) yang berdampak pada satu unit rumah rusak berat.</p><p class=\"ql-align-justify\">Langkah yang dilaksanakan ialah tim BPBD dan Damkar Banggai Laut mengevakuasi korban yang terdampak.</p><p class=\"ql-align-justify\"><br></p>', '1747981119418-WhatsApp Image 2025-02-09 at 09.16.59.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747981119418-WhatsApp Image 2025-02-09 at 09.16.59.jpeg', '2025-05-23 06:18:39', '2025-05-23 06:18:39'),
(155, '-	Angin Kencang Menerjang 2 Kecamatan di Kabupaten Banggai Laut', 'terbaru', '2025-02-09', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Angin kencang terjadi pada Minggu (09/02/25) pukul 01.00 WITA. Angin kencang terjadi di beberapa titik diantaranya Desa Monsongan dan Desa Gonggong di Kecamatan Banggai Tengah, Kelurahan Lompio dan Desa Lampa yang terletak di Kecamatan Banggai Kabupaten Banggai Laut. </p><p class=\"ql-align-justify\">Hujan deras disertai angin kencang menyebabkan 8 unit rumah rusak ringan, 2 unit rumah rusak sedang serta 3 unit rumah rusak berat di Desa Monsongan. 3 unit rumah rusak di Desa Gonggong, 1 unit rumah rusak di Desa Lapa dan 3 unit rumah rusak di Kelurahan Lompio serta 1 unit bangunan sekolah SMKN 1 Banggai rusak ringan.</p><p class=\"ql-align-justify\">Kebutuhan mendesak berupa Logistik PB. Situasi akhir warga yang terdampak mengungsi ke rumah kerabat terdekat.</p><p class=\"ql-align-justify\"><br></p>', '1747981165586-WhatsApp Image 2025-02-09 at 14.48.11.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747981165586-WhatsApp Image 2025-02-09 at 14.48.11.jpeg', '2025-05-23 06:19:25', '2025-05-23 06:19:25'),
(156, '-	Tanah Longsor terjadi di Desa Keuno Kecamatan Petasia Timur Kabupaten Morowali Utara. ', 'terbaru', '2025-02-18', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Tanah Longsor terjadi di Desa Keuno pada Selasa (18/02/25) pukul 23.00 WITA. Mengakibatkan runtuhnya material yang berdampak pada rusaknya fasilitas umum.</p><p class=\"ql-align-justify\"><br></p>', '1747981207401-WhatsApp Image 2025-02-19 at 19.45.47.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747981207401-WhatsApp Image 2025-02-19 at 19.45.47.jpeg', '2025-05-23 06:20:07', '2025-05-23 06:20:07'),
(157, '-	Banjir terjadi di Desa Pamberea Kecamatan Mori Atas Kabupaten Morowali Utara ', 'terbaru', '2025-03-01', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Sabtu (01/03/25) pukul 20.00 WITA. Banjir mengakibatkan terendamnya 5 unit rumah warga. Banjir dipicu oleh hujan dengan intensitas tinggi sejak sore hari.</p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 30 jiwa dan 5 rumah terdampak. Situasi akhir air mulai surut.</p><p class=\"ql-align-justify\"><br></p>', '1747981242784-WhatsApp Image 2025-03-02 at 09.28.03.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747981242784-WhatsApp Image 2025-03-02 at 09.28.03.jpeg', '2025-05-23 06:20:42', '2025-05-23 06:20:42'),
(158, '-	Banjir dan tanah longsor terjadi di 2 desa di kecamatan Lore Barat', 'terbaru', '2025-03-03', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir dan tanah longsor terjadi di Desa Kageroa dan Lengkeka Kecamatan Lore Barat Kabupaten Poso pada Senin (03/03/2025) pukul 17.00 WITA. Hujan yang mengguyue sejak sore hingga malam hari mengakibatkan banjir dan tanah longsor di beberapa titik di kedua desa tersebut.</p><p class=\"ql-align-justify\">Terdampak akibat kejadian ini diantaranya 12 titik longsor pada ruas jalan Desa Lengkeka serta 1 unit jembatan putus. Situasi akhir banjir telah surut.&nbsp;</p><p><br></p>', '1747991624583-WhatsApp Image 2025-03-04 at 11.24.04.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747991624583-WhatsApp Image 2025-03-04 at 11.24.04.jpeg', '2025-05-23 09:13:44', '2025-05-23 09:13:44'),
(159, 'Banjir merendam Kelurahan Kayamanya ', 'terbaru', '2025-03-05', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Kelurahan Kayamanya Kecamatan Poso Kota Kabupaten Poso pada Rabu (05/03/25) pukul 16.00 WITA. Intensitas hujan yang tinggi sejak siang hari mengakibatkan banjir meluap ke pemukiman warga yang berada di bantaran Sungai.</p><p class=\"ql-align-justify\">Terdampak akibat kejadian ini yakni 9 unit rumah warga. Situasi akhir hujan sudah reda banjir telah surut.&nbsp;</p><p><br></p>', '1747991663538-WhatsApp Image 2025-03-05 at 22.39.33.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747991663538-WhatsApp Image 2025-03-05 at 22.39.33.jpeg', '2025-05-23 09:14:23', '2025-05-23 09:14:23'),
(160, '-	Banjir terjadi di Desa Salua Kecamatan Kulawi Kabupaten Sigi', 'terbaru', '2025-03-05', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Rabu (05/03/25) pukul 13.30 WITA. Hujan dengan intensitas tinggi mengakibatkan meningkatnya debit air Sungai Desa Salua yang disertai material dan material tertahan di bendungan Sabodam.</p><p class=\"ql-align-justify\">Kebutuhan mendesak berupa pembersihan material. Situasi akhir air telah surut dan tidak mengancam pemukiman, jalan sudah dapat diakses namun Masyarakat tetap dihimbau untuk waspada dan mengutamakan keselamatan.</p>', '1747991715963-WhatsApp Image 2025-03-05 at 23.38.08.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747991715963-WhatsApp Image 2025-03-05 at 23.38.08.jpeg', '2025-05-23 09:15:15', '2025-05-23 09:15:15'),
(161, '-	Banjir terjadi di Desa Oo Parese Kecamatan Kulawi Selatan Kabupaten Sigi', 'terbaru', '2025-03-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Intensitas hujan yang tinggi mengakibatkan meluapnya daerah aliran Sungai Mewe dan Sungai Oo Parese ke pemukiman warga dan merusak lahan persawahan dan Perkebunan. (jumat, 07/03/25) pukul 17.00 WITA</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 3 KK dan 3 unit rumah terendam banjir. Kebutuhan mendesak berupa alat berat guna mengendalikan sumber ancaman. Situasi akhir air telah surut, hujan gerimis masih berlangsung dan Sebagian pengungsi telah Kembali ke rumah masing-masing</p>', '1747991821025-WhatsApp Image 2025-03-08 at 01.24.13.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747991821025-WhatsApp Image 2025-03-08 at 01.24.13.jpeg', '2025-05-23 09:17:01', '2025-05-23 09:17:01'),
(162, 'Banjir Kembali menggenangi Desa Onepute', 'terbaru', '2025-03-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Onepute Kecamatan Petasia Barat Kabupaten Morowali Utara pada Kamis (07/03/25) pukul 07.00 WITA. Intensitas hujan yang tinggi mengakibatkan meluaonya Sungai La’a ke pemukiman warga.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 100 KK/ 500 Jiwa, 125 unit rumah warga terendam banjir, 20 Lansia dan 45 Anak-anak. Kebutuhan mendesak berupa perlengkapan medis. Situasi akhir banjir masih menggenangi pemukiman warga.</p><p class=\"ql-align-justify\"><br></p>', '1747991891342-WhatsApp Image 2025-03-08 at 12.04.36.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747991891342-WhatsApp Image 2025-03-08 at 12.04.36.jpeg', '2025-05-23 09:18:11', '2025-05-23 09:18:11'),
(163, 'Banjir terjadi di Desa Omu Kecamatan Gumbasa Kabupaten Sigi ', 'terbaru', '2025-03-08', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Sabtu (08/03/25) pukul 10.17 WITA. Hujan dengan intensitas tinggi mengakibatkan meluapnya Sungai Omu yang mengakibatkan terendamnya Perkebunan serta mengancam putusnya jalan raya yang menghubungkan Desa Omu dan Desa Bangga.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada sekitar 10 Ha lahan Perkebunan warga. Kebutuhan mendesak berupa alat berat guna pengendalian sumber ancaman. Situasi saat ini air masih menggenangi perkebuanan warga dan masih berlangsung hujan ringan.</p>', '1747991940659-WhatsApp Image 2025-03-08 at 11.38.11 (2).jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1747991940659-WhatsApp Image 2025-03-08 at 11.38.11 (2).jpeg', '2025-05-23 09:19:00', '2025-05-23 09:19:00'),
(164, 'Desa Ulatan Dilanda Banjir', 'terbaru', '2025-03-08', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Ulatan Kecamatan Palasa Kabupaten Parigi Moutong pada Sabtu (08/03/25) pukul 12.40 WITA. Hujan dengan intensitas sedang hingga lebat memicu terjadinya banjir. Terdampak akibat kejadian diantaranya 6 KK / 22 jiwa, 4 lansia, 2 bayi dan 3 balita. </p><p class=\"ql-align-justify\">Kebutuhan mendesak Logistik PB dan normalisasi Sungai. Situasi akhir air berangsur surut dan warga melakukan pembersihan rumah masing-masing.&nbsp;</p>', '1748229910218-WhatsApp Image 2025-03-08 at 18.46.17.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748229910218-WhatsApp Image 2025-03-08 at 18.46.17.jpeg', '2025-05-26 03:25:10', '2025-05-26 03:25:10'),
(165, 'Banjir Terjadi di Desa Resara Kecamatan Balantak Selatan Kabupaten Banggai', 'terbaru', '2025-03-08', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Sabtu (08/03/25) pukul 13.00 WITA. Akibat curah hujan dengan intensitas sedang hingga lebat menyebabkan banjir di Desa Resara.</p><p class=\"ql-align-justify\">Terdampak akibat kejadian ini diantara 45 Unit Rumah, 1 unit kantor desa, 2 sarana Kesehatan, 2 unit sarana Pendidikan, perkantoran dan sebuah gereja. </p><p class=\"ql-align-justify\">Kebutuhan mendesak berupa sembako. Situasi akhir air berangsur surut namun beberapa masih tergenang.</p>', '1748229969173-WhatsApp Image 2025-03-08 at 20.23.43.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748229969173-WhatsApp Image 2025-03-08 at 20.23.43.jpeg', '2025-05-26 03:26:09', '2025-05-26 03:26:09'),
(166, 'Banjir Terjadi di Desa Resara Kecamatan Balantak Selatan Kabupaten Banggai', 'terbaru', '2025-03-08', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Sabtu (08/03/25) pukul 13.00 WITA. Akibat curah hujan dengan intensitas sedang hingga lebat menyebabkan banjir di Desa Resara.</p><p class=\"ql-align-justify\">Terdampak akibat kejadian ini diantara 45 Unit Rumah, 1 unit kantor desa, 2 sarana Kesehatan, 2 unit sarana Pendidikan, perkantoran dan sebuah gereja. </p><p class=\"ql-align-justify\">Kebutuhan mendesak berupa sembako. Situasi akhir air berangsur surut namun beberapa masih tergenang.</p>', '1748229999641-WhatsApp Image 2025-03-08 at 20.23.43.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748229999641-WhatsApp Image 2025-03-08 at 20.23.43.jpeg', '2025-05-26 03:26:39', '2025-05-26 03:26:39'),
(167, '-	Banjir Melanda Desa Bambasiang Kecamatan Palasa Kabupaten Parigi Moutong', 'terbaru', '2025-03-08', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Sabtu (08/03/25) pukul 15.00 WITA. Hujan dengan intensitas sedang hingga lebat sejak pagi hingga siang hari menyebabkan banjir. </p><p class=\"ql-align-justify\">Kejadian ini menyebabkan 1 unit jembatan putus. Situasi akhir hujan telah reda dan air telah surut.&nbsp;</p><p class=\"ql-align-justify\"><br></p>', '1748230047042-Picture1.jpg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230047042-Picture1.jpg', '2025-05-26 03:27:27', '2025-05-26 03:27:27'),
(168, '-	Banjir terjadi Desa Kokobuka Kecamatan Tiloan Kabupaten Buol', 'terbaru', '2025-03-08', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir melanda Desa Kokobuka pada Sabtu (08/03/25) pukul 15.45 WITA. Hujan dengan intensitas sedang hingga lebat disertai dengan angin kencang yang mengakibatkan banjir pada Dusun IV dengan ketinggian air berkisar 70 Cm hingga 1 meter.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 62 unit rumah, 175 KK / 500 jiwa, 2 unit saran Pendidikan, 1 unit masjid, 2 unit sarana Kesehatan serta 2 unit jembatan kayu (perlintasan warga desa) kebutuhan mendesak berupa makanan siap saji dan air bersih. Situasi akhir hujan telah reda, banjir berangsur surut dan warga membersihkan rumah masing-masing.</p>', '1748230127721-WhatsApp Image 2025-03-09 at 19.11.54.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230127721-WhatsApp Image 2025-03-09 at 19.11.54.jpeg', '2025-05-26 03:28:47', '2025-05-26 03:28:47'),
(169, 'Banjir Desa Palau Kecamatan Balaesang Tanjung Kabupaten Donggala', 'terbaru', '2025-03-13', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Kamis (13/03/25) pukul 15.30 WITA. Akibat curah hujan yang tinggi sehingga menyebabkan air Sungai meluap hingga ke pemukiman warga. Terdampak akibat kejadian 3 KK dan 3 unit rumah. Situasi akhir banjir sudah surut dan hujan telah reda.&nbsp;</p>', '1748230192209-WhatsApp Image 2025-03-13 at 21.52.25.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230192209-WhatsApp Image 2025-03-13 at 21.52.25.jpeg', '2025-05-26 03:29:52', '2025-05-26 03:29:52'),
(170, '-	Banjir Desa Tomini Barat Kecamatan Tomini Kabupaten Parigi Moutong ', 'terbaru', '2025-03-13', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Kamis (13/03/25) pukul 18.00 WITA. Hujan dengan intensitas sedang hingga lebat menyebabkan banjir di Sungai Popa dan meluap ke pemukiman warga. </p><p class=\"ql-align-justify\">Kejadian ini berdampak pada rumah warga, 2 unit sarana Pendidikan dan tanggul Sungai Popa Desa Tomini Barat Jebol. Kebutuhan mendesak berupa logistic PB, situasi akhir air berangsur surut dan warga melakukan pembersihan di rumah masing-masing.&nbsp;</p>', '1748230242693-WhatsApp Image 2025-03-13 at 22.56.12.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230242693-WhatsApp Image 2025-03-13 at 22.56.12.jpeg', '2025-05-26 03:30:42', '2025-05-26 03:30:42'),
(171, 'Banjir menerjang 2 Desa di Kecamatan Palasa Kabupaten Parigi Moutong', 'terbaru', '2025-03-13', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Ogoansam dan Bambasiang pada Kamis (13/03/25) pukul 19.00 WITA. Hujan dengan intensitas sedang hingga lebat menyebabkan meluapnya Sungai Palasa hingga ke pemukiman warga.</p><p class=\"ql-align-justify\">Terdampak di Desa Ogoansam diantara 50 KK, 50 unit rumah, serta 30 unit rumah rusak berat. Kebutuhan mendesak berupa Logistik PB.</p>', '1748230333250-WhatsApp Image 2025-03-13 at 22.56.12.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230333250-WhatsApp Image 2025-03-13 at 22.56.12.jpeg', '2025-05-26 03:32:13', '2025-05-26 03:32:13'),
(172, 'Abrasi Pantai Desa Ngune Kecamatan Lakea Kabupaten Buol ', 'terbaru', '2025-03-13', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Kejadian terjadi pada Kamis (13/03/25) pukul 17.00 WITA. Air laut disertai ombak dan angin kencang merusak sekitar 50 unit rumah warga, yang merupakan rumah nelayan bantuan dari pemerintah Kabupaten Buol.</p><p class=\"ql-align-justify\">Terdampak akibat kejadian ini diantaranya 37 KK, 147 jiwa dan 37 unit rumah rusak berat. Kebutuhan mendesak berupa logistic PB.</p>', '1748230379863-WhatsApp Image 2025-03-14 at 00.38.30.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230379863-WhatsApp Image 2025-03-14 at 00.38.30.jpeg', '2025-05-26 03:32:59', '2025-05-26 03:32:59'),
(173, 'Tanah Longsor terjadi di Taipa Obal Kecamatan Tinombo Kabupaten Parigi Moutong ', 'terbaru', '2025-03-14', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Tanah longsor terjadi pada Jumat (14/03/25) pukul 17.00 WITA. Intensitas hujan yang tinggi sejak sore hari mengakibatkan terjadinya tanah longsor pada akses jalan utama menuju Desa Taipa Obal sepanjang 150 meter serta tidak dapat dilalui oleh kendaraan. </p><p class=\"ql-align-justify\">Terdampak akibat kejadian ini adalah akses jalan menuju desa. Tidak ada korban jiwa dan pengungsi akibat kejadian ini. Kebutuhan mendesak berupa perbaikan akses jalan. Situasi akhir hujan telah reda, akses jalan belum dapat dilalui.</p>', '1748230504335-WhatsApp Image 2025-03-14 at 22.28.26.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230504335-WhatsApp Image 2025-03-14 at 22.28.26.jpeg', '2025-05-26 03:35:04', '2025-05-26 03:35:04'),
(174, 'Banjir terjadi di Desa Toro Kecamatan Kulawi Kabupaten Sigi', 'terbaru', '2025-03-14', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Jumat (14/03/25) pukul 19.50 WITA. Intensitas hujan yang tinggi mengakibatkan meluapnya Sungai Meweh hingga merendam pemukiman warga di Dusun 6 Desa Toro. </p><p class=\"ql-align-justify\">Kejadian ini mengakibatkan 5KK/13&nbsp;Jiwa, 5 unit rumah dan 1 penggilingan padi terdampak. Kebutuhan mendesak berupa Logistik PB. Situasi akhir hujan telah reda, air berangsur surut.</p>', '1748230617957-WhatsApp Image 2025-03-14 at 22.39.49.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230617957-WhatsApp Image 2025-03-14 at 22.39.49.jpeg', '2025-05-26 03:36:57', '2025-05-26 03:36:57'),
(175, 'Desa Maranda Dilanda Banjir', 'terbaru', '2025-03-16', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Maranda Kecamatan Poso Pesisir Utara Kabupaten Poso pada Minggu (16/03/25) pukul 20.00 WITA. Intensitas hujan yang tinggi mengakibatkan debit air Sungai Samalera meningkat hingga meluap ke pemukiman warga Desa Maranda. </p><p class=\"ql-align-justify\">Saat ini air berangsur surut, hujan masih mengguyur, dan ketinggian air sebatas lutut orang dewasa. Saat ini masyarakat masih waspada terhadap banjir susulan</p>', '1748230745042-maranda.jpg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230745042-maranda.jpg', '2025-05-26 03:39:05', '2025-05-26 03:39:05'),
(176, 'Banjir terjadi di Desa Mendaan ', 'terbaru', '2025-03-16', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Mendaan Kecamatan Karamat Kabupaten Buol pada Minggu (16/03/25) pukul 18.20 WITA. Curah Hujan yang tinggi di daerah pegunungan sejak beberapa hari terakhir mengakibatkan debit air meningkat sehingga merendam pemukiman warga.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 30 KK dan 150 jiwa serta 10 unit rumah. Kebutuhan mendesak berupa logistik PB. Situasi saat ini air berangsur surut.</p><p class=\"ql-align-justify\"><br></p>', '1748230900313-WhatsApp Image 2025-03-16 at 23.30.17.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748230900313-WhatsApp Image 2025-03-16 at 23.30.17.jpeg', '2025-05-26 03:41:40', '2025-05-26 03:41:40'),
(177, 'Banjir Menerjang Kelurahan Tambun Kecamatan Baolan Kabupaten Toli-Toli ', 'terbaru', '2025-03-16', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir Menerjang Kelurahan Tambun Kecamatan Baolan Kabupaten Toli-Toli pada Minggu (16/03/25) pukul 20.00 WITA. Hujan yang mengguyur Kabupaten Toli-Toli sejak sore hari dengan intensitas tinggi mengakibatkan meluapnya air di beberapa wilayah pemukiman warga di Kabupaten Toli-Toli salah satunya di Kelurahan Tambun.</p><p class=\"ql-align-justify\">Saat ini jumlah terdampak dan kebutuhan mendesak masih dalam proses pendataan. Situasi saat ini hujan masih berlangsung, air berangsur surut namun ketinggian air mencapai paha orang dewasa. Saat ini TRC Kabupaten Toli-Toli sedang melakukan kaji cepat lapangan.</p><p class=\"ql-align-justify\"><br></p>', '1748231180608-TAMBUN.jpg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748231180608-TAMBUN.jpg', '2025-05-26 03:46:20', '2025-05-26 03:46:20'),
(178, 'Banjir terjadi di Desa Lelean Nono Kecamatan Baolan Kabupaten Toli-', 'terbaru', '2025-03-16', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Hujan dengan intensitas tinggi yang terjadi di Desa Lelean Nono Kecamatan Baolan Kabupaten Toli-Toli sejak pukul 14.00 WITA menyebabkan terjadinya luapan air sungai pada pukul 17.30 WITA yang mengakibatkan banjir pada pemukiman warga.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 45 KK / 132 jiwa serta 43 unit rumah. Kebutuhan mendesak berupa Logistik PB. Situasi akhir saat ini air mulai surut.</p>', '1748231382326-LELEANNONO.jpg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748231382326-LELEANNONO.jpg', '2025-05-26 03:49:42', '2025-05-26 03:49:42'),
(179, 'Banjir Melanda 3 Desa di Kecamatan Lampasio Kabupaten Toli-Toli', 'terbaru', '2025-03-17', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Janja, Desa Sibea dan Desa Salugan Kecamatan Lampasio Kabupaten Toli-Toli pada Senin (17/03/25) pukul 07.00 WITA</p><p class=\"ql-align-justify\">Hujan dengan intensitas tinggi yang terjadi di Daerah Kabupaten Toli-Toli sejak Minggu (16/03/25) menyebabkan terjadinya luapan air sungai yang mengakibatkan banjir pada pemukiman, Persawahan dan perkebunan warga. </p><p class=\"ql-align-justify\">Terdampak di Desa Janja sebanyak 60 Unit Rumah, Desa Sibea dalam pendataan, Desa Salugan 160 KK, 20 Ha Persawahan dan 20 Ha perkebunan. </p><p class=\"ql-align-justify\">Kebutuhan mendesak berupa Logistik PB. Situasi akhir hujan telah reda, air berangsur surut.</p>', '1748231638847-WhatsApp Image 2025-03-17 at 22.12.25.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748231638847-WhatsApp Image 2025-03-17 at 22.12.25.jpeg', '2025-05-26 03:53:58', '2025-05-26 03:53:58'),
(180, 'Banjir Desa Koninis Kecamatan Simpang Raya Kabupaten Banggai', 'terbaru', '2025-03-18', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Selasa (18/03/25) pukul 23.05 WITA. Intensitas hujan yang tinggi mengakibatkan banjir hingga meluap ke pemukiman warga dan terjadi pengikisan tebing sungai di area Pemakaman Umum.</p><p class=\"ql-align-justify\">Sebanyak 7 unit rumah warga terdampak dan pemakaman umum terancam akiban pengikisan tebing sungai. Kebutuhan mendesak berupa normalisasi sungai dan pembuatan tanggul. Saat ini banjir telah surut.</p>', '1748231950758-WhatsApp Image 2025-03-19 at 13.18.57.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748231950758-WhatsApp Image 2025-03-19 at 13.18.57.jpeg', '2025-05-26 03:59:10', '2025-05-26 03:59:10'),
(181, 'Tanah longsor terjadi di daerah pegunungan perbatasan antara Desa Balukang dan Desa Bou', 'terbaru', '2025-03-22', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Tanah longsor terjadi pada Sabtu (22/03/25) pukul 11.30 WITA di daerah pegunungan perbatasan antara Desa Balukang dan Desa Bou, Kec. Sojol,. Kab. Donggala. Akibat dari hujan deras yang terjadi menyebabkan terjadinya tanah longsor sehingga menutupi sebagian badan jalan sekitar 50 meter<strong>,</strong> adapun dari kejadian ini dibutuhkan alat berat guna untuk membersihkan sisa material longsor.</p><p><br></p>', '1748236139526-longsor.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748236139526-longsor.jpeg', '2025-05-26 05:08:59', '2025-05-26 05:08:59'),
(182, '-	Banjir Desa Padungnyo Kecamatan Nambo Kabupaten Banggai', 'terbaru', '2025-03-27', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa di Desa Padungnyo pada Kamis (27/03/25) pukul 19.00 WITA. Intensitas hujan yang tinggi di Desa Lumbe mengakibatkan debit air meningkag sehingga Desa Padungnyo terdampak banjir kiriman yang menggenangi pemukiman warga. Kejadian ini berdampak pada 20 unit rumah warga.</p><p class=\"ql-align-justify\">Saat ini kebutuhan mendesak masih dalam pendataan. Situasi akhir banjir masih menggenangi setinggi pinggang orang Dewasa serta hujan masih mengguyur.</p>', '1748237436901-banjir.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748237436901-banjir.jpeg', '2025-05-26 05:30:36', '2025-05-26 05:30:36'),
(183, 'Banjir Merendam 2 Desa di Kecamatan Dondo Kabupaten Toli-Toli', 'terbaru', '2025-03-28', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Tinabogan dan Malomba Kecamatan Dondo pada Jumat (28/03/25) pukul 19.20 WITA. Kedua desa ini di guyur hujan dengan intensitas tinggi menyebabkan air sungai meluap dan menggenangi sebagian wilayah pemukiman.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada pemukiman, persawahan, fasilitas pemerintahan dan jalan Trans Sulawesi. Situasi akhir hujan telah reda dan ketinggian air berangsur surut.</p><p><br></p>', '1748308060383-dondo.jpg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748308060383-dondo.jpg', '2025-05-27 01:07:40', '2025-05-27 01:07:40'),
(184, 'Banjir Merendam 3 Dusun di Desa Ogolili Kecamatan Galang Kabupaten Toli-Toli', 'terbaru', '2025-03-28', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Dusun 1, 2 dan 3 Desa Ogolili Kecamatan Galang Kabupaten Toli-Toli pada Jumat (28/03/24) pukul 21.00 WITA. Intensitas hujan yang tinggi menyebabkan debit air meningkat dan meluapnya 2 Sungai yang mengapit Desa Ogolili yakni Sungai Malulu dan Ogolili. </p><p class=\"ql-align-justify\">Terdampak di Dusun 1 sebanyak 30 rumah, Dusun 2 sebanyak 5 rumah dan 15 rumah di Dusun 3. Kebutuhan mendesak berupa air bersih. Situasi akhir air sempat surut namun banjir kembali melanda pada Sabtu 29 Maret pukul 16.00 WITA</p>', '1748308178851-ogolili.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748308178851-ogolili.jpeg', '2025-05-27 01:09:38', '2025-05-27 01:09:38'),
(185, 'Desa Bahoea Reko-Reko Kecamatan Bungku Barat Kabupaten Morowali Terendam Banjir', 'terbaru', '2025-03-31', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Intensitas hujan yang tinggi sejak pukul 21.20 WITA mengakibatkan air sungai meluap pada Senin (31/03/25), air meluap ke jalan trans dan pemukiman warga serta memutus akses satu-satunya penghubung Desa Bahoea Reko-Reko dan Dusun Kabera.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 4 rumah. Dibutuhkan normalisasi sungai dan perbaikan jembatan penghubung. Situasi akhir air sudah surut.</p>', '1748308364323-rekoreko.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748308364323-rekoreko.jpeg', '2025-05-27 01:12:44', '2025-05-27 01:12:44'),
(186, 'Banjir Menerjang Desa Torete Kecamatan Bungku Pesisir Kabupaten Morowali', 'terbaru', '2025-03-31', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Torete pada Senin (31/03/25) pukul 22.20 WITA. Air mengalir dari area jalan houling PT. TAS dan area penambangan galian CPT. Graha Batu Perdana hingga air meluap ke pemukiman dan jalan Trans. Drainase sempit dan penuh dengan material yang terbawa air.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 24 unit rumah. Situasi akhir saat ini sudah mulai surut.</p>', '1748308627233-torete.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748308627233-torete.jpeg', '2025-05-27 01:17:07', '2025-05-27 01:17:07'),
(187, 'Banjir Terjadi di Desa Kabonga Besar Kecamatan Banawa Kabupaten Donggala', 'terbaru', '2025-04-01', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Selasa (01/04/25) pukul 15.45 WITA. Intensitas hujan yang tinggi menyebabkan air yang ada di wilayah pegunungan meluap ke Pemukiman Desa Kabonga Besar. </p><p class=\"ql-align-justify\">Kejadian ini berdampak pada sekitar 3 unit rumah. Kubutuhan mendesak berupa selimut, tikar dan Logistik PB. Sotuasi saat ini air telah surut, warga membersihkan rumah dan hujan telah reda</p>', '1748308753820-kabonga.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748308753820-kabonga.jpeg', '2025-05-27 01:19:13', '2025-05-27 01:19:13'),
(188, 'Banjir terjadi di Desa Peboa Kecamatan Petasia Timur Kabupaten Morowali Utara', 'terbaru', '2025-04-02', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Intensitas hujan yang tinggi mengakibatkan meluapnya sungai Tambalako sehingga mengakibatkan banjir pada Rabu (02/04/25) pukul 14.30 WITA. Kejadian ini berdampak pada 21 KK dan 17 unit rumah serta 11 KK mengungsi.</p><p class=\"ql-align-justify\">Kebutuhan mendesak berupa Logistik PB, Normalisasi Sungai dan Pembuatan Tanggul. Situasi akhir kondisi banjir dengan ketinggian 50 cm hingga 1.25 meter.</p>', '1748308874572-peboa.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748308874572-peboa.jpeg', '2025-05-27 01:21:14', '2025-05-27 01:21:14'),
(189, 'Banjir terjadi di Desa Mopu Kecamatan Bukal Kabupaten Buol', 'terbaru', '2025-04-04', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi pada Jumat (04/04/25) pukul 17.49 WITA. Hujan dengan intensitas tinggi menyebabkan meluapnya sungai Bukal sehingga merendam puluhan rumah dengan ketinggian 40-60 cm.</p><p class=\"ql-align-justify\">Kejadian ini berdampak pada 52 KK, 218 jiwa dan 36 unit rumah serta sekitar 5 Ha persawahan masyarakat terendam hingga terancam gagal panen. Kebutuhan mendesa berupa Logistik PB dan air bersih.</p>', '1748309096527-mopu.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748309096527-mopu.jpeg', '2025-05-27 01:24:56', '2025-05-27 01:24:56'),
(190, 'Banjir dan Angin Kencang Melanda Desa Betalemba dan Desa Tabalu ', 'terbaru', '2025-04-06', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir dan Tanah Longsor terjadi di Desa Betalemba dan Tabalu Kecamatan Poso Pesisir Selatan Kabupaten Poso pada Minggu (06/04/25) pukul 14.30 WITA. Hujan dengan intensitas tinggi disertai angin kencang menyebabkan terjadinya banjir yang meluap ke pemukiman warga serta menimbulkan kerisakan pada bangunan akibat angin kencang yang terjadi.</p><p class=\"ql-align-justify\">Terdampak di Desa Tabalu sekitar 115 unit rumah warga, 2 unit sarang walet rusak berat dan 2 unit rumah Rusak Sedang akibat angin kencang dan 1 unit TK terdampak. Terdampak di Desa Betalemba sedang dalam pendataan. Kebutuhan mendesak berupa normalisasi jalur air. Situasi akhir hujan mulai reda dan air berangsur surut.</p>', '1748309477762-tabalu.jpg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748309477762-tabalu.jpg', '2025-05-27 01:31:17', '2025-05-27 01:31:17'),
(191, 'Banjir Menerjang Desa Pebuonang Kecamatan Palasa Kabupaten Parigi Moutong ', 'terbaru', '2025-04-14', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Pebuonang pada Senin (14/04/2025) pukul 17.09 WITA. Hujan dengan intensitas sedang hingga lebat di hulu menyebanjir di Desa Pebuonang akibatnya 2 jembatan akses jalan desa putus dan 7 unit rumah hanyut.</p><p class=\"ql-align-justify\">Kebutuhan mendesak masih dalam proses pendataan. Situasi akhir di Lokasi kejadian banjir berangsur surut namum hujan masih mengguyur.</p><p class=\"ql-align-justify\"><br></p>', '1748310112735-pebuonang.jpg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748310112735-pebuonang.jpg', '2025-05-27 01:41:52', '2025-05-27 01:41:52'),
(192, 'Banjir terjadi di Desa Pande Kecamatan Moutong Kabupaten Parigi Moutong', 'terbaru', '2025-04-14', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Senin (14/04/25) pukul 22.57 WITA terjadi banjir di Desa Pande Kecamatan Moutong akibat hujan dengan intensitas tinggi menyebabkan meluapnya Sungai Taopa. </p><p class=\"ql-align-justify\">Saat ini jumlah terdampak dan kebutuhan mendesak masih dalam proses pendataan. Situasi akhir saat ini air masih menggenang.</p>', '1748310209730-pande.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748310209730-pande.jpeg', '2025-05-27 01:43:29', '2025-05-27 01:43:29'),
(193, 'Luapan Air Sungai Desa Pangi Mengakibatkan Banjir', 'terbaru', '2025-04-15', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Hujan dengan intensitas tinggi sejak pukul 14.00 hingga 15.00 WITA yang mengguyur Kecamatan Baolan mengakibatkan meluapnya Air Sungai Desa Pangi ke jalan raya dan sebagian besar wilayah pemukiman warga Desa Pangi Kecamatan Baolan Kabupaten Toli-Toli pada Selasa (15/04/25).</p><p class=\"ql-align-justify\">Saat ini jumlah terdampak dan kebutuhan mendesak masih dalam proses pendataan. Situasi di lokasi kejadiaan saat ini hujan telah reda dan air berangsur surut.</p>', '1748310407871-pangi.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748310407871-pangi.jpeg', '2025-05-27 01:46:47', '2025-05-27 01:46:47'),
(194, 'Banjir merendam 9 desa di Kecamatan Banawa Selatan', 'terbaru', '2025-04-15', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Selasa (15/04/25) pukul 13.00 WITA, wilayah Kecamatan Banawa Selatan di guyur hujan dengan intensitas tinggi yang mengakibatkan meluapnya air sungai ke pemukiman warga.</p><p class=\"ql-align-justify\">Sebanyak 9 Desa terendam diantaranya Desa Bambarimi, Lembasada, Lumbutarombo, Lumbumamara, Ongulara, Salumpaku, Salungkaenu, Sarombaya dan Tanahmea. Terdampak di Desa Lumbutarombo diantaranya 31 unit rumah, perernakan warga dan 100 karung gabah. Jumlah terdampak di 8 Desa lainnya masih dalam proses pendataan.</p><p class=\"ql-align-justify\">Saat ini Tim TRC BPBD Donggala sedang melakukan peninjauan di lokasi kejadian. Situasi di tempat kejadian hujan telah reda namun air masih menggenang.</p>', '1748310500617-bnw.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748310500617-bnw.jpeg', '2025-05-27 01:48:20', '2025-05-27 01:48:20'),
(195, 'Jembatan Nyaris Putus Akibat Banjir di Desa Pasir Putih', 'terbaru', '2025-04-17', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Banjir terjadi di Desa Pasir Putih Kecamatan Pamona Selatan pada Kamis (17/04/25) pukul 15.00 WITA. Debit air sungai yang meningkat mengakibatkan pengikisan Jembatan Tinelala yang merupakan penghubung Desa Pasir Putih dan Pendolo.</p><p class=\"ql-align-justify\">Situasi saat ini hujan telah reda namun akses jembatan belum dapat dilalui oleh kendaraan roda 4.</p>', '1748310646404-jmbtn.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748310646404-jmbtn.jpeg', '2025-05-27 01:50:46', '2025-05-27 01:50:46'),
(196, 'Tanah Longsor Terjadi Di Desa Sedoa Kecamatan Lore Utara Kabupaten Poso', 'terbaru', '2025-04-22', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Tanah Longsor terjadi pada Selasa 22 April 2025 Pukul 05.00 WITA. Intensitas hujan yang tinggi mengakibatkan tanah longsor yang mengakibatkan tertutupnya akses jalan di Desa Sedoa. </p><p class=\"ql-align-justify\">Dibutuhkan alat berat untuk menggeser material longsor yang menutupi jalan. Saat ini masyarakat melakukan pengerukan secara manual dengan alat seadanya.</p>', '1748310755065-sedoa.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748310755065-sedoa.jpeg', '2025-05-27 01:52:35', '2025-05-27 01:52:35'),
(197, 'Banjir Desa Bentean Kecamatan Banggai Selatan Kabupaten Banggai Laut', 'terbaru', '2025-04-22', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Intensitas hujan yang tinggi sejak pukul 05.30 (Jumat, 16/05/25) mengakibatkan ruas jalan utama dan 10 unit rumah warga tergenang. Mengakibatkan aktivitas warga terganggu. Sebanyak 10 unit rumah warga. Kebutuhan mendesak logistik PB. Situasi akhir hujan masih berlangsung</p>', '1748310903495-bentean.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1748310903495-bentean.jpeg', '2025-05-27 01:55:03', '2025-05-27 01:55:03'),
(198, 'Banjir Menerjang Desa Pangi Kecamatan Baolan Kabupaten Toli-Toli ', 'terbaru', '2025-05-21', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Rabu (21/05/25) pukul 12.30 WITA. Hujan Deras yang dimulai sejak pukul 12.30 hingga 14.00 mengakibatkan meluapnya air Sungai Desa Pangi akibat debit air yang meningkat hingga menggenangi jalan raya dan Sebagian besar pemukiman warga.</p><p class=\"ql-align-justify\">	&nbsp;Kejadian ini berdampak pada pemukiman, lahan Perkebunan, fasilitas pemerinahan dan jalan trans Sulawesi. Situasi akhir di Lokasi kejadian hujan masih mengguyur namun banjir berangsur surut.</p>', '1755496566287-banjir baolan.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755496566287-banjir baolan.jpeg', '2025-08-18 05:56:06', '2025-08-18 05:56:06'),
(199, 'Banjir Menerjang Desa Pangi Kecamatan Baolan Kabupaten Toli-Toli ', 'terbaru', '2025-05-21', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Rabu (21/05/25) pukul 12.30 WITA. Hujan Deras yang dimulai sejak pukul 12.30 hingga 14.00 mengakibatkan meluapnya air Sungai Desa Pangi akibat debit air yang meningkat hingga menggenangi jalan raya dan Sebagian besar pemukiman warga.</p><p class=\"ql-align-justify\">	&nbsp;Kejadian ini berdampak pada pemukiman, lahan Perkebunan, fasilitas pemerinahan dan jalan trans Sulawesi. Situasi akhir di Lokasi kejadian hujan masih mengguyur namun banjir berangsur surut.</p>', '1755496566819-banjir baolan.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755496566819-banjir baolan.jpeg', '2025-08-18 05:56:06', '2025-08-18 05:56:06'),
(200, 'Tanah Longsor terjadi di Kelurahan Tanobununungan Kecamatan Banggai Kabupaten Banggai Laut', 'terbaru', '2025-05-24', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Tanah Longsor melanda Kompleks 12 Kelurahan Tanobonunungan Kecamatan Banggai pada Sabtu (24/05/25) pukul 04.15 WITA. Akibat intensitas hujan yang cukup lebat dari pukul 21.00 WITA hingga 04.30 WITA, yang menyebabkan sebuah rumah milik warga di Kelurahan Tanobonunungan tertimbun tanah longsor. 1 KK yang terdiri dari 3 Jiwa (Ancu Jarre (56), Rita Magga (48), Moh. Ardiansyah Jarre (17)). Situasi akhir Hujan telah reda, BPBD Balut melakukan pembersihan material dan tetap waspada akan potensi terjadinya longsor susulan.</p>', '1755496613585-longsor tanobununungan.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755496613585-longsor tanobununungan.jpeg', '2025-08-18 05:56:53', '2025-08-18 05:56:53'),
(201, 'Banjir menerjang Desa Toribulu Kecamatan Toribulu Kabupaten Parigi Moutong', 'terbaru', '2025-05-25', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Minggu (25/05/25) pukul 20.37 WITA hujan dengan intensitas sedang hingga lebat menyebabkan sungai meluap hingga ke pemukiman warga. Jumlah terdampak masih dalam pendataan, tidak ada pengungsi dan korban jiwa akibat kejadian ini.&nbsp;</p>', '1755496672270-toribulu.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755496672270-toribulu.jpeg', '2025-08-18 05:57:52', '2025-08-18 05:57:52'),
(202, 'Banjir Bandang Melanda Desa Wombo Kalonggo Kecamatan Tanantovea Kabupaten Donggala', 'terbaru', '2025-05-27', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Pada hari Selasa tanggal 27 Mei 2025 pukul 15.00 desa Wombo di guyur hujan dengan intensitas tinggi yang mengakibatkan meluapnya air sungai dan menyebabkan banjir bandang. Hingga saat ini warga masih mengharapkan pertolongan dari tim Rescue. </p><p class=\"ql-align-justify\">	Terdampak akibat kejadian ini diantaranya 50 unit rumah warga, 1 Jembatan putus total, Gedung TK, SD, SMP dan Madrasah. Pengungsi sebanyak sekitar 100 KK, 2 jiwa ditemukan dalam kondisi terluka dan 2 jiwa masih dalam pencarian. Kebutuhan mendesak berupa Logistik PB, Air bersih, makanan siap saji, tenda pengungsi, obat-obatan dan kidsware. Situasi akhir hujan telah reda, air berangsur surut namun warga masih waspada potensi banjir susulan.</p>', '1755496725758-wombo kalonggo.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755496725758-wombo kalonggo.jpeg', '2025-08-18 05:58:45', '2025-08-18 05:58:45'),
(203, 'Banjir menerjang 5 Desa Di Kecamatan Moutong Kabupaten Parigi Moutong', 'terbaru', '2025-06-01', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Minggu, 01 Juni 2025. Pukul 06.00 WITA, telah terjadi banjir di Desa Moutong Tengah, Desa Moutong Utara, Desa Moutong Timur, Desa Moutong Barat, dan Desa Lobu Kec. Moutong Kab. Parigi moutong. Akibat hujan dengan intensitas yang tinggi menyebabkan sungai moutong meluap hingga ke pemukiman warga. Terdampak akibat kejadian ini diantaranya Desa Moutong Tengah sebanyak 387 KK/785 Jiwa, Moutong timur sebanyak 80 KK/240 jiwa, SDN 1 Moutong, SMPN 1 Moutong, MTs 1 Moutong dan wilayah pasar. Kebutuhan mendesak berupa Logistik PB. Situasi akhir air belum surut, hujan masih berlangsung.&nbsp;</p>', '1755496784767-kec. moutong.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755496784767-kec. moutong.jpeg', '2025-08-18 05:59:44', '2025-08-18 05:59:44'),
(204, 'Banjir terjadi di Maleali Kecamatan Sausu Kabupaten Parigi Moutong', 'terbaru', '2025-06-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Sabtu, 7 Juni 2025. Pukul 21.15 WITA, telah terjadi banjir di Desa. Maleali, Kec. Sausu. Akibat dari hujan dengan intensitas yang tinggi. Terdampak sebanyak 73 KK, sekitar 284 jiwa, 5 Bayi, 27 balita dan 65 Lansia dan pengungsi sejumlah 1 KK, 10 jiwa, 2 bayi 4 balita dan 2 lansia. Kebutuhan mendesak berupa logistic PB dan normalisasi Sungai. Situasi akhir air banjir telah surut dan Masyarakat melakukan pembersihan rumah masing-masing.</p>', '1755496992647-malealii.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755496992647-malealii.jpeg', '2025-08-18 06:03:12', '2025-08-18 06:03:12'),
(205, 'Banjir Desa Sausu Pakareme Kecamatan Sausu Kabupaten Parigi Moutong', 'terbaru', '2025-06-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir Desa Sausu pada Sabtu (07/06/25) pukul 21.15 WITA akibat intensitas hujan yang tinggi mengakibatkan meluapnya Sungai Pakareme hingga ke pemukiman warga. Terdampak sebanyak 73 KK dan 284 jiwa. Situasi akhir air telah surut dan warga membersihkan rumah mashing-masing.</p>', '1755497034935-pakareme.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755497034935-pakareme.jpeg', '2025-08-18 06:03:54', '2025-08-18 06:03:54'),
(206, 'Banjir Tambarana Kecamatan Poso Pesisir Utara Kabupaten Poso', 'terbaru', '2025-06-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Curah hujan yang tinggi mengakibatkan meluapnya aliran air Sungai Matawo Desa Tambarana pada Sabtu (07/06/25) pukul 21.45 WITA. Terdampak sebanyak 54 Unit Rumah Warga, 3 Unit Warung Makan dan 1 unit Panel Tenaga Surya Kelompok Tani. Fasilitas umum yang terdampak diantaranya Tempat Ibadah Agama Hindu (Pura), jalan Trans Sulawesi dan 1 Unit Jembatan Desa. Kebutuhan mendesak yaitu normalisasi Sungai dan perbaikan jembatan. Situasi akhir air telah surut, akses jalan trans Sulawesi sudah bisa dilewati, jembatan yang berada di Dusun 2 rusak parah dan tidak bisa dilalui kendaraan.</p><p class=\"ql-align-justify\"><br></p>', '1755497091793-tambaranaaa.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755497091793-tambaranaaa.jpeg', '2025-08-18 06:04:51', '2025-08-18 06:04:51'),
(207, 'Banjir Desa Pendolo Kecamatan Pamona Selatan Kabupaten Poso', 'terbaru', '2025-06-12', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Kamis (12/06/25) pukul 19.00 WITA. Curah hujan yang tinggi mengakibatkan terjadinya luapan Sungai Pandayora Desa Pendolo Kecamatan Pamona Selatan Kabupaten Poso dan menyebabkan 4 rumah warga terendam sekitar 50 cm. terdampak sebanyak 4 KK dan 10 Jiwa serta 4 unit rumah. Kebutuhan mendesak berupa Logistik PB. Situasi akhir yakni air berangsur surut.</p>', '1755497129761-pendolo.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755497129761-pendolo.jpeg', '2025-08-18 06:05:29', '2025-08-18 06:05:29'),
(208, 'Banjir dan Tanah Longsor melanda 2 Kelurahan dan 1 Desa di Kecamatan Petasia Kabupaten Morowali Utara', 'terbaru', '2025-06-14', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir dan Tanah Longsor terjadi di Kelurahan Bahontula, Kelurahan Bahoue dan Desa Ganda-Ganda pada Sabtu (14/06/25) pukul 22.00 WITA. Intensitas hujan yang tinggi mengakibatkan terjadinya luapan Sungai serta longsor pada badan jalan di beberapa wilayah di Kecamatan Petasia. </p><p class=\"ql-align-justify\">	Kejadian ini menimbulakn dampak diantaranya 4 KK/16 jiwa di Lrg Kamboja Kelurahan Bahontula, Jl. Kuda Laut sebanyak 3 KK/12 jiwa, 3 unit rumah dan 3 unit fasilitas umum, Jl. Batu Susun Kecamatan Bahoue 1 KK, Desa Ganda-Ganda 1 KK dan 1 Unit rumah (rusak Berat). Kebutuhan mendesak berupa Logistik PB dan alat berat. Situasi akhir hujan masih berlangsung.</p>', '1755497193074-bahontula.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755497193074-bahontula.jpeg', '2025-08-18 06:06:33', '2025-08-18 06:06:33'),
(210, 'Banjir Dan Tanah Longsor Desa Lembah Bomban Kecamatan Bolano Lambunu Kabupaten Parigi Moutong ', 'terbaru', '2025-06-17', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir dan tanah longsor terjadi pada Selasa (17/06/25) pukul 16.20 WITA menerhang Desa Lembah Bomban, Desa Lambunu, Desa Wanamukti Utara, Desa Siendeng, Desa Wanamukti, Desa Wanamukti Barat, Desa Beringin Jaya, Desa Sritabaang, Desa Bolano, Desa Bolano Barat, Desa Bolano Utara Kec. Bolano Lambunu, Kab. Parigi Moutong akibat hujan deras yang cukup lama. Terdampak di Desa Lembah Bomban sebanyak 30 KK/114 Jiwa Dusun I, 12 KK/43 Jiwa Dusun II, 5 KK/19 Jiwa Dusun III, 57 KK/221 Jiwa Dusun IV, 1 unit rumah Rusak Berat, fasilitas umum 1 unit Masjid, 1 Unit TPA, 2 Sarana Pendidikan. Desa Wanamukti Utara 34 KK/ 115 Jiwa dan akses Dusun III Putus, Desa Siendeng sekitar 300 KK dan 1200 jiwa. Fasilitas umum berupa 2 unit masjid, 2 unit musholla, 1 unit Balai Desa, SDK Siendeng, SD Inpres 1 Lambunu, SMK DDI Siendeng. Pengungsi Desa Lembah Bomban 20 KK/143 Jiwa, 6 Bayi, 10 Balita, 55 Lansia, Desa Wanamukti Utara 2 KK 9 Jiwa. Desa Siendeng sekitar 250 KK dan 1000 Jiwa.</p><p class=\"ql-align-justify\">	Kebutuhan mendesak berupa Logistik PB dan alat berat. Situasi akhir hujan telah reda, banjir berangsur surut, jalan yang terputus sudah bisa dilalui oleh kendaraan roda 2 dan roda 4 (Desa Lembah Bomban), titik pengungsian di kantor Desa Siendeng.</p><p><br></p>', '1755508657787-lembabomban.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755508657787-lembabomban.jpeg', '2025-08-18 09:17:37', '2025-08-18 09:17:37'),
(211, 'Banjir Melanda Desa Ongka Persatuan Utara Kecamatan Ongka Malino Kabupaten Parigi Moutong ', 'terbaru', '2025-06-19', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Kamis (19/06/25) pukul 16.35 WITA intensitas hujan yang deras mengakibatkan terjadinya luapan banjir hingga merendam pemukiman warga serta 1 unit jembatan penghubung menuju Dusun 4 terputus. Kebutuhan mendesak berupa perbaikan jembatan. Situasi akhir banjir telah surut.</p>', '1755508778811-WhatsApp Image 2025-06-18 at 09.18.20.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755508778811-WhatsApp Image 2025-06-18 at 09.18.20.jpeg', '2025-08-18 09:19:38', '2025-08-18 09:19:38'),
(212, 'Tanah Longsor Melanda Desa Tirtanagaya Kecamatan Bolano Kabupaten Parigi Moutong ', 'terbaru', '2025-06-22', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Tanah longsor terjadi pada Minggu (22/06/25) pukul 12.17 WITA, telah terjadi tanah longsor di Desa Tirtanagaya akibatnya diperkirakan 7 orang tertimbun longsor. Kebutuhan mendesak alat berat dan tim SAR. Situasi akhir tim gabungan sedang melakukan pencarian. </p><p class=\"ql-align-justify\">	Korban hilang diantaranya Sahrat (L/43), Subran (L/52), Ijal (L/28), Safrudin (L/36), Riska (P/26), Arun (L/17), Rapi (L/14)</p>', '1755509050150-WhatsApp Image 2025-06-22 at 16.36.52.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755509050150-WhatsApp Image 2025-06-22 at 16.36.52.jpeg', '2025-08-18 09:24:10', '2025-08-18 09:24:10'),
(213, 'Banjir terjang Desa Balinggi Kecamatan Balinggi Kabupaten Parigi Moutong', 'terbaru', '2025-06-26', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Kamis (26/06/25) pukul 15.20 WITA. Intensitas curah hujan yang deras menyebabkan banjir dan sungai yang berada di Desa Balinggi meluap hingga membuat tanggul sungai di balinggi jati jebol serta merendam pemukiman warga dan jalan trans. Terdampak akibat kejadian ini yakni jembatn di Desa Suli dan persawahan seluas sekitar 80 Ha. Kebutuhan mendesak yaitu perbaikan tanggul Sungai yang jebol. Situasi akhir hujan telah reda, banjir belum surut.</p>', '1755509325182-WhatsApp Image 2025-06-26 at 19.26.57.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755509325182-WhatsApp Image 2025-06-26 at 19.26.57.jpeg', '2025-08-18 09:28:45', '2025-08-18 09:28:45'),
(214, 'Kejadian Angin Kencang Melanda Desa Sulewana Kecamatan Pamona Utara Kabupaten Poso', 'terbaru', '2025-06-29', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Angin kencang akibat cuaca ekstrim pada Minggu (29/06/25) pukul 17.00 WITA menyebabkan padamnya Listrik serta beberapa rumah warga rusak di Desa Sulewana. Terdampak akibat kejadian ini diantaranya 16 unit rumah yang terdiri dari 1 unit di Dusun II, 11 Unit di Dusun III dan 5 unit di Dusun IV. Kejadian ini mengakibatkan 5 KK mengungsi ke rumah kerabat. Kebutuhan mendesak berupa pemulihan Listrik yang padam. Situasi akhir Listrik masih padam namum kondisi cuaca mulai kondusif.&nbsp;</p>', '1755509458963-WhatsApp Image 2025-06-26 at 19.26.57.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755509458963-WhatsApp Image 2025-06-26 at 19.26.57.jpeg', '2025-08-18 09:30:58', '2025-08-18 09:30:58'),
(215, 'Kejadian Banjir Desa Kwala Besar dan Desa Baturata Kecamatan Paleleh Kabupaten Buol ', 'terbaru', '2025-07-04', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Jumat (04/07/25) pukul 18.30 WITA. Intensitas hujan yang deras menyebabkan banjir hingga merendam pemukiman dan Perkebunan warga. Terdampak akibat kejadian ini yaitu 90 unit rumah dan 90 KK. Lahan Perkebunan seluas sekitar 12 Ha, pengungsi sebanyak 2 KK/8 jiwa di Desa Kwala Besar dan 62 KK/120 Jiwa dan 57 unit rumah terendam. Kebutuhan mendesak berupa logistic PB. Situasi akhir hujan sudah reda dan warga membersihkan rumah masing-masing.&nbsp;</p>', '1755509527851-WhatsApp Image 2025-06-26 at 19.26.57.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755509527851-WhatsApp Image 2025-06-26 at 19.26.57.jpeg', '2025-08-18 09:32:07', '2025-08-18 09:32:07'),
(216, 'Banjir terjadi di Desa Air Panas Kecamatan Parigi Barat Kabupaten Parigi Moutong', 'terbaru', '2025-07-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Senin (07/07/25) pukul 15.20 WITA telah terjadi banjir akibat intensitas curah hujan yang deras. Terdampak akibat kejadian ini diantaranya 19 KK/77 jiwa, 1 bayi, 5 balita, 4 lansia dan 1 unit mushollah. Kebutuhan mendesak yaitu normalisasi Sungai dan logistic PB situasi akhir air berangsur surut.</p>', '1755509608251-WhatsApp Image 2025-07-07 at 21.20.01.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755509608251-WhatsApp Image 2025-07-07 at 21.20.01.jpeg', '2025-08-18 09:33:28', '2025-08-18 09:33:28'),
(217, 'Banjir Desa Solonsa Kecamatan Witaponda Kabupaten Morowali ', 'terbaru', '2025-07-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Senin (07/07/25) pukul 13.30 WITA. Hujan berintensitas sedang hingga lebat menyebabkan air dan lumpur yang berasar dari Lokasi peertambangan PT. Alaska melewati galian parit meluap sampai ke Jalan Trans Sulawesi dan rumah warga. Terdampak akibat kejadian ini sebanyak 116 KK. Kebutuhan mendesak berupa pelebaran saluran air. Situasi akhir air sudah surut.</p>', '1755509784307-WhatsApp Image 2025-07-07 at 21.32.39.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755509784307-WhatsApp Image 2025-07-07 at 21.32.39.jpeg', '2025-08-18 09:36:24', '2025-08-18 09:36:24'),
(218, 'Kejadian Angin Puting Beliung Desa Ginunggung dan Desa Bajugan Kecamatan Galang Kabupaten Toli-Toli', 'terbaru', '2025-07-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Angin puting beliung terjadi pada Senin (07/07/25) pukul 14.00 WITA. Cuaca buruk sekitar pukul 14.00 WITA menyebabkan terjadinya hujan disertai angin. Terdapat 6 rumah terdampak di Desa Gununggung diantaranya 3 rusak berat dan 2 rusak ringan. Desa Bajugan terdapat 6 rumah terdampak. Terdapat 2 korban luka ringan akibat kejadian tersebut. </p>', '1755654491646-glg.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755654491646-glg.jpeg', '2025-08-20 01:48:11', '2025-08-20 01:48:11'),
(219, 'Banjir terjang 2 Kecamatan di Kabupaten Donggala', 'terbaru', '2025-07-07', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi di Kecamatan Banawa Tengah dan Banawa Selatan pada Senin (07/07/25) pukul 14.30 WITA. 5 Desa di Kecamatan Banawa Selatan diantaranya Desa Tosale, Lumbumamara, Salungkaenu, Bambarimi dan Lumbutarombo. Selain itu di Kecamatan Banawa Tengah yaitu Desa Towale, Mekar Baru, Limboro, Kola-Kola, Lumbudolo dan Powelua. Hujan deras sejak pukul 14.00-18.00 WITA mengakibatkan banjir. </p><p class=\"ql-align-justify\">	Terdampak di Kecamatan Banawa Selatan sebanyak 90 unit rumah, SD, Tsanawiyah dan 1 unit jembatan putus di Desa Tosale, 192 unit runah di Desa Lumbu Mamara, 17 rumah di Desa Lumbu Tarombo. Sementara itu di Kecamatan Banawa Tengah sekitar 125 rumah terdampak di Desa Towale, 90 rumah dan 1 SMA di Desa Mekar Baru, 104 rumah dan sebuah masjid di Desa Limboro, 147 rumah, kantor desa, kantor BPD, Mushollah, posyandu dan puskesmas terdampak di Desa Kola-Kola, 1 unit jembatan di Desa Lumbudolo serta jalan penghubung dusun 1 ke dusun 2 Desa Powelua terputus.</p><p class=\"ql-align-justify\">	Kejadian ini juga menyebabkan seorang warga dusun 1 Desa Lumbu Mamara hilang di duga hanyut terbawa banjir atas nama Taharudin (L/60). Kebutuhan mendesak berupa air bersih dan logistic PB. Situasi akhir air berangsur surut, warga terdampak melakukan pembersihan di rumah masing-masing. Setelah dilakukan pencarian korban hilang berhasil ditemukan dalam kondisi meninggal dunia (MD).</p><p class=\"ql-align-justify\"><br></p>', '1755654543980-dgl.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755654543980-dgl.jpeg', '2025-08-20 01:49:03', '2025-08-20 01:49:03'),
(220, 'Tanah Longsor Desa Mohoni Kecamatan Petasia Timur Kabupaten Morowali Utara', 'terbaru', '2025-07-12', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Tanah Longsor terjadi pada Sabtu (12/07/25) pukul 04.00 WITA. Hujan yang terjadi sejak 00.00 WITA mengakibatkan terjadinya longsor di Jalan Trans Penghubung Antara Desa Bimor Jaya dan Desa Mohoni. Terdampak akibat kejadian ini yang terputusnya jalan trans. Situasi akhir material longsor masih menutupu badan jalan.</p>', '1755654590673-mhn.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755654590673-mhn.jpeg', '2025-08-20 01:49:50', '2025-08-20 01:49:50'),
(221, 'Banjir Rendam 4 Kecamatan di Kota Palu', 'terbaru', '2025-07-12', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Sabtu (12/07/25) pukul 17.53 WITA. Banjir merendam beberapa wilayah diantaranya Kelurahan Baru, Ujuna, Kamonji, Lere dan Nunu yang tersebar pada Kecamatan Palu Barat, Kelurahan Besusu Barat, Lolu Utara dan Lolu Selatan yang tersebar di Kecamatan Palu Timur, Kelurahan Birobuli Selatan di Palu Selatan dan Kelurahan Tanamodindi Kecamatan Mantikulore. hujan deras mulai mengguyur wilayah Kota Palu sejak pukul 17.35 WITA. Hujan berlangsung cukup lama dan menyebabkan debit air meningkat di sejumlah wilayah Kota Palu. Memasuki pukul 17.53 WITA, banjir terjadi di beberapa wilayah, yaitu Kelurahan Baru, Kelurahan Ujuna, dan Kelurahan Besusu Barat, Kelurahan Lolu Utara, Kelurahan Kamonji, Kelurahan Nunu, Kelurahan Birobuli Selatan, Kelurahan Tanamodindi, Kelurahan Lolu Selatan, Kelurahan Besusu Barat, Kelurahan Lere, Kelurahan Ujuna. Banjir tersebut disebabkan oleh derasnya hujan serta kondisi drainase yang menyebabkan saluran air meluap dan genangan terjadi di permukiman warga, dengan ketinggian air mencapai lutut orang dewasa. Air mulai surut pada pukul 23.43 WITA di hari yang sama.</p><p class=\"ql-align-justify\">	Terdampak akibat kejadian ini yaitu 128 jiwa dan 26 rumah di Kelurahan Baru, 125 jiwa di Kelurahan Ujuna, 50 jiwa dan 11 rumah di Kelurahan Kamonji dan 78 jiwa 19 rumah. Sedangkan di Kecamatan Palu Timur Kelurahan Besusu Barat 16 Jiwa 4 rumah, Kelurahan Lolu Utara sebanyak 9 jiwa dan 1 rumah. Kecamatan Palu Selatan tepatnya di Kelurahan Birobuli Selatan sebanyak 160 jiwa dan 50 rumah.</p><p class=\"ql-align-justify\"><br></p>', '1755654629036-ujn.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755654629036-ujn.jpeg', '2025-08-20 01:50:29', '2025-08-20 01:50:29'),
(222, 'Banjir Merendam Desa Tuva Kecamatan Gumbasa Kabupaten Sigi', 'terbaru', '2025-07-14', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Senin (14/07/25) pukul 20.00 WITA. Hujan deras yang mengguyur wilayah Gumbasa mengakibatkan meningkatnya volume air Sungai Mafane hingga menyebabkan jebolnya tanggul yang menggenangi rumah penduduk dengan ketinggian sekitar 30-50cm. Kejadian ini mengakibatkan 7 rumah terdampak. Situasi akhir air telah surut.</p>', '1755654679044-ujn.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755654679044-ujn.jpeg', '2025-08-20 01:51:19', '2025-08-20 01:51:19'),
(223, 'Gempa Bumi Mengguncang Desa TIndoli Kecamatan Pamona Tenggara Kabupaten Poso ', 'terbaru', '2025-07-14', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Gempa bumi terjadi pada Senin (14/07/25) pukul 19.52 WITA. Hari Senin 14 Juli 2025 pukul 19.52.18 WIB wilayah Pamona Tenggara, Poso, Sulawesi Tengah diguncang gempa tektonik. Hasil analisis BMKG menunjukkan gempabumi ini memiliki parameter update dengan magnitudo M5,0. Episenter gempabumi terletak pada koordinat 2,01° LS ; 120,68° BT, atau tepatnya berlokasi di darat wilayah Pamona Tenggara, Poso, Sulawesi Tengah pada kedalaman 14 km.</p><p class=\"ql-align-justify\">	Kejadian ini mengakibatkan 38 unit rumah rusak ringan, pengungsi sebanyak 20 KK. Kebutuhan mendesak berupa logistic PB, tenda pengungsi dan obat-obatan. Situasi akhir kondisi dilapangan telah kondusif, namun Masyarakat masih waspada terhadap potensi gempabumi susulan. Lokasi pengungsian tersebar di rumah kerabat dan halaman rumah warga.</p><p class=\"ql-align-justify\"><br></p>', '1755654720435-tndl.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755654720435-tndl.jpeg', '2025-08-20 01:52:00', '2025-08-20 01:52:00'),
(224, 'Gempa Bumi Mengguncang 2 Kecamatan di Kabupaten Poso', '', '2025-07-24', 'admin pusdalops', '', '<p class=\"ql-align-justify\">Gempa Bumi terjadi di Kecamatan Pamona Tenggara dan Kecamatan Pamona Selatan pada Kamis (24/07/25) pukul 21.06 WITA. Pada hari Kamis 24 Juli 2025 pukul 20.06.59 WIB wilayah Poso, Sulawesi Tengah diguncang gempa tektonik. Hasil analisis BMKG menunjukkan gempabumi ini memiliki parameter update dengan magnitudo M5,7. Episenter gempabumi terletak pada koordinat 2,01° LS ; 120,78° BT, atau tepatnya berlokasi di darat wilayah Poso, Sulawesi Tengah pada kedalaman 10 km.</p><p class=\"ql-align-justify\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Kejadian ini mengakibatkan&nbsp;184 KK terdampak, 4 Unit rumah Rusak berat dan 21 unit rumah rusak ringan di Desa Tokilo, 70 unit rumah tusak ringan, 10 unit rumah rusak berat, 1 unit gereja dan 1 unit sekolah TK terdampak di Desa Tindoli, 1 unit rumah rusak ringan di Desa Pendolo. Jumlah gempa bumi susulan yang tercatat sebanyak 96 kali. Jumlah pengungsi di Desa Tokilo 596 jiwa/184 KK, 22 Balita, 7 Bayi, 85 Lansia, 3 ibu hamil dan 4 disabilitas. Desa Tindoli sebanyak 887 jiwa/266KK. Desa Tolambo sebanyak 528 jiwa / 159 KK, 33 balita, 82 lansia, 5 disabilitas dan 4 ibu hamil. 2 orang korban luka ringan di Desa Tindoli dan Desa Tolambo. Kebutuhan mendesak berupa tenda, light tower, genset, alas tidur selimut, terpal, makanan siap saji, perlengkapan bayi dan obat-obatan. Situasi akhir gempa susulan masih terjadi dan warga masih waspada.</p>', '1755654895941-WhatsApp Image 2025-07-24 at 22.22.23.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755654895941-WhatsApp Image 2025-07-24 at 22.22.23.jpeg', '2025-08-20 01:53:07', '2025-08-20 01:54:55'),
(225, 'Angin puting beliung terjadi di 3 Kecamatan Kabupaten Sigi', 'terbaru', '2025-07-26', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">Angin kencang terjadi di Kecamatan Sigi Biromaru, Dolo dan Palolo Kabupaten Sigi. Hujan lebat, angin kencang disertai petir yang melanda Kab. sigi dan Sekitarnya hingga malam ini telah mengakibatkan sejumlah pohon tumbang sepanjang jalan poros Palu - Palolo. Selain itu hujan juga mengakibatkan padamnya listrik pada beberapa wilayah Kota Palu dan sekitarnya. Peristiwa ini terjadi pada Sabtu (26/07/25) pukul 20.10 WITA. Kejadian ini berdampak pada 78 KK/245 jiwa dan 62 unit rumah di Desa Sidera, 22 KK/85 jiwa, 22 unit rumah dan 1 kantor desa di Soulowe, 4 KK/14 jiwa dan 4 unit rumah di Desa Oloboju. Selain itu, 2 KK/ 9 jiwa serta 2 unit rumah terdampak di Desa Bunga. Kebutuhan mendesak berupa perbaikan rumah, terpal, matras dan bahan bangunan. Situasi akhir masyarakat terdampak berupaya melakukan perbaikan rumah secara mandiri seadanya, namun masih sangat membutuhkan dukungan dan bantuan dari pemerintah. Kondisi lampu saat ini sudah menyala dan dilakukan perbaikan serta penebangan pohon yang mengancam jalur listrik oleh PLN Kota Palu. Masyarakat setempat tidak ada yang mengungsi karena menjaga keamanan barang dan perabot rumah serta ternak.</p>', '1755654846092-WhatsApp Image 2025-07-27 at 01.59.17.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755654846092-WhatsApp Image 2025-07-27 at 01.59.17.jpeg', '2025-08-20 01:54:06', '2025-08-20 01:54:06'),
(226, 'Banjir terjadi di Desa Kami Wangi Kecamatan Toili Barat Kabupaten Banggai', 'terbaru', '2025-08-03', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Hujan deras yang terjadi sejak tanggal 1 hingga 3 Agustus 2025 menyebabkan terjadinya banjir akibat dari meluapnya sungai sehingga merendam pemukiman dan persawahan warga di Desa Kami Wangi. Terdampak sebanyak 32 KK, kebutuhan mendesak logsitik PB dan air bersih. Situasi akhir air mulai surut dan hujan telah reda.</p>', '1755659862666-kmwg.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755659862666-kmwg.jpeg', '2025-08-20 03:17:42', '2025-08-20 03:17:42'),
(227, 'Banjir terjadi di Desa Korolama Kecamatan Petasia Kabupaten Morowali Utara', 'terbaru', '2025-08-09', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Sabtu (09/08/25) pukul 01.00 WITA. Akibat curah hujan yang cukup deras terjadi sejak Pukul 21:00 Wita s/d Pukul 02:00 Wita. Mengakibatkan debit air yang turun ke pemukiman warga sangat tinggi hingga menyebabkan terjadinya banjir dengan ketinggian 30-50 cm. kebutuhan mendesak berupa normalisasi Sungai dan Pembangunan tanggul. Situasi akhir hujan masih berlangsung dan ari masih menggenang.</p>', '1755659913873-krlm.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755659913873-krlm.jpeg', '2025-08-20 03:18:33', '2025-08-20 03:18:33'),
(228, 'Banjir Bandang Menerjang Desa Namo Kecamatan Kulawi Kabupaten Sigi', 'terbaru', '2025-08-14', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir Bandang menerjang sekitar pukul 18.59 WITA hari Kamis (14/08/25). Akibat curah hujan yang cukup deras sehingga mengakibatkan terjadinya banjir bandang hingga meluap ke pemukiman warga dan jalan trans Palu-Kulawi. Terdampak akibat kejadian ini diantaranya 37 KK/126 Jiwa terdampak, bayi 1 jiwa, Balita 9 Jiwa, anak (5-17<sup>th</sup>) 29 jiwa, Lansia 12 jiwa, ibu hamil 1 jiwa, 3 unit rumah rusak ringan, 3 unit rumah rusak berat, 2 unit rumah hilang, 2 jembatan rusak, rusaknya jaringan pipa air bersih serta jalan poros Palu- Kulawi. Pengungsi sebanyak 3 KK 14 jiwa. Kebutuhan mendesak berupa air bersih, logistic pb, obat-obatan, kidsware dan ibu hamil. Situasi akhir jalan sudah bisa dilalui kendaraan, Masyarakat melakukan gotong royong membersihkan rumah masing-masing. 2 unit alat berat PU Sigi dan BWS Sulawesi III sedang melakukan pembersihan material.</p>', '1755659973933-namo.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755659973933-namo.jpeg', '2025-08-20 03:19:33', '2025-08-20 03:19:33'),
(229, 'Gempa Bumi Mengguncang 3 Kecamatan Di Kabupaten Poso ', 'terbaru', '2025-08-17', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Gempa Bumi terjadi di Kecamatan Poso Pesisir, Poso Pesisir Selatan dan Poso Pesisir Utara pada Minggu (17/08/25) pukul 06.38 WITA. Pada hari Minggu 17 Agustus 2025 pukul 06.38. WITA wilayah Poso, Sulawesi Tengah diguncang gempa tektonik. Hasil analisis BMKG menunjukkan gempa bumi ini memiliki parameter update dengan magnitudo M6,0. Episenter gempa bumi terletak pada koordinat 1,30° LS ; 120,62° BT, atau tepatnya berlokasi di darat wilayah Poso, Sulawesi Tengah pada kedalaman 10 Km.</p><p class=\"ql-align-justify\">	Terdampak di Kecamatan Poso Pesisir diantaranya Desa Masani 1 unit Gereja rusak berat, Desa Bega 3 unit rumah rusak ringan, Desa Masamba 9 unit rumah rusak ringan, Desa Tokorondo 1 unit rumah rusak bera dan 9 unit rumah rusak ringan. Desa Towu 31 unit rumah rusak ringan, 4 unit rumah rusak berat, 1 unit kantor Desa, 1 unit Polides, 1 unit Gedung Sekolah Dasar dan 2 unit rumah ibadah rusak ringan. Desa Lape 8 unit rumah rusak ringan. Desa TAngkura 58 unit rumah rusak berat, 35 unit rumah rusak ringan, 2 unit gereja rusak berat, 1 unit gereja rusak ringan dan 2 unit Gedung sekolah dasar rusak berat. Desa Patiwunga 2 unit rumah rusak berat. Desa Ueralulu 1 unit sekolah rusak, Desa Tiwaa 4 unit rumah rusak berat dan&nbsp;unit rumah rusak ringan. Kecamatan Poso Pesisir Utara Desa Kilo 1 unit rumah rusak berat, 5 unit rumah rusak ringan. Kecamatan Poso Pesisir Selatan Desa Padalembara 3 unit rumah risak ringan, 21 rumah ibadah pura keluarga rusak ringan. Desa Tabalu 6 unit rumah rusak ringan 3 unit rumah rusak sedang. Jumlah gempa susulan sebanyak 65 Kali. Pengungsi sebanyak 89 pasien di RSUD Poso diungsikan ke tenda BPBD di halaman RSUD. 9 korban luka berat telah menjalani operasi 2 korban Meninggal Dunia, 7 korban luka ringan dalam perawatan RSUD Poso, 10 Korban luka ringan telah ditangani di Lokasi oleh Dinkes Poso dan 8 korban luka ringan telah di tangani puskesmas tangkura. Kebutuhan mendesak berupa terpal, tenda, lampu taktikal, selimut, alas tidur, makanan siap saji, perlengkapan bayi, obat-obatan dan kendaraan operasional pendukung. Situasi akhir gempa susulan masih terjadi dan warga masih waspada.</p>', '1755660016543-gmpa.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755660016543-gmpa.jpeg', '2025-08-20 03:20:16', '2025-08-20 03:20:16'),
(230, 'Banjir terjang Desa Maranda Kecamatan Poso Pesisir Utara', 'terbaru', '2025-08-19', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Selasa (19/08/25) pukul 19.30 WITA. Curah hujan yang cukup deras sejak pukul 19.00 WITA dan kondisi gorong-gorong yang kecil menyebabkan saluran air meluap dan menggenangi pemukiman warga. Terdampak akibat kejadian ini sekitar 46 KK dan 46 unit rumah terdampak. Dibutuhkan segera perluasan gorong-gorong. Situasi akhir hujan masih berlangsung dan air masih mengggenang.</p>', '1755743190214-mrnd.jpg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755743190214-mrnd.jpg', '2025-08-21 02:26:30', '2025-08-21 02:26:30'),
(231, 'Banjir menerjang Desa Balinggi Jati Kecamatan Balinggi Kabupaten Parigi Moutong', '', '2025-08-19', 'admin pusdalops', '', '<p>Palu - Selasa (19/08/25) pukul 20.15 WITA curah hujan deras mengakibatkan jebolnya tanggul sungai hingga menyebabkan banjir. terdampak di Dusun I sebanyak 20 KK / 121 jiwa, 2 bayi, 23 balita, 65 lansia. Dusun II 115 KK /369 jiwa, 2 ibu hamil, 24 bayi, 24 balita dan 51 lansia. Dusun III 230 KK / 456 jiwa, 7 ibu hamil, 14 bayi, 4 balita, 23 lansia. Dusun V 99 KK / 188 jiwa, 6 bayi, 2 balita, 26 lansia. Dusun VI 200 KK, 700 jiwa, 6 ibu hamil, 8 bayi, 36 balita dan 117 lansia. total jumlah terdampak sebanyak 664 KK, 1834 jiwa, 15 ibu hamil, 55 bayi, 89 lansia dan 282 lansian. selain itu jembatan penghubung utama dusun juga terdampak, SD Inpres 4 Balinggi, TK Negeri 2 Balinggi dan 4 Ha persawahan turut terdampak. 91 KK pengungsi telah kembali ke rumah masing-masing. kebutuhan mnedesak berupa makanan siap saji, Logistik PB, Selimut, Matras, Alat berat. situasi akhir air telah surut dan warga mulai melakukan pembersihan.</p>', '1755743229849-blngg.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755743229849-blngg.jpeg', '2025-08-21 02:27:09', '2025-08-28 03:04:23'),
(232, 'Banjir menggenangi Desa Sidera Kecamatan Sigi Biromaru Kabupaten Sigi', 'terbaru', '2025-08-19', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Selasa (19/08/25) pukul 17.00 WITA. Hujan deras mengguyur sejak pukul 15.00 hingga 17.00 mwnyebabkan debit air meningkat sehingga drainase tidak mampu menampung dan mengakibatkan air meluap menggenangi pemukiman warga. Terdampak akibat kejadian ini sejumlah 4 unit rumah warga dan 1 KK pengungsi. Kebutuhan mendesak masih dalam pendataan. Situasi akhir hujan mulai reda dan air masih menggenang</p>', '1755743324794-sdr.jpg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755743324794-sdr.jpg', '2025-08-21 02:28:44', '2025-08-21 02:28:44'),
(233, 'Banjir menerjang Desa Sidoan Selatan Kecamatan Tinombo Kabupaten Parigi Moutong', 'terbaru', '2025-08-20', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir merendam Desa Sidoan Selatan Kecamatan Tinombo pada Rabu (20/08/25) pukul 00.10 WITA. Hujan deras mengakibatkan air meluap ke pemukiman warga. Terdampak akibat kejadian ini sebanyak 60 KK. Beruntungnya tidak ada korban jiwa dan pengungsi akibat kejadian ini. Kebutuhan mendesak masih dalam pendataan. Situasi akhir air telah surut, aktivitas warga Kembali normal.</p>', '1755743402619-sdnsltn.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755743402619-sdnsltn.jpeg', '2025-08-21 02:30:02', '2025-08-21 02:30:02'),
(234, 'Banjir Bandang menerjang pemukiman warga di Desa Malino Kecamatan Petasia Timur Kabupaten Morowali Utara', 'terbaru', '2025-08-20', 'admin pusdalops', 'Ya', '<p class=\"ql-align-justify\">	Banjir terjadi pada Selasa (20/08/25) pukul 01.00 WITA. Akibat hujan deras yang mengguyut Desa Malino mengakibatkan debit air meningkat dan mengakibatkan banjir bandang. Kejadian ini berdampak pada 12 KK / 48 jiwa, 3 jiwa (bayi), 3 jiwa (lansia), dan 2 unit rumah rusak berat. Pengungsi akbiat kejadian ini sebanyak 16 KK yang terdiri dari 64 jiwa. Kebutuhan mendesak berupa sembako, perlengkapan bayi, air bersih, terpal, tenda dan toilet portable. Situasi akhir di tempat kejadian yaitu sedang berlangsung proses pembersihan sisa-sisa banjir dan air telah surut.</p>', '1755743457245-mln.jpeg', 'https://backendreboon.api.pusdalops-bpbdsulteng.com/images/1755743457245-mln.jpeg', '2025-08-21 02:30:57', '2025-08-21 02:30:57'),
(235, 'eeeeee', 'terbaru', '2026-02-24', 'arqrrarrrr', 'Ya', '<p>qwertghjkjhgfdsxdcvbnmkuytresxcvb</p>', '1771918789195-eeee.png', 'http://localhost:5001/public/images/1771918789195-eeee.png', '2026-02-24 07:37:06', '2026-02-24 07:39:49'),
