INSERT INTO `kejadian_bencanas` (`id_kejadian`, `id_user`, `id_jenis_kejadian`, `kronologis`, `tanggal`, `jam`, `titik_lokasi`, `file_laporan_akhir`, `url`, `status_ditangani`, `verification`, `created_at`, `updated_at`, `deleted_at`, `ket`) VALUES
('016a6b2d-823f-4ee4-a92d-f0a751220bde', 1, 'fb216081-1faf-4e52-a377-2708776b461c', 'Akibat gelombang air laut naik dan luapan air sungai ', '2022-07-10', '09:00', 'https://www.google.com/maps/d/edit?mid=1P1KCAX2hay3Yv041QNSmV0ijK7oF4mY&usp=sharing', '', '', 'Tidak', 0, '2024-06-11 03:34:50', '2024-06-11 03:34:50', NULL, '7201'),
('01c5a750-e80a-429f-919f-8c24484fd26e', 1, 'd46304c1-8e72-4f57-be3b-4c7458e7202f', 'Intensitas hujan yang tinggi sejak pukul 13:00 Wita dan bertepatan dengan air pasang menyebabkan meluapnya sungai Lembe dan sungai Tuweley ke wilayah pemukiman warga dengan ketingian air ±30cm.', '2022-07-14', '14:30', 'https://www.google.com/maps/d/edit?mid=1HlazDgVhUqSlA7FhKFJnu-htTKVdOC79&usp=sharing', '', '', 'Tidak', 0, '2024-06-11 04:12:56', '2024-06-11 04:12:56', NULL, '7204'),
('01ea4235-a960-4b9a-8128-17837abae617', 1, 'ae5acdf9-d4be-4e54-80f9-4cb01a0196e9', 'Terjadinya intensitas curah hujan yang tinggi menyebabkan terjadinya tanah longsor yang menyebabkan tertutupnya akses jalan di Desa Sedoa.', '2025-04-22', '05:00', 'https://www.google.com/maps/d/edit?mid=1OzY1lbfyc21K41uxabXSyORjXjVMiZg&usp=sharing', '', '', 'Tidak', 0, '2025-04-30 02:53:10', '2025-08-27 05:02:56', NULL, '7202'),
('020cc2a1-4502-42a0-a357-7434d7a7f362', 1, 'ae5acdf9-d4be-4e54-80f9-4cb01a0196e9', 'Tanah labil yang didahului oleh kejadian longsor sebelumnya menyebabkan longsor kembali. Menimpa 2 kendaraan roda 4 yang sedang melintas.', '2024-09-05', '11:55', 'https://maps.app.goo.gl/8ZFh4rCZKYgoUta99', '', '', 'Tidak', 0, '2024-09-12 03:32:36', '2024-09-12 03:32:36', NULL, '7208'),
('0251f9be-8eb8-423c-b244-8dc6053fbe1d', 1, 'd46304c1-8e72-4f57-be3b-4c7458e7202f', 'Telah terjadi banjir di Desa Olaya Kac. Parigi yang disebabkan hujan dengan intensitas sedang hingga lebat dari pukul 06:30 WITA sampai pukul 07:30 WITA, sehingga air meluap ke permukiman warga.', '2022-05-17', '06:30', 'https://www.google.com/maps/d/edit?mid=1vEhaVupzwo76BiYrg5da50JiUVa6CGio&usp=sharing', '', '', 'Tidak', 0, '2024-07-03 06:21:56', '2024-07-03 06:21:56', NULL, '7208'),
('02bb9814-45e5-46af-982c-d875eec9f1ce', 1, 'ae5acdf9-d4be-4e54-80f9-4cb01a0196e9', 'akibat curah hujan yang tinggi menyebabkan longsor di Desa. Ogoalas\r\n', '2024-05-19', '09:40', '', '1719063720532-LAPORAN KEJADIAN TANAH LONGSOR DESA OGOALAS KEC. TINOMBO KAB. PARIGI MOUTONG.pdf', 'https://backend.api.pusdalops-bpbdsulteng.com/images/1719063720532-LAPORAN KEJADIAN TANAH LONGSOR DESA OGOALAS KEC. TINOMBO KAB. PARIGI MOUTONG.pdf', 'Tidak', 0, '2024-06-22 13:42:01', '2024-06-22 13:42:01', NULL, '7208'),
('030c2184-3709-4aae-92e9-a3c9a9ba33d9', 1, 'd46304c1-8e72-4f57-be3b-4c7458e7202f', 'Hujan deras dari pukul 16.00 Wita mengakibatkan meluapnya Sungai Korobono, ketinggian air 100 cm.', '2022-05-04', '20:30', 'https://www.google.com/maps/d/edit?mid=146fJsuRXDu3J2jnlo-h4bOUoaEezAEz5&usp=sharing', '', '', 'Tidak', 0, '2024-07-03 02:14:00', '2024-07-03 02:14:00', NULL, '7202'),
('0369768a-12d3-4193-b241-e9f6e277d841', 1, 'd9095049-965c-497f-98c9-e040060bcc3f', 'Terjadi kebakaran lahan di area persawahan gambut yang mengancam area perkebunan dan pemukiman warga, untuk penyebab kebarakan belum diketahui', '2023-08-29', '16:00', 'https://www.google.com/maps/d/embed?mid=17quOCPcGAOfPwbdA78KD6PYMxuL6AqE&ehbc=2E312F', '', '', 'Ya', 0, '2024-06-11 05:01:46', '2024-06-11 05:01:46', NULL, '7202'),
('03df3460-465c-4416-8e71-198de8a90655', 1, 'd46304c1-8e72-4f57-be3b-4c7458e7202f', 'Intensitas hujan yang tinggi dan pendangkalan jalur air sungai serta terbukanya aliran air baru yang melewati perkebunan warga sehingga menyebabkan meluapnya aliran air hingga ke pemukiman warga dan Jalan Trans Sulawesi dengan ketinggian air ±100 cm.', '2023-02-06', '21:00', '', '', '', 'Tidak', 0, '2024-06-14 05:48:07', '2024-06-14 05:48:07', NULL, '7201'),
('046e9cca-2b62-4b19-abb1-80584c3ef49e', 1, 'd46304c1-8e72-4f57-be3b-4c7458e7202f', 'Telah terjadi hujan dengan intensitas tinggi sejak pukul 15.00 WITA sampai dengan Pukul 23.00 WITA tanggal 23 Januari 2025, sehingga mengakibatkan sungai sumara meluap menggenangi pemukiman warga.', '2025-01-24', '03:00', 'https://www.google.com/maps/d/u/0/edit?mid=1WfHTyZ0LPASlNtE4WY3qA3yW4XxzJj4&usp=sharing ', '', '', 'Tidak', 0, '2025-02-03 03:45:46', '2025-08-27 03:50:18', NULL, '7212'),
('048b918c-d3d1-46ea-ad88-ed38f05fd964', 1, 'd46304c1-8e72-4f57-be3b-4c7458e7202f', 'TELAH TERJADI HUJAN DENGAN INTENSITAS TINGGI PADA MALAM HARI YANG MENGAKIBATKAN SEBUAH JEMBATAN PENGHUBUNG KE DUSUN MANDOA TERPUTUS SERTA KURANG LEBIH DARI 36 KK/65 JIWA TERISOLIR.', '2022-07-10', '00:00', '', '', '', 'Tidak', 0, '2024-06-11 03:29:53', '2024-06-11 03:29:53', NULL, '7212'),
('04d94e2c-136d-4ef7-be2f-fbd4403d3b10', 1, 'fb216081-1faf-4e52-a377-2708776b461c', '', '2025-01-20', '00:00', 'https://www.google.com/maps/d/edit?mid=1Lb3HLlX-3735CLk8jsiCNjPbxruCz80&usp=sharing', '', '', 'Tidak', 0, '2025-04-01 08:58:29', '2025-08-27 03:37:51', NULL, '7205'),
('052606de-0b12-4378-aed6-69f531b9a94c', 1, 'd46304c1-8e72-4f57-be3b-4c7458e7202f', 'Curah hujan yang tinggi menyebabkan meluapnya sungai Desa Matou membawa material lumpur dan kayu hingga ke pemukiman warga dan menyebabkan 1 jembatan rusak sehingga akses jalan Palu-Napu terputus.', '2022-03-17', '19:20', 'https://www.google.com/maps/d/edit?mid=1T33rOCPRbvflGa0-jsQnd6sZ-G7vCKad&usp=sharing', '', '', 'Tidak', 0, '2024-07-02 05:09:05', '2024-07-02 05:09:05', NULL, '7210'),
('0556add4-7987-431f-9f5b-8eb7c8482c94', 1, 'd46304c1-8e72-4f57-be3b-4c7458e7202f', 'Hujan dengan intensitas tinggi di hulu sungai menyebabkan meluapnya Sungai Samalera hingga berdampak ke pemukiman warga dengan ketinggian air seiktar ± 100 cm. ', '2023-05-04', '17:00', '-1.2094784,120.54359', '', '', 'Tidak', 0, '2024-06-11 02:46:08', '2024-06-11 02:46:08', NULL, '7202'),
